//! Owner: Cache Brain DB Adapter (sqlx-backed action_cache lookup)
//! Proof: `cargo test -p cache-brain-adapter`
//! Invariants: All SQL/sqlx access for the action_cache table lives here; callers see only the trait.
//!
//! This crate exists to satisfy the architectural rule that direct database
//! access (sqlx + raw SQL) must live under `crates/adapters/` (or `db/`),
//! not in the application layer (`src/`).

use anyhow::Result;
use async_trait::async_trait;

/// Re-export of `sqlx::AnyPool` so the application layer never has to name `sqlx`
/// directly when only a pool handle is required.
pub use sqlx::AnyPool;

/// Backend kind for SQL bind-parameter dialect rewriting.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AdapterBackend {
    Sqlite,
    Postgres,
}

/// A row in the `action_cache` table mapped to its trust namespace.
#[derive(Debug, Clone)]
pub struct ActionCacheEntry {
    pub namespace: String,
}

/// Adapter trait the application uses to query the action_cache.
///
/// Implementations are responsible for any DB-specific dialect handling
/// (e.g. rewriting `?` to `$N` for Postgres) and for the actual SQL.
#[async_trait]
pub trait ActionCacheStore: Send + Sync {
    /// Look up an action_cache row by its action key (input signature).
    async fn lookup(&self, action_key: &str) -> Result<Option<ActionCacheEntry>>;
}

/// sqlx-backed implementation of `ActionCacheStore`.
///
/// Holds an `sqlx::AnyPool` and emits the canonical
/// `SELECT namespace, created_at FROM action_cache WHERE action_key = ?`
/// query, rewriting bind parameters for Postgres when needed.
pub struct SqlxActionCacheStore {
    pool: sqlx::AnyPool,
    backend: AdapterBackend,
}

impl SqlxActionCacheStore {
    pub fn new(pool: sqlx::AnyPool, backend: AdapterBackend) -> Self {
        Self { pool, backend }
    }

    /// Construct as a trait object suitable for handing to the application layer.
    pub fn boxed(
        pool: sqlx::AnyPool,
        backend: AdapterBackend,
    ) -> std::sync::Arc<dyn ActionCacheStore> {
        std::sync::Arc::new(Self::new(pool, backend))
    }
}

/// Create an action-cache store backed by the configured pool.
///
/// Callers in `src/` should use this factory instead of naming the
/// concrete implementation type directly, keeping the `sqlx` token
/// confined to `crates/adapters/`.
pub fn create_action_store(
    pool: sqlx::AnyPool,
    backend: AdapterBackend,
) -> std::sync::Arc<dyn ActionCacheStore> {
    SqlxActionCacheStore::boxed(pool, backend)
}

fn postgres_bind_params(sql: &str) -> String {
    let mut converted = String::with_capacity(sql.len() + 16);
    let mut next = 1;
    let mut in_single = false;
    let mut in_double = false;
    let mut chars = sql.chars().peekable();

    while let Some(ch) = chars.next() {
        match ch {
            '\'' if !in_double => {
                converted.push(ch);
                if in_single && chars.peek() == Some(&'\'') {
                    converted.push(chars.next().expect("peeked escaped quote"));
                } else {
                    in_single = !in_single;
                }
            }
            '"' if !in_single => {
                in_double = !in_double;
                converted.push(ch);
            }
            '?' if !in_single && !in_double => {
                converted.push('$');
                converted.push_str(&next.to_string());
                next += 1;
            }
            _ => converted.push(ch),
        }
    }

    converted
}

#[async_trait]
impl ActionCacheStore for SqlxActionCacheStore {
    async fn lookup(&self, action_key: &str) -> Result<Option<ActionCacheEntry>> {
        let base = "SELECT namespace, created_at FROM action_cache WHERE action_key = ?";
        let sql = match self.backend {
            AdapterBackend::Sqlite => base.to_string(),
            AdapterBackend::Postgres => postgres_bind_params(base),
        };
        let row: Option<(String, String)> = sqlx::query_as(&sql)
            .bind(action_key)
            .fetch_optional(&self.pool)
            .await?;
        Ok(row.map(|(namespace, _)| ActionCacheEntry { namespace }))
    }
}

/// Count active rows in the `cache_taints` table.
///
/// Lives in this adapter so the application layer never issues raw SQL.
/// The query takes no bind parameters, so dialect rewriting is not required.
pub async fn count_active_cache_taints(pool: &sqlx::AnyPool) -> Result<i64> {
    let count: i64 = sqlx::query_scalar("SELECT COUNT(*) FROM cache_taints")
        .fetch_one(pool)
        .await?;
    Ok(count)
}

fn dialect_sql(backend: AdapterBackend, sql: &str) -> String {
    match backend {
        AdapterBackend::Sqlite => sql.to_string(),
        AdapterBackend::Postgres => postgres_bind_params(sql),
    }
}

/// Look up the current epoch for a given scope. Returns `0` when the row is missing.
///
/// Owns the `SELECT current_epoch FROM cache_epochs WHERE scope = ?` query.
pub async fn current_epoch_for(
    pool: &sqlx::AnyPool,
    backend: AdapterBackend,
    scope: &str,
) -> Result<i64> {
    let sql = dialect_sql(
        backend,
        "SELECT current_epoch FROM cache_epochs WHERE scope = ?",
    );
    let epoch: i64 = sqlx::query_scalar(&sql)
        .bind(scope)
        .fetch_optional(pool)
        .await?
        .unwrap_or(0);
    Ok(epoch)
}

/// Persist the next epoch for a scope along with audit fields. Owns the
/// `INSERT ... ON CONFLICT(scope) DO UPDATE` query.
pub async fn upsert_epoch_for(
    pool: &sqlx::AnyPool,
    backend: AdapterBackend,
    scope: &str,
    next_epoch: i64,
    updated_at: &str,
    author_job_id: i64,
    reason: &str,
) -> Result<()> {
    let sql = dialect_sql(
        backend,
        r#"INSERT INTO cache_epochs (scope, current_epoch, updated_at, author_job_id, reason)
           VALUES (?, ?, ?, ?, ?)
           ON CONFLICT(scope) DO UPDATE SET
             current_epoch = excluded.current_epoch,
             updated_at = excluded.updated_at,
             author_job_id = excluded.author_job_id,
             reason = excluded.reason"#,
    );
    sqlx::query(&sql)
        .bind(scope)
        .bind(next_epoch)
        .bind(updated_at)
        .bind(author_job_id)
        .bind(reason)
        .execute(pool)
        .await?;
    Ok(())
}

#[cfg(test)]
mod epoch_tests {
    use super::*;
    use sqlx::any::{AnyPoolOptions, install_default_drivers};

    async fn setup_pool() -> sqlx::AnyPool {
        install_default_drivers();
        let pool = AnyPoolOptions::new()
            .max_connections(1)
            .connect("sqlite::memory:")
            .await
            .unwrap();
        sqlx::query(
            "CREATE TABLE cache_epochs (
                scope TEXT PRIMARY KEY,
                current_epoch INTEGER NOT NULL,
                updated_at TEXT NOT NULL,
                author_job_id INTEGER NOT NULL,
                reason TEXT NOT NULL
            )",
        )
        .execute(&pool)
        .await
        .unwrap();
        pool
    }

    #[tokio::test]
    async fn current_epoch_defaults_to_zero() {
        let pool = setup_pool().await;
        let v = current_epoch_for(&pool, AdapterBackend::Sqlite, "scope:x")
            .await
            .unwrap();
        assert_eq!(v, 0);
    }

    #[tokio::test]
    async fn upsert_then_read_roundtrip() {
        let pool = setup_pool().await;
        upsert_epoch_for(
            &pool,
            AdapterBackend::Sqlite,
            "scope:x",
            7,
            "2026-01-01T00:00:00Z",
            42,
            "test",
        )
        .await
        .unwrap();
        let v = current_epoch_for(&pool, AdapterBackend::Sqlite, "scope:x")
            .await
            .unwrap();
        assert_eq!(v, 7);

        // ON CONFLICT branch
        upsert_epoch_for(
            &pool,
            AdapterBackend::Sqlite,
            "scope:x",
            8,
            "2026-01-01T00:00:01Z",
            43,
            "bump",
        )
        .await
        .unwrap();
        let v = current_epoch_for(&pool, AdapterBackend::Sqlite, "scope:x")
            .await
            .unwrap();
        assert_eq!(v, 8);
    }
}

use std::fs;
use std::path::{Path, PathBuf};
use std::process::Command;
use std::time::Instant;

use anyhow::{Context, Result};
use cargo_aer::scan_workspace;
use chrono::Utc;

use crate::model::{BenchVariantResult, ExceptionCaseResult, ExceptionCaseSpec, ScenarioReport};

pub fn run(output: &Path) -> Result<ScenarioReport> {
    let root = workspace_root();
    let manifest_path = root.join("proof/examples/labs/exception-zoo/manifest.json");
    let payload = fs::read_to_string(&manifest_path)
        .with_context(|| format!("failed to read {}", manifest_path.display()))?;
    let specs: Vec<ExceptionCaseSpec> = serde_json::from_str(&payload)
        .with_context(|| format!("failed to parse {}", manifest_path.display()))?;

    let mut results = Vec::new();
    let mut cases = Vec::new();
    for spec in specs {
        if !spec.benchmarkable {
            continue;
        }
        let start = Instant::now();
        let (success, observed_signal) = match spec.mode.as_str() {
            "scan" => run_scan_case(&root, &spec)?,
            "test" => run_cargo_case(&root, &spec, "test")?,
            _ => run_cargo_case(&root, &spec, "check")?,
        };
        let wall_time_ms = start.elapsed().as_millis() as u64;
        cases.push(ExceptionCaseResult {
            case_id: spec.case_id.clone(),
            category: spec.category.clone(),
            failure_mode: spec.failure_mode.clone(),
            expected_signal: spec.expected_signal.clone(),
            observed_signal: observed_signal.clone(),
            success,
            wall_time_ms,
            docs: spec.docs.clone(),
        });
        results.push(BenchVariantResult {
            scenario: "exceptions".to_string(),
            variant: spec.case_id.clone(),
            wall_time_ms,
            peak_rss_kb: None,
            thread_count_max: None,
            throughput: None,
            latency_p50_ms: None,
            latency_p95_ms: None,
            context_files: None,
            context_bytes: None,
            selected_tests: None,
            selected_arcs: None,
            notes: vec![
                format!("mode: {}", spec.mode),
                format!("success: {}", success),
                format!("observed: {}", observed_signal),
            ],
        });
    }

    let report = ScenarioReport {
        scenario: "exceptions".to_string(),
        generated_at: Utc::now().format("%Y-%m-%d").to_string(),
        results,
        cases,
        notes: vec![
            "The exception zoo mixes compile failures, runtime failures, and structural scan findings.".to_string(),
            "These fixtures model common vibe-coding failure modes that agents should normalize instead of hiding.".to_string(),
        ],
    };
    fs::write(output, serde_json::to_string_pretty(&report)?)
        .with_context(|| format!("failed to write {}", output.display()))?;
    Ok(report)
}

fn run_scan_case(root: &Path, spec: &ExceptionCaseSpec) -> Result<(bool, String)> {
    let manifest = root.join(&spec.manifest_path);
    let report = scan_workspace(Some(&manifest))?;
    let observed = match report
        .findings
        .iter()
        .find(|finding| finding.class_id == spec.expected_signal)
    {
        Some(finding) => finding.class_id.clone(),
        None => match report.findings.first() {
            Some(finding) => finding.class_id.clone(),
            None => "no-finding".to_string(),
        },
    };
    Ok((observed == spec.expected_signal, observed))
}

fn run_cargo_case(
    root: &Path,
    spec: &ExceptionCaseSpec,
    subcommand: &str,
) -> Result<(bool, String)> {
    let manifest = root.join(&spec.manifest_path);
    let mut command = Command::new("cargo");
    command
        .arg(subcommand)
        .arg("--quiet")
        .arg("--manifest-path")
        .arg(&manifest);
    command.args(&spec.cargo_args);
    let output = command
        .output()
        .with_context(|| format!("failed to run cargo {subcommand} for {}", spec.case_id))?;
    let combined = String::from_utf8_lossy(&output.stderr).to_string()
        + &String::from_utf8_lossy(&output.stdout);
    let observed = first_signal(&combined);
    let success = combined.contains(&spec.expected_signal);
    Ok((success, observed))
}

fn first_signal(output: &str) -> String {
    if let Some(line) = output
        .lines()
        .find(|line| line.contains("error") || line.contains("panicked"))
    {
        line.trim().to_string()
    } else {
        "no-error-line-found".to_string()
    }
}

fn workspace_root() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .parent()
        .and_then(|path| path.parent())
        .expect("workspace root")
        .to_path_buf()
}

#![allow(clippy::single_char_add_str)]
mod exceptions;
mod model;
mod psd_mechanics;
mod repo_shape;
mod runtime;
mod witness_loop;

use std::fs;
use std::path::PathBuf;

use anyhow::{Context, Result};
use chrono::Utc;
use clap::{Parser, Subcommand, ValueEnum};

use crate::model::ScenarioReport;
use crate::runtime::RuntimeVariant;

#[derive(Parser)]
#[command(name = "arc-bench")]
#[command(about = "Benchmarked demos for the Agent-Native Rust Standard")]
struct Cli {
    #[command(subcommand)]
    command: Command,
}

#[derive(Subcommand)]
enum Command {
    Run {
        #[arg(value_enum)]
        scenario: Scenario,
        #[arg(long)]
        output: Option<PathBuf>,
    },
    Report {
        #[arg(long, default_value = "bench-results")]
        input_dir: PathBuf,
        #[arg(long, default_value = "bench-results/comparison.md")]
        output: PathBuf,
    },
    #[command(hide = true)]
    InternalRuntime {
        #[arg(long)]
        variant: String,
        #[arg(long)]
        ops: usize,
        #[arg(long)]
        workers: usize,
        #[arg(long)]
        key_space: u64,
    },
}

#[derive(Clone, Copy, ValueEnum)]
enum Scenario {
    #[value(name = "repo-shape")]
    RepoShape,
    Runtime,
    Exceptions,
    #[value(name = "witness-loop")]
    WitnessLoop,
    #[value(name = "psd-mechanics")]
    PsdMechanics,
}

fn main() {
    if let Err(error) = run() {
        eprintln!("arc-bench error: {error:#}");
        std::process::exit(1);
    }
}

fn run() -> Result<()> {
    let cli = Cli::parse();
    match cli.command {
        Command::Run { scenario, output } => {
            let output = match output {
                Some(path) => path,
                None => default_output(scenario),
            };
            if let Some(parent) = output.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            let report = match scenario {
                Scenario::RepoShape => repo_shape::run(&output)?,
                Scenario::Runtime => runtime::run(&output)?,
                Scenario::Exceptions => exceptions::run(&output)?,
                Scenario::WitnessLoop => witness_loop::run(&output)?,
                Scenario::PsdMechanics => psd_mechanics::run(&output)?,
            };
            println!("{}", serde_json::to_string_pretty(&report)?);
        }
        Command::Report { input_dir, output } => {
            let mut reports = Vec::new();
            for entry in fs::read_dir(&input_dir)
                .with_context(|| format!("failed to read {}", input_dir.display()))?
            {
                let entry = entry?;
                let path = entry.path();
                if path.extension().and_then(|ext| ext.to_str()) != Some("json") {
                    continue;
                }
                let payload = fs::read_to_string(&path)
                    .with_context(|| format!("failed to read {}", path.display()))?;
                let report: ScenarioReport = serde_json::from_str(&payload)
                    .with_context(|| format!("failed to parse {}", path.display()))?;
                reports.push(report);
            }
            reports.sort_by(|left, right| left.scenario.cmp(&right.scenario));
            let markdown = build_report(&reports);
            if let Some(parent) = output.parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("failed to create {}", parent.display()))?;
            }
            fs::write(&output, markdown)
                .with_context(|| format!("failed to write {}", output.display()))?;
            println!("{}", output.display());
        }
        Command::InternalRuntime {
            variant,
            ops,
            workers,
            key_space,
        } => {
            let variant = RuntimeVariant::parse(&variant)?;
            let result = runtime::run_internal(variant, ops, workers, key_space)?;
            println!("{}", serde_json::to_string(&result)?);
        }
    }
    Ok(())
}

fn default_output(scenario: Scenario) -> PathBuf {
    let name = match scenario {
        Scenario::RepoShape => "repo-shape",
        Scenario::Runtime => "runtime",
        Scenario::Exceptions => "exceptions",
        Scenario::WitnessLoop => "witness-loop",
        Scenario::PsdMechanics => "psd-mechanics",
    };
    PathBuf::from(format!("bench-results/{name}.json"))
}

fn build_report(reports: &[ScenarioReport]) -> String {
    let mut output = String::new();
    output.push_str("# Proof-Scoped Benchmark Comparison\n\n");
    output.push_str(&format!("Generated: {}\n\n", Utc::now().format("%Y-%m-%d")));
    for report in reports {
        output.push_str(&format!("## {}\n\n", report.scenario));
        output.push_str("| Variant | Wall ms | Selected ARCs | Selected tests | Context files | Context bytes | Throughput | P50 ms | P95 ms |\n");
        output.push_str("| --- | --- | --- | --- | --- | --- | --- | --- | --- |\n");
        for result in &report.results {
            output.push_str(&format!(
                "| {} | {} | {} | {} | {} | {} | {} | {} | {} |\n",
                result.variant,
                result.wall_time_ms,
                render_option(result.selected_arcs),
                render_option(result.selected_tests),
                render_option(result.context_files),
                render_option(result.context_bytes),
                render_float(result.throughput),
                render_float(result.latency_p50_ms),
                render_float(result.latency_p95_ms),
            ));
        }
        if !report.notes.is_empty() {
            output.push_str("\n");
            for note in &report.notes {
                output.push_str(&format!("- {}\n", note));
            }
            output.push('\n');
        }
        if !report.cases.is_empty() {
            output.push_str("| Case | Success | Expected | Observed | Wall ms |\n");
            output.push_str("| --- | --- | --- | --- | --- |\n");
            for case in &report.cases {
                output.push_str(&format!(
                    "| {} | {} | {} | {} | {} |\n",
                    case.case_id,
                    case.success,
                    case.expected_signal.replace('|', "\\|"),
                    case.observed_signal.replace('|', "\\|"),
                    case.wall_time_ms
                ));
            }
            output.push('\n');
        }
    }
    output
}

fn render_option<T: std::fmt::Display>(value: Option<T>) -> String {
    match value {
        Some(value) => value.to_string(),
        None => "-".to_string(),
    }
}

fn render_float(value: Option<f64>) -> String {
    match value {
        Some(value) => format!("{value:.2}"),
        None => "-".to_string(),
    }
}

use std::fs;
use std::path::{Path, PathBuf};

use anyhow::{Context, Result};
use chrono::Utc;
use serde::Deserialize;

use crate::model::{BenchVariantResult, ScenarioReport};

pub fn run(output: &Path) -> Result<ScenarioReport> {
    let root = workspace_root();
    let scratch = std::env::temp_dir().join(format!(
        "psd-mechanics-{}",
        match std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH) {
            Ok(duration) => duration.as_nanos(),
            Err(_) => 0,
        }
    ));
    fs::create_dir_all(&scratch)
        .with_context(|| format!("failed to create {}", scratch.display()))?;

    let repo_shape = crate::repo_shape::run(&scratch.join("repo-shape.json"))?;
    let witness_loop = crate::witness_loop::run(&scratch.join("witness-loop.json"))?;
    let exceptions = crate::exceptions::run(&scratch.join("exceptions.json"))?;

    let (classification_accuracy, false_positive_eliminations) =
        witness_metrics(&root, &witness_loop)?;
    let repo_delta = repo_shape_delta(&repo_shape);
    let exception_successes = exceptions.cases.iter().filter(|case| case.success).count();

    let compile_manifest =
        root.join("proof/examples/labs/exception-zoo/cases/borrow-lifetime/Cargo.toml");
    let compile_root = compile_manifest
        .parent()
        .context("compile fixture manifest has no parent")?;
    let compile_packets =
        cargo_witness::diagnose::diagnose_workspace(compile_root, Some(&compile_manifest))?;
    let compile_routing_success = compile_packets
        .packets
        .iter()
        .find(|packet| packet.level == "error")
        .map(|packet| packet.owning_arc != "<unmatched>" && !packet.local_commands.is_empty())
        .unwrap_or(false);

    let repair_root = scratch.join("repair-runtime");
    let repair_success = repair_packet_enrichment_success(&repair_root)?;

    let results = vec![
        build_variant_result(
            "repo-shape",
            repo_shape.results.iter().map(|result| result.wall_time_ms).sum(),
            repo_shape
                .results
                .iter()
                .find(|result| result.variant == "arcified")
                .and_then(|result| result.context_files),
            repo_shape
                .results
                .iter()
                .find(|result| result.variant == "arcified")
                .and_then(|result| result.context_bytes),
            repo_shape
                .results
                .iter()
                .find(|result| result.variant == "arcified")
                .and_then(|result| result.selected_tests),
            repo_shape
                .results
                .iter()
                .find(|result| result.variant == "arcified")
                .and_then(|result| result.selected_arcs),
            vec![
                format!(
                    "Arcified context bytes: {} vs monolith {} (~{:.2}x smaller).",
                    repo_delta.arcified_context_bytes,
                    repo_delta.monolith_context_bytes,
                    repo_delta.context_reduction_ratio
                ),
                "Measures default context shrinkage for a local business-rule change.".to_string(),
            ],
        ),
        build_variant_result(
            "witness-loop",
            witness_loop.results.iter().map(|result| result.wall_time_ms).sum(),
            None,
            None,
            Some(false_positive_eliminations),
            None,
            vec![
                format!(
                    "Classification accuracy across scripted witness mutations: {:.2}.",
                    classification_accuracy
                ),
                format!("False-positive boundary escalations eliminated: {}.", false_positive_eliminations),
            ],
        ),
        build_variant_result(
            "exceptions",
            exceptions.results.iter().map(|result| result.wall_time_ms).sum(),
            None,
            None,
            Some(exception_successes),
            None,
            vec![
                format!("Exception-zoo detections: {exception_successes}/{}.", exceptions.cases.len()),
                "Covers compile failures, structural findings, and runtime-adjacent failures.".to_string(),
            ],
        ),
        build_variant_result(
            "compile-routing",
            0,
            None,
            None,
            Some(compile_packets.summary.total_errors),
            Some(compile_packets.summary.arcs_affected),
            vec![
                format!("Compile diagnostic routing success: {compile_routing_success}."),
                format!(
                    "Borrow-checker fixture produced {} error packet(s) across {} ARC(s).",
                    compile_packets.summary.total_errors,
                    compile_packets.summary.arcs_affected
                ),
            ],
        ),
        build_variant_result(
            "repair-packet",
            0,
            None,
            None,
            None,
            None,
            vec![
                format!("Synthetic runtime repair packet enrichment success: {repair_success}."),
                "Confirms that repair bundles preserve match provenance and suggested local validation.".to_string(),
            ],
        ),
    ];

    let report = ScenarioReport {
        scenario: "psd-mechanics".to_string(),
        generated_at: Utc::now().format("%Y-%m-%d").to_string(),
        results,
        cases: Vec::new(),
        notes: vec![
            "Aggregates repo-shape, witness-loop, exception, compile-routing, and repair-packet benchmarks.".to_string(),
            "Reports proof routing precision, context shrinkage, and failure enrichment for the current mutation set.".to_string(),
            "Covers the benchmark inputs used by the proof-scoped control plane.".to_string(),
        ],
    };

    fs::write(output, serde_json::to_string_pretty(&report)?)
        .with_context(|| format!("failed to write {}", output.display()))?;
    Ok(report)
}

#[derive(Debug)]
struct RepoShapeDelta {
    monolith_context_bytes: u64,
    arcified_context_bytes: u64,
    context_reduction_ratio: f64,
}

#[derive(Debug, Deserialize)]
struct WitnessScenarioSpec {
    id: String,
    expected_classification: String,
    expect_escalation: bool,
}

fn witness_metrics(root: &Path, witness_loop: &ScenarioReport) -> Result<(f64, usize)> {
    let manifest = root.join("proof/labs/witness-bench/manifest.json");
    let scenarios: Vec<WitnessScenarioSpec> = serde_json::from_str(
        &fs::read_to_string(&manifest)
            .with_context(|| format!("failed to read {}", manifest.display()))?,
    )
    .with_context(|| format!("failed to parse {}", manifest.display()))?;

    let mut correct = 0usize;
    let mut total = 0usize;
    let mut false_positive_eliminations = 0usize;

    for scenario in scenarios {
        let baseline_variant = format!("{}-baseline", scenario.id);
        let witnessed_variant = format!("{}-witnessed", scenario.id);
        let baseline = witness_loop
            .results
            .iter()
            .find(|result| result.variant == baseline_variant)
            .context("missing baseline witness-loop result")?;
        let witnessed = witness_loop
            .results
            .iter()
            .find(|result| result.variant == witnessed_variant)
            .context("missing witnessed witness-loop result")?;

        let observed_classification = match extract_note_value(&witnessed.notes, "Classification") {
            Some(value) => value,
            None => "",
        };
        let observed_escalation = extract_note_value(&witnessed.notes, "Escalated")
            .map(|value| value == "true")
            .unwrap_or(false);
        let baseline_escalation = extract_note_value(&baseline.notes, "Escalated")
            .map(|value| value == "true")
            .unwrap_or(false);

        if observed_classification == scenario.expected_classification
            && observed_escalation == scenario.expect_escalation
        {
            correct += 1;
        }
        if baseline_escalation && !scenario.expect_escalation && !observed_escalation {
            false_positive_eliminations += 1;
        }
        total += 1;
    }

    let accuracy = if total == 0 {
        0.0
    } else {
        correct as f64 / total as f64
    };
    Ok((accuracy, false_positive_eliminations))
}

fn repo_shape_delta(report: &ScenarioReport) -> RepoShapeDelta {
    let monolith = match report
        .results
        .iter()
        .find(|result| result.variant == "monolith")
        .and_then(|result| result.context_bytes)
    {
        Some(value) => value,
        None => 0,
    };
    let arcified = match report
        .results
        .iter()
        .find(|result| result.variant == "arcified")
        .and_then(|result| result.context_bytes)
    {
        Some(value) => value,
        None => 0,
    };
    let ratio = if arcified == 0 {
        0.0
    } else {
        monolith as f64 / arcified as f64
    };
    RepoShapeDelta {
        monolith_context_bytes: monolith,
        arcified_context_bytes: arcified,
        context_reduction_ratio: (ratio * 100.0).round() / 100.0,
    }
}

