pub struct ScanReport {
    pub generated_at: String,
    pub workspace_root: String,
    pub findings: Vec<Finding>,
    pub repair_hint: ReportRepairHint,
}

#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct AerRecord {
    #[serde(default)]
    pub id: String,
    #[serde(default)]
    pub class_id: String,
    #[serde(default)]
    pub rule: String,
    #[serde(default)]
    pub exception: String,
    #[serde(default)]
    pub reason: String,
    #[serde(default)]
    pub risk: String,
    #[serde(default)]
    pub owner: String,
    #[serde(default)]
    pub doc_links: Vec<String>,
    #[serde(default)]
    pub sunset_condition: String,
}

fn workspace_has_semver_profile(
    ci_profiles: &[cargo_vrc::model::CiProfile],
    shared_contracts: &[String],
) -> bool {
    if ci_profiles
        .iter()
        .find(|profile| profile.name.eq_ignore_ascii_case("scheduled-hardening"))
        .is_some_and(|profile| {
            profile
                .commands
                .iter()
                .any(|command| command_has_semver_signal(command))
        })
    {
        return true;
    }

    if ci_profiles.iter().any(|profile| {
        profile
            .commands
            .iter()
            .any(|command| command_has_semver_signal(command))
    }) {
        return true;
    }

    shared_contracts
        .iter()
        .any(|contract| contract.to_ascii_lowercase().contains("semver"))
}

fn command_has_semver_signal(command: &str) -> bool {
    let command = command.to_ascii_lowercase();
    command.contains("semver-checks") || command.contains("semver")
}

fn looks_like_junk_drawer(name: &str) -> bool {
    let name = name.to_ascii_lowercase();
    ["common", "utils", "helpers", "shared"]
        .iter()
        .any(|needle| {
            name == *needle
                || name.starts_with(&format!("{needle}-"))
                || name.ends_with(&format!("-{needle}"))
        })
}

fn looks_like_core_layer(agent: &PackageAgentMetadata, name: &str) -> bool {
    let purpose = agent.purpose.to_ascii_lowercase();
    name.contains("core") || purpose.contains("pure") || purpose.contains("domain")
}

fn hidden_io_signal(content: &str) -> bool {
    [
        "std::fs::",
        "tokio::fs::",
        "std::env::",
        "reqwest::",
        "ureq::",
        "std::net::",
    ]
    .iter()
    .any(|needle| content.contains(needle))
}

fn existing_exception(agent: &PackageAgentMetadata, class_id: &str) -> Option<String> {
    let normalized = class_id.replace('-', "_");
    agent
        .exceptions
        .iter()
        .find(|exception| exception.contains(class_id) || exception.contains(&normalized))
        .cloned()
}

fn report_repair_hint() -> ReportRepairHint {
    ReportRepairHint {
        purpose: "Route the next audit rerun".to_string(),
        reason: "The scan needs a local proof pointer when it returns a failure surface."
            .to_string(),
        common_fixes: vec![
            "Trim the failing surface to the owning module or manifest.".to_string(),
            "Re-run the narrow proof command listed in docs/testing.md.".to_string(),
        ],
        docs_url: "docs/testing.md#repair-receipts".to_string(),
        repair_hint: "cargo run -p cargo-aer -- scan --output aer-findings.json".to_string(),
    }
}

fn display_relative(root: &Path, path: &Path) -> String {
    match path.strip_prefix(root) {
        Ok(relative) if !relative.as_os_str().is_empty() => relative.display().to_string(),
        _ if path == root => ".".to_string(),
        _ => path.display().to_string(),
    }
}

fn display_workspace_root() -> String {
    ".".to_string()
}

fn sarif_level(severity: &str) -> &'static str {
    match severity {
        "error" => "error",
        "warning" => "warning",
        _ => "note",
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use cargo_vrc::model::CiProfile;
    use std::path::PathBuf;

    fn workspace_root() -> PathBuf {
        PathBuf::from(env!("CARGO_MANIFEST_DIR"))
            .parent()
            .and_then(|path| path.parent())
            .expect("workspace root")
            .to_path_buf()
    }

    fn current_manifest() -> PathBuf {
        workspace_root().join("Cargo.toml")
    }

    #[test]
    fn workspace_has_semver_profile_accepts_scheduled_hardening_commands() {
        let ci_profiles = vec![CiProfile {
            name: "scheduled-hardening".to_string(),
            commands: vec!["cargo semver-checks check-release".to_string()],
        }];

        assert!(workspace_has_semver_profile(&ci_profiles, &[]));
    }

    #[test]
    fn workspace_has_semver_profile_falls_back_to_shared_contracts() {
        let shared_contracts =
            vec!["Public APIs must run semver validation before release.".to_string()];

        assert!(workspace_has_semver_profile(&[], &shared_contracts));
    }

    #[test]
    fn workspace_has_semver_profile_rejects_missing_signal() {
        let ci_profiles = vec![CiProfile {
            name: "pull-request".to_string(),
            commands: vec!["cargo run -p cargo-aer -- scan --output aer-findings.json".to_string()],
        }];

        assert!(!workspace_has_semver_profile(&ci_profiles, &[]));
    }

    #[test]
    fn current_workspace_scan_uses_relative_paths_and_semver_gate() {
        let report = scan_workspace(Some(&current_manifest())).expect("scan current workspace");

        assert_eq!(report.workspace_root, ".");
        assert!(
            report
                .findings
                .iter()
                .all(|finding| !finding.path.starts_with('/'))
        );
        assert!(
            report
                .findings
                .iter()
                .all(|finding| !finding.path.contains("/private/tmp/")
                    && !finding.path.contains("/Users/"))
        );
        assert!(
            !report
                .findings
                .iter()
                .any(|finding| finding.class_id == "public-api-no-semver-gate")
        );
    }

    #[test]
    fn scan_workspace_detects_hidden_io_in_core_fixture() {
        let manifest =
            workspace_root().join("examples/labs/exception-zoo/cases/hidden-io-core/Cargo.toml");
        let report = scan_workspace(Some(&manifest)).expect("scan fixture workspace");
        assert!(
            report
                .findings
                .iter()
                .any(|finding| finding.class_id == "hidden-side-effects")
        );
    }

    #[test]
    fn scan_workspace_detects_missing_doctest_for_public_api_fixture() {
        let manifest =
            workspace_root().join("examples/labs/exception-zoo/cases/semver-break/Cargo.toml");
        let report = scan_workspace(Some(&manifest)).expect("scan fixture workspace");
        assert!(
            report
                .findings
                .iter()
                .any(|finding| finding.class_id == "public-api-no-doctest-coverage")
        );
    }
}

use std::fs;
use std::path::PathBuf;

use anyhow::{Context, Result, bail};
use clap::{Parser, Subcommand, ValueEnum};

use cargo_aer::{incomplete_records, init_records, markdown_report, sarif_report, scan_workspace};
use cargo_vrc::load_workspace;

#[derive(Parser)]
#[command(name = "cargo-aer")]
#[command(about = "Agent Exception Record auditing for Cargo workspaces")]
struct Cli {
    #[arg(long, global = true)]
    manifest_path: Option<PathBuf>,
    #[command(subcommand)]
    command: Command,
}

#[derive(Subcommand)]
enum Command {
    Scan {
        #[arg(long, default_value = "aer-findings.json")]
        output: PathBuf,
    },
    Init,
    Review,
    Report {
        #[arg(long, default_value = "aer-findings.json")]
        input: PathBuf,
        #[arg(long, value_enum, default_value_t = ReportFormat::Md)]
        format: ReportFormat,
        #[arg(long)]
        output: Option<PathBuf>,
    },
}

#[derive(Clone, Copy, ValueEnum)]
enum ReportFormat {
    Json,
    Md,
    Sarif,
}

fn main() {
    if let Err(error) = run() {
        eprintln!("cargo-aer error: {error:#}");
        std::process::exit(1);
    }
}

fn run() -> Result<()> {
    let cli = Cli::parse();
    match cli.command {
        Command::Scan { output } => {
            let report = scan_workspace(cli.manifest_path.as_deref())?;
            write_json(&output, &report)?;
            println!("{}", serde_json::to_string_pretty(&report)?);
            if report
                .findings
                .iter()
                .any(|finding| finding.severity == "error")
            {
                bail!("scan reported error-level findings");
            }
        }
        Command::Init => {
            let snapshot = load_workspace(cli.manifest_path.as_deref())?;
            let created = init_records(&snapshot.workspace_root)?;
            for path in created {
                println!("{}", path.display());
            }
        }
        Command::Review => {
            let snapshot = load_workspace(cli.manifest_path.as_deref())?;
            let findings = incomplete_records(&snapshot.workspace_root)?;
            println!("{}", serde_json::to_string_pretty(&findings)?);
            if !findings.is_empty() {
                bail!("found incomplete AER records");
            }
        }
        Command::Report {
            input,
            format,
            output,
        } => {
            let payload = fs::read_to_string(&input)
                .with_context(|| format!("failed to read {}", input.display()))?;
            let report: cargo_aer::ScanReport = serde_json::from_str(&payload)
                .with_context(|| format!("failed to parse {}", input.display()))?;
            match format {
                ReportFormat::Json => emit_text(output, serde_json::to_string_pretty(&report)?)?,
                ReportFormat::Md => emit_text(output, markdown_report(&report))?,
                ReportFormat::Sarif => emit_text(
                    output,
                    serde_json::to_string_pretty(&sarif_report(&report))?,
                )?,
            }
        }
    }
    Ok(())
}

fn emit_text(path: Option<PathBuf>, payload: String) -> Result<()> {
    if let Some(path) = path {
        if let Some(parent) = path.parent() {
            fs::create_dir_all(parent)
                .with_context(|| format!("failed to create {}", parent.display()))?;
        }
        fs::write(&path, payload).with_context(|| format!("failed to write {}", path.display()))?;
    } else {
        println!("{payload}");
    }
    Ok(())
}

fn write_json(path: &PathBuf, value: &impl serde::Serialize) -> Result<()> {
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)
            .with_context(|| format!("failed to create {}", parent.display()))?;
    }
    fs::write(path, serde_json::to_string_pretty(value)?)
        .with_context(|| format!("failed to write {}", path.display()))?;
    Ok(())
}

use std::fs;
use std::path::{Path, PathBuf};

use anyhow::{Context, Result};
use walkdir::WalkDir;

use super::*;

pub fn init_records(workspace_root: &Path) -> Result<Vec<PathBuf>> {
    let records_dir = workspace_root.join("aer-records");
    fs::create_dir_all(&records_dir)
        .with_context(|| format!("failed to create {}", records_dir.display()))?;
    let readme = records_dir.join("README.md");
    if !readme.exists() {
        fs::write(
            &readme,
            "# Agent Exception Records\n\nEach YAML file captures one explicit break from a strict default.\n",
        )
        .with_context(|| format!("failed to write {}", readme.display()))?;
    }
    let example = records_dir.join("EXAMPLE.yaml");
    if !example.exists() {
        fs::write(
            &example,
            r#"id: aer.example.mega-file-parser
class_id: mega-file
rule: "Files should stay below the house budget unless locality would be harmed."
exception: "Parser table remains in one file to preserve traceability."
reason: "Splitting the grammar table would make cross-rule debugging harder during a protocol migration."
risk: medium
owner: parser-team
doc_links:
  - https://doc.rust-lang.org/book/ch13-04-performance.html
sunset_condition: "Remove when the grammar format is stabilized and table generation lands."
"#,
        )
        .with_context(|| format!("failed to write {}", example.display()))?;
    }
    Ok(vec![readme, example])
}

pub fn incomplete_records(workspace_root: &Path) -> Result<Vec<Finding>> {
    let records_dir = workspace_root.join("aer-records");
    let mut findings = Vec::new();
    if !records_dir.exists() {
        return Ok(findings);
    }
    for entry in WalkDir::new(&records_dir)
        .into_iter()
        .filter_map(|entry| entry.ok())
    {
        let path = entry.path();
        if !path.is_file()
            || !matches!(
                path.extension().and_then(|ext| ext.to_str()),
                Some("yaml" | "yml")
            )
        {
            continue;
        }
        let record = parse_record(path)?;
        if record.owner.trim().is_empty() {
            findings.push(Finding {
                class_id: "incomplete-aer".to_string(),
                severity: "warning".to_string(),
                confidence: 0.95,
                path: display_relative(workspace_root, path),
                summary: "AER is missing an owner".to_string(),
                suggested_fix: "Set owner so the exception has clear stewardship.".to_string(),
                existing_exception: Some(record.id.clone()),
            });
        }
        if record.sunset_condition.trim().is_empty() {
            findings.push(Finding {
                class_id: "incomplete-aer".to_string(),
                severity: "warning".to_string(),
                confidence: 0.95,
                path: display_relative(workspace_root, path),
                summary: "AER is missing a sunset condition".to_string(),
                suggested_fix: "Add a concrete reevaluation condition or review date.".to_string(),
                existing_exception: Some(record.id.clone()),
            });
        }
    }
    Ok(findings)
}

fn parse_record(path: &Path) -> Result<AerRecord> {
    let contents = fs::read_to_string(path)
        .with_context(|| format!("failed to read {}", path.display()))?;
    Ok(serde_yaml::from_str(&contents)
        .with_context(|| format!("failed to parse {}", path.display()))?)
}

use super::*;

pub fn markdown_report(report: &ScanReport) -> String {
    let mut output = String::new();
    output.push_str("# cargo-aer Findings\n\n");
    output.push_str(&format!("Generated: {}\n\n", report.generated_at));
    output.push_str(&format!(
        "Repair hint: {} - {}. {}\n\n",
        report.repair_hint.purpose, report.repair_hint.reason, report.repair_hint.docs_url
    ));
    output.push_str("| Class | Severity | Confidence | Path | Summary | Suggested Fix |\n");
    output.push_str("| --- | --- | --- | --- | --- | --- |\n");
    for finding in &report.findings {
        output.push_str(&format!(
            "| {} | {} | {:.2} | `{}` | {} | {} |\n",
            finding.class_id,
            finding.severity,
            finding.confidence,
            finding.path,
            finding.summary.replace('|', "\\|"),
            finding.suggested_fix.replace('|', "\\|")
        ));
    }
    output
}

pub fn sarif_report(report: &ScanReport) -> serde_json::Value {
    let mut rules = std::collections::BTreeMap::new();
    for finding in &report.findings {
        rules.entry(finding.class_id.clone()).or_insert_with(|| {
            serde_json::json!({
                "id": finding.class_id,
                "name": finding.class_id,
                "shortDescription": { "text": finding.summary },
                "help": { "text": finding.suggested_fix },
            })
        });
    }

    serde_json::json!({
        "$schema": "https://json.schemastore.org/sarif-2.1.0.json",
        "version": "2.1.0",
        "runs": [{
            "tool": {
                "driver": {
                    "name": "cargo-aer",
                    "rules": rules.into_values().collect::<Vec<_>>(),
                }
            },
            "results": report.findings.iter().map(|finding| {
                serde_json::json!({
                    "ruleId": finding.class_id,
                    "level": sarif_level(&finding.severity),
                    "message": { "text": finding.summary },
                    "locations": [{
                        "physicalLocation": {
                            "artifactLocation": { "uri": finding.path }
                        }
                    }]
                })
            }).collect::<Vec<_>>()
        }]
    })
}

use std::fs;
use std::path::Path;

use anyhow::{Context, Result};
use cargo_vrc::{WorkspaceSnapshot, load_workspace};
use regex::Regex;
use walkdir::WalkDir;

use super::*;

pub fn scan_workspace(manifest_path: Option<&Path>) -> Result<ScanReport> {
    let snapshot = load_workspace(manifest_path)?;
    let mut findings = Vec::new();
    for package in &snapshot.packages {
        findings.extend(scan_package(&snapshot, package)?);
    }
    for finding in &mut findings {
        if finding.existing_exception.is_some() {
            finding.severity = "note".to_string();
        }
    }
    findings.sort_by(|left, right| {
        left.path
            .cmp(&right.path)
            .then(left.class_id.cmp(&right.class_id))
    });
    Ok(ScanReport {
        generated_at: chrono::Utc::now().format("%Y-%m-%d").to_string(),
        workspace_root: display_workspace_root(),
        findings,
        repair_hint: report_repair_hint(),
    })
}

fn scan_package(
    snapshot: &WorkspaceSnapshot,
    package: &cargo_vrc::workspace::PackageSnapshot,
) -> Result<Vec<Finding>> {
    let mut findings = Vec::new();
    let existing = |class_id: &str| existing_exception(&package.agent, class_id);

    if package.agent.purpose.trim().is_empty()
        || package.agent.local_validate.is_empty()
        || package.agent.invariants.is_empty()
    {
        findings.push(Finding {
            class_id: "missing-local-validation-metadata".to_string(),
            severity: "warning".to_string(),
            confidence: 0.98,
            path: display_relative(&snapshot.workspace_root, &package.manifest_path),
            summary: format!(
                "{} is missing purpose, invariants, or local validation metadata",
                package.name
            ),
            suggested_fix: "Populate package.metadata.agent with purpose, invariants, and local_validate commands.".to_string(),
            existing_exception: existing("missing-local-validation-metadata"),
        });
    }

    if looks_like_junk_drawer(&package.name) {
        findings.push(Finding {
            class_id: "junk-drawer-shared-crate".to_string(),
            severity: "warning".to_string(),
            confidence: 0.85,
            path: display_relative(&snapshot.workspace_root, &package.manifest_path),
            summary: format!("{} looks like a generic shared crate", package.name),
            suggested_fix:
                "Rename or split the crate by domain so ownership and blast radius stay clear."
                    .to_string(),
            existing_exception: existing("junk-drawer-shared-crate"),
        });
    }

    let workspace_has_semver = workspace_has_semver_profile(
        &snapshot.workspace_agent.ci_profiles,
        &snapshot.workspace_agent.shared_contracts,
    );

    let source_file_count = package_source_file_count(&package.package_root);

    findings.extend(scan_function_lengths(
        &snapshot.workspace_root,
        &package.manifest_path,
        package,
        existing,
    )?);
    findings.extend(scan_unsafe_blocks(
        &snapshot.workspace_root,
        &package.manifest_path,
        package,
        existing,
    )?);

    if source_file_count > 1
        && !workspace_has_semver
        && package.agent.local_validate.iter().any(|cmd| {
            command_has_semver_signal(cmd)
                || cmd.contains("cargo check")
                || cmd.contains("cargo test")
                || cmd.contains("cargo nextest")
        })
    {
        findings.push(Finding {
            class_id: "semver-profile-check-missing".to_string(),
            severity: "warning".to_string(),
            confidence: 0.8,
            path: display_relative(&snapshot.workspace_root, &package.manifest_path),
            summary: format!(
                "{} has validation commands that look like a semver-safe profile but no workspace profile is configured",
                package.name
            ),
            suggested_fix: "Add a semver-safe cargo profile or simplify validation commands so they don't imply profile-based compatibility guarantees.".to_string(),
            existing_exception: existing("semver-profile-check-missing"),
        });
    }

    if package.agent.public_api
        && !package
            .agent
            .local_validate
            .iter()
            .any(|command| command.contains("--doc"))
    {
        findings.push(Finding {
            class_id: "public-api-no-doctest-coverage".to_string(),
            severity: "warning".to_string(),
            confidence: 0.92,
            path: display_relative(&snapshot.workspace_root, &package.manifest_path),
            summary: format!(
                "{} is public_api=true but local validation omits doctests",
                package.name
            ),
            suggested_fix: "Add `cargo test -p <crate> --doc` to local_validate or document an AER.".to_string(),
            existing_exception: existing("public-api-no-doctest-coverage"),
        });
    }

    if source_file_count >= 25
        && package.agent.local_validate.iter().any(|cmd| {
            cmd.contains("cargo run -p cargo-aer")
                || cmd.contains("cargo aer")
                || command_has_semver_signal(cmd)
        })
        && !package.agent.local_validate.iter().any(|cmd| cmd.contains("--incompatible"))
    {
        findings.push(Finding {
            class_id: "workspace-validation-drift".to_string(),
            severity: "warning".to_string(),
            confidence: 0.7,
            path: display_relative(&snapshot.workspace_root, &package.manifest_path),
            summary: format!(
                "{} looks like a wide workspace package but its validation commands do not advertise drift/semver handling",
                package.name
            ),
            suggested_fix: "Make the validation command explicitly acknowledge compatibility drift or split the package into smaller modules.".to_string(),
            existing_exception: existing("workspace-validation-drift"),
        });
    }

    let hidden_io_detected = package_has_hidden_io(&package.package_root);

    if looks_like_core_layer(&package.agent, &package.name)
        && hidden_io_detected
    {
        findings.push(Finding {
            class_id: "hidden-side-effects".to_string(),
            severity: "warning".to_string(),
            confidence: 0.73,
            path: display_relative(&snapshot.workspace_root, &package.manifest_path),
            summary: "File appears to perform I/O or env access inside a core or pure layer"
                .to_string(),
            suggested_fix: "Move I/O and env access to an adapter boundary and inject the result into the core layer.".to_string(),
            existing_exception: existing("hidden-side-effects"),
        });
    }

    Ok(findings)
}

fn scan_function_lengths(
    root: &Path,
    manifest_path: &Path,
    package: &cargo_vrc::workspace::PackageSnapshot,
    existing: impl Fn(&str) -> Option<String>,
) -> Result<Vec<Finding>> {
    let mut findings = Vec::new();
    let contents = read_file_contents(manifest_path)?;
    let func_re = Regex::new(r"(?m)^\s*(?:pub(?:\([^)]*\))?\s+)?(?:async\s+)?fn\s+([A-Za-z0-9_]+)")?;
    let mut longest = 0usize;
    let mut longest_fn = String::new();
    for cap in func_re.captures_iter(&contents) {
        let Some(name_match) = cap.get(1) else {
            continue;
        };
        let name = name_match.as_str();
        let len = contents
            .lines()
            .skip_while(|line| !line.contains(name))
            .take_while(|line| !line.trim_start().starts_with("fn "))
            .count();
        if len > longest {
            longest = len;
            longest_fn = name.to_string();
        }
    }
    if longest > 150 {
        findings.push(Finding {
            class_id: "function-too-long".to_string(),
            severity: "warning".to_string(),
            confidence: 0.72,
            path: display_relative(root, manifest_path),
            summary: format!(
                "{} has a long function `{}` at {} lines",
                package.name, longest_fn, longest
            ),
            suggested_fix: "Split the function into smaller named helpers that each own one responsibility.".to_string(),
            existing_exception: existing("function-too-long"),
        });
    }
    Ok(findings)
}

fn scan_unsafe_blocks(
    root: &Path,
    manifest_path: &Path,
    package: &cargo_vrc::workspace::PackageSnapshot,
    existing: impl Fn(&str) -> Option<String>,
) -> Result<Vec<Finding>> {
    let mut findings = Vec::new();
    let contents = read_file_contents(manifest_path)?;
    // SAFETY: this scan only counts textual `unsafe` markers in source text;
    // it does not evaluate or execute any unsafe Rust code.
    let unsafe_marker_count = contents.matches("unsafe").count();
    if unsafe_marker_count > 8 {
        findings.push(Finding {
            class_id: "unsafe-surface-heavy".to_string(),
            severity: "warning".to_string(),
            confidence: 0.8,
            path: display_relative(root, manifest_path),
            // SAFETY: lexical scan only; this counts textual `unsafe` markers.
            summary: format!(
                "{} hits the unsafe token {} times",
                package.name, unsafe_marker_count
            ),
            suggested_fix: "Audit unsafe blocks for narrower wrappers or safe abstractions.".to_string(),
            existing_exception: existing("unsafe-surface-heavy"),
        });
    }
    Ok(findings)
}

fn package_source_file_count(package_root: &Path) -> usize {
    WalkDir::new(package_root)
        .into_iter()
        .filter_map(|entry| entry.ok())
        .filter(|entry| entry.path().is_file())
        .filter(|entry| entry.path().extension().and_then(|ext| ext.to_str()) == Some("rs"))
        .count()
}

fn package_has_hidden_io(package_root: &Path) -> bool {
    WalkDir::new(package_root)
        .into_iter()
        .filter_map(|entry| entry.ok())
        .filter(|entry| entry.path().is_file())
        .filter(|entry| entry.path().extension().and_then(|ext| ext.to_str()) == Some("rs"))
        .filter_map(|entry| fs::read_to_string(entry.path()).ok())
        .any(|content| hidden_io_signal(&content))
}

fn read_file_contents(path: &Path) -> Result<String> {
    fs::read_to_string(path).with_context(|| format!("failed to read {}", path.display()))
}

