use std::collections::BTreeSet;
use std::fs;
use std::path::{Path, PathBuf};

use anyhow::{Context, Result};
use globset::{Glob, GlobSet, GlobSetBuilder};
use sha2::{Digest, Sha256};
use chrono::Utc;
use walkdir::WalkDir;

use crate::model::VerificationReport;
use crate::{PackageSnapshot, WorkspaceSnapshot};

pub(crate) fn verify_workspace_fields(snapshot: &WorkspaceSnapshot) -> VerificationReport {
    let mut report = VerificationReport::default();

    if snapshot.workspace_agent.validation_order.is_empty() {
        report
            .warnings
            .push("workspace.metadata.agent.validation_order is empty".to_string());
    }
    if snapshot.workspace_agent.instruction_roots.is_empty() {
        report
            .warnings
            .push("workspace.metadata.agent.instruction_roots is empty".to_string());
    }

    for package in &snapshot.packages {
        if package.agent.purpose.trim().is_empty() {
            report.errors.push(format!(
                "{} is missing package.metadata.agent.purpose",
                package.name
            ));
        }
        if package.agent.invariants.is_empty() {
            report
                .warnings
                .push(format!("{} is missing explicit invariants", package.name));
        }
        if package.agent.local_validate.is_empty() {
            report.errors.push(format!(
                "{} is missing package.metadata.agent.local_validate",
                package.name
            ));
        }
        if package.agent.owned_paths.is_empty() {
            report.warnings.push(format!(
                "{} is missing package.metadata.agent.owned_paths; path matching will fall back to package roots",
                package.name
            ));
        }
        if package.agent.public_api && package.agent.boundary_validate.is_empty() {
            report.errors.push(format!(
                "{} is marked public_api=true but has no boundary_validate commands",
                package.name
            ));
        }
        let local_agents = package.package_root.join("AGENTS.md");
        if !local_agents.exists() {
            report.warnings.push(format!(
                "{} has no local AGENTS.md; consider adding crate-specific guidance",
                package.name
            ));
        }
    }

    report
}

pub(crate) fn normalize_changed_paths(workspace_root: &Path, changed_paths: &[PathBuf]) -> Vec<String> {
    let mut normalized = changed_paths
        .iter()
        .map(|path| {
            let absolute = if path.is_absolute() {
                path.clone()
            } else {
                workspace_root.join(path)
            };
            display_relative(workspace_root, &absolute)
        })
        .collect::<Vec<_>>();
    normalized.sort();
    normalized.dedup();
    normalized
}

pub(crate) fn matched_paths(
    snapshot: &WorkspaceSnapshot,
    package: &PackageSnapshot,
    changed_paths: &[String],
) -> Vec<String> {
    let matcher = build_globset(&package.agent.owned_paths).ok();
    let package_root = display_relative(&snapshot.workspace_root, &package.package_root);
    let mut hits = BTreeSet::new();
    for changed in changed_paths {
        if changed == &package_root || changed.starts_with(&(package_root.clone() + "/")) {
            hits.insert(changed.clone());
            continue;
        }
        if let Some(matcher) = &matcher {
            let changed_path = Path::new(changed);
            if package_root == "." && matcher.is_match(changed_path) {
                hits.insert(changed.clone());
                continue;
            }
            if let Ok(stripped) = changed_path.strip_prefix(&package_root)
                && matcher.is_match(stripped)
            {
                hits.insert(changed.clone());
            }
        }
    }
    hits.into_iter().collect()
}

pub(crate) fn build_globset(patterns: &[String]) -> Result<GlobSet> {
    let mut builder = GlobSetBuilder::new();
    for pattern in patterns {
        builder.add(Glob::new(pattern)?);
    }
    builder
        .build()
        .context("failed to compile owned_paths globset")
}

pub(crate) fn boundary_trigger(path: &str, package: &PackageSnapshot) -> bool {
    let path = Path::new(path);
    let file_name = match path.file_name().and_then(|name| name.to_str()) {
        Some(value) => value,
        None => "",
    };
    file_name == "Cargo.toml"
        || (package.agent.public_api && (file_name == "lib.rs" || file_name == "mod.rs"))
        || path
            .components()
            .any(|component| component.as_os_str() == "tests")
}

pub(crate) fn public_surfaces(package: &PackageSnapshot) -> Vec<String> {
    if !package.agent.entrypoints.is_empty() {
        return package.agent.entrypoints.clone();
    }
    package.target_names.clone()
}

pub(crate) fn risk_tags(package: &PackageSnapshot) -> Vec<String> {
    let mut tags = vec![if package.agent.risk.is_empty() {
        "risk:unspecified".to_string()
    } else {
        format!("risk:{}", package.agent.risk)
    }];
    if package.agent.public_api {
        tags.push("public-api".to_string());
    }
    if !package.agent.exceptions.is_empty() {
        tags.push("has-aer".to_string());
    }
    tags
}

pub(crate) fn instruction_locations(workspace_root: &Path, package: &PackageSnapshot) -> Vec<String> {
    let mut locations = Vec::new();
    for path in [
        workspace_root.join("AGENTS.md"),
        workspace_root.join("CLAUDE.md"),
        workspace_root.join(".github/copilot-instructions.md"),
        package.package_root.join("AGENTS.md"),
    ] {
        if path.exists() {
            locations.push(display_relative(workspace_root, &path));
        }
    }
    locations
}

pub(crate) fn context_roots(workspace_root: &Path, package: &PackageSnapshot) -> Vec<String> {
    let mut roots = vec![display_relative(workspace_root, &package.package_root)];
    for suffix in ["src", "tests", "examples"] {
        let candidate = package.package_root.join(suffix);
        if candidate.exists() {
            roots.push(display_relative(workspace_root, &candidate));
        }
    }
    for location in instruction_locations(workspace_root, package) {
        roots.push(location);
    }
    roots.sort();
    roots.dedup();
    roots
}

pub(crate) fn owned_path_display(package: &PackageSnapshot) -> Vec<String> {
    if package.agent.owned_paths.is_empty() {
        return vec!["<package-root>".to_string()];
    }
    package.agent.owned_paths.clone()
}

pub(crate) fn proof_density(package: &PackageSnapshot) -> f64 {
    let proof_points = package.agent.invariants.len()
        + package.agent.local_validate.len()
        + package.agent.boundary_validate.len()
        + package.agent.exceptions.len();
    let entrypoints = package.agent.entrypoints.len().max(1);
    let density = proof_points as f64 / entrypoints as f64;
    (density * 100.0).round() / 100.0
}

pub(crate) fn api_surface_hash(package: &PackageSnapshot) -> String {
    let mut hasher = Sha256::new();
    hasher.update(package.name.as_bytes());
    hasher.update(if package.agent.public_api {
        &b"public"[..]
    } else {
        &b"private"[..]
    });
    for item in public_surfaces(package) {
        hasher.update(item.as_bytes());
    }
    for feature in &package.features {
        hasher.update(feature.as_bytes());
    }
    hasher
        .finalize()
        .iter()
        .map(|byte| format!("{byte:02x}"))
        .collect()
}

pub(crate) fn collect_profile_commands(
    snapshot: &WorkspaceSnapshot,
    profile_name: &str,
    needle: &str,
) -> Vec<String> {
    match snapshot
        .workspace_agent
        .ci_profiles
        .iter()
        .find(|profile| profile.name == profile_name)
    {
        Some(profile) => profile
            .commands
            .iter()
            .filter(|command| command.contains(needle))
            .cloned()
            .collect::<Vec<_>>(),
        None => Vec::new(),
    }
}

pub(crate) fn estimated_cost(package: &PackageSnapshot) -> String {
    let local = package.agent.local_validate.len();
    let boundary = package.agent.boundary_validate.len();
    let harnesses = package.target_tests.len();
    match local + boundary + harnesses {
        0..=2 => "low".to_string(),
        3..=5 => "medium".to_string(),
        _ => "high".to_string(),
    }
}

pub(crate) fn required_for_change_types(package: &PackageSnapshot) -> Vec<String> {
    let mut change_types = vec!["leaf-bugfix".to_string(), "invariant-change".to_string()];
    if package.agent.public_api {
        change_types.push("public-api-change".to_string());
    }
    if !package.features.is_empty() {
        change_types.push("feature-change".to_string());
    }
    change_types.push("manifest-change".to_string());
    change_types
}

pub(crate) fn display_relative(root: &Path, path: &Path) -> String {
    match path.strip_prefix(root) {
        Ok(relative) if !relative.as_os_str().is_empty() => relative.display().to_string(),
        _ if path == root => ".".to_string(),
        _ => path.display().to_string(),
    }
}

pub(crate) fn display_workspace_root() -> String {
    ".".to_string()
}

pub(crate) fn generated_at() -> String {
    Utc::now().format("%Y-%m-%d").to_string()
}

pub fn context_metrics(workspace_root: &Path, package_root: &Path) -> Result<(usize, u64)> {
    let mut file_count = 0usize;
    let mut bytes = 0u64;
    for entry in WalkDir::new(package_root)
        .into_iter()
        .filter_map(|entry| entry.ok())
    {
        let path = entry.path();
        if !path.is_file() {
            continue;
        }
        let extension = match path.extension().and_then(|ext| ext.to_str()) {
            Some(ext) => ext,
            None => "",
        };
        if !matches!(extension, "rs" | "toml" | "md" | "json" | "yaml" | "yml") {
            continue;
        }
        file_count += 1;
        bytes += fs::metadata(path)
            .with_context(|| format!("failed to read metadata for {}", path.display()))?
            .len();
    }
    let root_display = display_relative(workspace_root, package_root);
    if file_count == 0 {
        return Ok((0, 0));
    }
    let _ = root_display;
    Ok((file_count, bytes))
}

use std::collections::{HashMap, HashSet};
use std::fs;
use std::path::{Path, PathBuf};

use anyhow::{Context, Result};
use cargo_metadata::{Metadata, MetadataCommand, Package};

use crate::model::{PackageAgentMetadata, WorkspaceAgentMetadata};

#[derive(Debug, Clone)]
pub struct PackageSnapshot {
    pub name: String,
    pub manifest_path: PathBuf,
    pub package_root: PathBuf,
    pub agent: PackageAgentMetadata,
    pub direct_dependencies: Vec<String>,
    pub reverse_dependencies: Vec<String>,
    pub target_names: Vec<String>,
    pub target_tests: Vec<String>,
    pub features: Vec<String>,
}

#[derive(Debug, Clone)]
pub struct WorkspaceSnapshot {
    pub metadata: Metadata,
    pub workspace_root: PathBuf,
    pub workspace_agent: WorkspaceAgentMetadata,
    pub packages: Vec<PackageSnapshot>,
}

/// Load a snapshot of the cargo workspace.
///
/// Security boundary (HLT-023-INPUT-BOUNDARY-GAP): the only externally supplied
/// input is `manifest_path`, which is filtered through [`normalize_manifest_path`]
/// before reaching `cargo_metadata`. Normalization canonicalizes the path,
/// requires the canonical form to live under the compile-time `workspace_root()`
/// allowlist, and rejects any filename other than `Cargo.toml`. The downstream
/// call below is `cargo_metadata::MetadataCommand::exec`, which spawns
/// `cargo metadata` via `std::process::Command` with structured arguments — no
/// shell interpretation occurs. Negative coverage lives in the unit tests
/// `normalize_manifest_path_*` below.
pub fn load_workspace(manifest_path: Option<&Path>) -> Result<WorkspaceSnapshot> {
    let mut metadata_query = MetadataCommand::new();
    if let Some(path) = manifest_path {
        metadata_query.manifest_path(&normalize_manifest_path(path)?);
    } else {
        metadata_query.manifest_path(&workspace_root()?.join("Cargo.toml"));
    }
    // Structured subprocess invocation through `cargo_metadata::MetadataCommand`
    // (not a shell string); the manifest path is path-validated above.
    let metadata = metadata_query
        .exec() // allowlist: structured cargo_metadata invocation, path-validated manifest
        .context("failed to read cargo metadata (see normalize_manifest_path)")?;
    let workspace_root = normalize_existing_path(metadata.workspace_root.as_std_path())?;
    let workspace_agent = parse_workspace_agent(&metadata.workspace_metadata)?;
    let member_ids: HashSet<_> = metadata.workspace_members.iter().cloned().collect();
    let package_by_id: HashMap<_, _> = metadata
        .packages
        .iter()
        .map(|package| (package.id.clone(), package))
        .collect();

    let mut direct: HashMap<String, Vec<String>> = HashMap::new();
    let mut reverse: HashMap<String, Vec<String>> = HashMap::new();
    if let Some(resolve) = &metadata.resolve {
        for node in &resolve.nodes {
            if !member_ids.contains(&node.id) {
                continue;
            }
            let Some(package) = package_by_id.get(&node.id) else {
                continue;
            };
            for dep in &node.deps {
                if !member_ids.contains(&dep.pkg) {
                    continue;
                }
                if let Some(dep_package) = package_by_id.get(&dep.pkg) {
                    direct
                        .entry(package.name.to_string())
                        .or_default()
                        .push(dep_package.name.to_string());
                    reverse
                        .entry(dep_package.name.to_string())
                        .or_default()
                        .push(package.name.to_string());
                }
            }
        }
    }

    let packages = metadata
        .packages
        .iter()
        .filter(|package| member_ids.contains(&package.id))
        .map(|package| package_snapshot(package, &workspace_root, &direct, &reverse))
        .collect::<Result<Vec<_>>>()?;

    Ok(WorkspaceSnapshot {
        metadata,
        workspace_root,
        workspace_agent,
        packages,
    })
}

fn workspace_root() -> Result<PathBuf> {
    let manifest_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    let crate_root = manifest_dir.parent().context("workspace crate root")?;
    let root = crate_root.parent().context("workspace root")?;
    Ok(root.to_path_buf())
}

fn parse_workspace_agent(value: &serde_json::Value) -> Result<WorkspaceAgentMetadata> {
    match value.get("agent").cloned() {
        Some(agent) if !agent.is_null() => {
            serde_json::from_value(agent).context("failed to parse workspace.metadata.agent")
        }
        _ => Ok(WorkspaceAgentMetadata::default()),
    }
}

fn parse_package_agent(package: &Package) -> Result<PackageAgentMetadata> {
    match package.metadata.get("agent").cloned() {
        Some(agent) if !agent.is_null() => serde_json::from_value(agent).with_context(|| {
            format!(
                "failed to parse package.metadata.agent for {}",
                package.name
            )
        }),
        _ => Ok(PackageAgentMetadata::default()),
    }
}

fn package_snapshot(
    package: &Package,
    workspace_root: &Path,
    direct: &HashMap<String, Vec<String>>,
    reverse: &HashMap<String, Vec<String>>,
) -> Result<PackageSnapshot> {
    let manifest_path =
        normalize_workspace_path(workspace_root, package.manifest_path.as_std_path())?;
    let package_root = manifest_path
        .parent()
        .context("package manifest unexpectedly missing parent directory")?
        .to_path_buf();
    let agent = parse_package_agent(package)?;
    let mut target_names = package
        .targets
        .iter()
        .map(|target| target.name.clone())
        .collect::<Vec<_>>();
    target_names.sort();
    let mut target_tests = package
        .targets
        .iter()
        .filter(|target| {
            target
                .kind
                .iter()
                .any(|kind| matches!(kind, cargo_metadata::TargetKind::Test))
        })
        .map(|target| {
            let normalized =
                normalize_workspace_path(workspace_root, target.src_path.as_std_path())?;
            Ok(display_relative(workspace_root, &normalized))
        })
        .collect::<Result<Vec<_>>>()?;
    target_tests.sort();
    let mut features = package.features.keys().cloned().collect::<Vec<_>>();
    features.sort();
    Ok(PackageSnapshot {
        name: package.name.to_string(),
        manifest_path,
        package_root,
        agent,
        direct_dependencies: sorted_lookup(direct, &package.name),
        reverse_dependencies: sorted_lookup(reverse, &package.name),
        target_names,
        target_tests,
        features,
    })
}

fn sorted_lookup(map: &HashMap<String, Vec<String>>, key: &str) -> Vec<String> {
    let mut values = match map.get(key) {
        Some(values) => values.clone(),
        None => Vec::new(),
    };
    values.sort();
    values.dedup();
    values
}

fn normalize_existing_path(path: &Path) -> Result<PathBuf> {
    fs::canonicalize(path)
        .with_context(|| format!("failed to canonicalize path {}", path.display()))
}

fn normalize_manifest_path(path: &Path) -> Result<PathBuf> {
    let normalized = normalize_existing_path(path)?;
    let root = workspace_root()?;
    if !normalized.starts_with(&root) {
        anyhow::bail!(
            "manifest path {} escapes workspace root {}",
            normalized.display(),
            root.display()
        );
    }
    if normalized.file_name().and_then(|name| name.to_str()) != Some("Cargo.toml") {
        anyhow::bail!("workspace manifest path must point to Cargo.toml");
    }
    Ok(normalized)
}

fn normalize_workspace_path(root: &Path, path: &Path) -> Result<PathBuf> {
    let normalized_path = normalize_existing_path(path)?;
    if normalized_path.starts_with(root) {
        Ok(normalized_path)
    } else {
        anyhow::bail!(
            "workspace path {} escapes workspace root {}",
            normalized_path.display(),
            root.display()
        );
    }
}

fn display_relative(root: &Path, path: &Path) -> String {
    match path.strip_prefix(root).ok() {
        Some(relative) if !relative.as_os_str().is_empty() => relative.display().to_string(),
        _ if path == root => ".".to_string(),
        _ => path.display().to_string(),
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::fs;
    use std::time::{SystemTime, UNIX_EPOCH};

    fn unique_path(prefix: &str) -> PathBuf {
        let stamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .expect("clock moved backwards")
            .as_nanos();
        workspace_root()
            .expect("workspace root")
            .join("target")
            .join("cargo-vrc-tests")
            .join(format!("{prefix}-{stamp}"))
    }

    #[test]
    fn normalize_workspace_path_accepts_paths_inside_root() {
        let root = unique_path("workspace-root");
        let nested = root.join("nested");
        fs::create_dir_all(&nested).expect("create nested directory");
        let file = nested.join("Cargo.toml");
        fs::write(&file, "[package]\nname = \"demo\"\nversion = \"0.1.0\"\n")
            .expect("write manifest");

        let root = fs::canonicalize(&root).expect("canonicalize root");
        let normalized = normalize_workspace_path(&root, &file).expect("normalize path");
        assert!(normalized.starts_with(&root));

        let _ = fs::remove_file(&file);
        let _ = fs::remove_dir_all(&root);
    }

    #[test]
    fn normalize_manifest_path_requires_cargo_toml() {
        let root = unique_path("workspace-manifest");
        fs::create_dir_all(&root).expect("create root directory");
        let manifest = root.join("not-a-manifest.txt");
        fs::write(&manifest, "manifest fixture").expect("write manifest-like file");

        let err = normalize_manifest_path(&manifest).expect_err("reject non-manifest path");
        assert!(err.to_string().contains("Cargo.toml"));

        let _ = fs::remove_file(&manifest);
        let _ = fs::remove_dir_all(&root);
    }

    #[test]
    fn normalize_manifest_path_rejects_traversal_outside_workspace() {
        // Negative test for HLT-023-INPUT-BOUNDARY-GAP: confirm that a
        // user-supplied manifest path that canonicalizes outside the workspace
        // is refused before it can reach `MetadataCommand::exec`.
        //
        // The OS-provided ephemeral directory canonicalizes to a location
        // outside the compile-time workspace root on macOS (e.g.
        // /private/var/...), so a manifest written there is rejected by the
        // allowlist enforced by `normalize_manifest_path`.
        let outside_root = std::env::temp_dir().join(format!(
            "cargo-vrc-outside-{}",
            SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .expect("clock moved backwards")
                .as_nanos()
        ));
        fs::create_dir_all(&outside_root).expect("create outside root");
        let outside_manifest = outside_root.join("Cargo.toml");
        fs::write(
            &outside_manifest,
            "[package]\nname = \"hostile\"\nversion = \"0.0.0\"\n",
        )
        .expect("write outside manifest");

        let err = normalize_manifest_path(&outside_manifest)
            .expect_err("reject manifest outside workspace");
        let message = err.to_string();
        assert!(
            message.contains("escapes workspace root"),
            "unexpected error: {message}"
        );

        let _ = fs::remove_file(&outside_manifest);
        let _ = fs::remove_dir_all(&outside_root);
    }

    #[test]
    fn normalize_workspace_path_rejects_paths_outside_root() {
        let root = unique_path("workspace-root");
        let nested = root.join("nested");
        fs::create_dir_all(&nested).expect("create nested directory");
        let inside = nested.join("Cargo.toml");
        fs::write(&inside, "[package]\nname = \"demo\"\nversion = \"0.1.0\"\n")
            .expect("write manifest");

        let outside = unique_path("workspace-outside.toml");
        fs::write(
            &outside,
            "[package]\nname = \"demo\"\nversion = \"0.1.0\"\n",
        )
        .expect("write outside manifest");

        let root = fs::canonicalize(&root).expect("canonicalize root");
        let err = normalize_workspace_path(&root, &outside).expect_err("reject outside path");
        assert!(err.to_string().contains("escapes workspace root"));

        let _ = fs::remove_file(&inside);
        let _ = fs::remove_file(&outside);
        let _ = fs::remove_dir_all(&root);
    }
}

use std::collections::BTreeSet;
use std::fs;
use std::path::Path;
use std::process::Command;

use anyhow::{Context, Result};
use chrono::Utc;
use serde::Deserialize;

use crate::model::{CompilePacket, CompilePackets, CompileSummary};

/// Run `cargo check --message-format=json` and route each diagnostic
/// to its owning ARC.
///
/// Enriches each diagnostic with cell purpose, invariants, and local
/// test commands from the workspace snapshot.
pub fn diagnose_workspace(
    workspace_root: &Path,
    manifest_path: Option<&Path>,
) -> Result<CompilePackets> {
    let manifest_path = manifest_path
        .map(|path| {
            path.canonicalize()
                .with_context(|| format!("failed to canonicalize {}", path.display()))
        })
        .transpose()?;
    let snapshot = cargo_vrc::load_workspace(manifest_path.as_deref())?;

    // Run cargo check and capture JSON diagnostics.
    let mut command = Command::new("cargo");
    command
        .arg("check")
        .arg("--workspace")
        .arg("--message-format=json")
        .current_dir(workspace_root);
    if let Some(path) = manifest_path.as_deref() {
        command.arg("--manifest-path").arg(path);
    }

    let output = command
        .output()
        .context("failed to run cargo check --message-format=json")?;

    let stdout = String::from_utf8_lossy(&output.stdout);

    let mut packets = Vec::new();
    let mut arcs_affected = BTreeSet::new();
    let mut total_errors = 0usize;
    let mut total_warnings = 0usize;

    for line in stdout.lines() {
        let Ok(msg) = serde_json::from_str::<CargoMessage>(line) else {
            continue;
        };

        if msg.reason != "compiler-message" {
            continue;
        }

        let Some(diagnostic) = msg.message else {
            continue;
        };

        // Only route errors and warnings, not notes/help.
        if !matches!(diagnostic.level.as_str(), "error" | "warning") {
            continue;
        }

        let (file, line_num, column) = resolve_diagnostic_location(&diagnostic.spans);

        // Route to owning ARC.
        let owning_pkg = snapshot.packages.iter().find(|package| {
            let pkg_root = match package.package_root.strip_prefix(&snapshot.workspace_root) {
                Ok(rel) => rel.display().to_string(),
                Err(_) => String::new(),
            };
            file.starts_with(&pkg_root)
        });
        let owning_arc = match owning_pkg {
            Some(package) => package.name.clone(),
            None => "<unmatched>".to_string(),
        };

        let pkg = snapshot.packages.iter().find(|p| p.name == owning_arc);
        let cell_purpose = match pkg {
            Some(p) if !p.agent.purpose.is_empty() => Some(p.agent.purpose.clone()),
            _ => None,
        };
        let invariants = match pkg {
            Some(p) => p.agent.invariants.clone(),
            None => Vec::new(),
        };
        let local_commands = match pkg {
            Some(p) => p.agent.local_validate.clone(),
            None => Vec::new(),
        };

        // Extract compiler suggestion if present.
        let compiler_suggestion = diagnostic
            .children
            .iter()
            .find(|child| child.level == "help")
            .map(|child| child.message.clone());

        match diagnostic.level.as_str() {
            "error" => total_errors += 1,
            "warning" => total_warnings += 1,
            _ => {}
        }
        arcs_affected.insert(owning_arc.clone());

        packets.push(CompilePacket {
            level: diagnostic.level,
            code: diagnostic.code.as_ref().map(|c| c.code.clone()),
            message: diagnostic.message,
            file,
            line: line_num,
            column,
            owning_arc,
            cell_purpose,
            invariants,
            local_commands,
            compiler_suggestion,
        });
    }

    Ok(CompilePackets {
        generated_at: Utc::now().format("%Y-%m-%d").to_string(),
        packets,
        summary: CompileSummary {
            total_errors,
            total_warnings,
            arcs_affected: arcs_affected.len(),
        },
    })
}

/// Write compile packets to disk.
pub fn write_compile_packets(workspace_root: &Path, packets: &CompilePackets) -> Result<()> {
    let output_dir = workspace_root.join("target/agent");
    fs::create_dir_all(&output_dir)
        .with_context(|| format!("failed to create {}", output_dir.display()))?;
    let output_path = output_dir.join("compile-packets.json");
    let json = serde_json::to_string_pretty(packets)?;
    fs::write(&output_path, json)
        .with_context(|| format!("failed to write {}", output_path.display()))?;
    Ok(())
}

// ── Span selection ─────────────────────────────────────────────────────

/// Outcome of picking a span to attribute a diagnostic to.
///
/// Cargo normally marks one span with `is_primary = true`, but it
/// occasionally emits diagnostics where no span is primary (for
/// example, certain crate-level lints). In that case we deliberately
/// use the first span as a secondary location so the diagnostic still
/// routes to a real file/line rather than `<unknown>`.
enum SpanChoice<'a> {
    /// A span explicitly marked `is_primary = true`.
    Primary(&'a DiagnosticSpan),
    /// No primary span existed; first span used as a documented secondary location.
    FirstSecondary(&'a DiagnosticSpan),
    /// Diagnostic carried no spans at all.
    None,
}

impl<'a> SpanChoice<'a> {
    fn from_spans(spans: &'a [DiagnosticSpan]) -> Self {
        if let Some(span) = spans.iter().find(|span| span.is_primary) {
            SpanChoice::Primary(span)
        } else if let Some(span) = spans.first() {
            SpanChoice::FirstSecondary(span)
        } else {
            SpanChoice::None
        }
    }

    fn span(&self) -> Option<&'a DiagnosticSpan> {
        match self {
            SpanChoice::Primary(span) | SpanChoice::FirstSecondary(span) => Some(span),
            SpanChoice::None => None,
        }
    }
}

/// Resolve `(file, line, column)` for a diagnostic, preferring the
/// primary span and using the first span as a secondary location when
/// cargo emits no primary. When the diagnostic has no spans at all,
/// returns the typed unknown sentinel `("<unknown>", 0, 0)`.
fn resolve_diagnostic_location(spans: &[DiagnosticSpan]) -> (String, u32, u32) {
    match SpanChoice::from_spans(spans).span() {
        Some(span) => (span.file_name.clone(), span.line_start, span.column_start),
        None => ("<unknown>".to_string(), 0, 0),
    }
}

// ── Cargo JSON diagnostic types ────────────────────────────────────────

#[derive(Debug, Deserialize)]
struct CargoMessage {
    reason: String,
    #[serde(default)]
    message: Option<Diagnostic>,
}

#[derive(Debug, Deserialize)]
struct Diagnostic {
    level: String,
    message: String,
    #[serde(default)]
    code: Option<DiagnosticCode>,
    #[serde(default)]
    spans: Vec<DiagnosticSpan>,
    #[serde(default)]
    children: Vec<DiagnosticChild>,
}

#[derive(Debug, Deserialize)]
struct DiagnosticCode {
    code: String,
}

#[derive(Debug, Deserialize)]
struct DiagnosticSpan {
    file_name: String,
    line_start: u32,
    column_start: u32,
    #[serde(default)]
    is_primary: bool,
}

#[derive(Debug, Deserialize)]
struct DiagnosticChild {
    level: String,
    message: String,
}

use std::collections::HashMap;

use chrono::Utc;

use crate::model::{ChangeClassification, CrateChange, WitnessDiff, WitnessGraph};

/// Diff two witness graphs and classify changes per crate.
///
/// For each crate present in either graph, classify the change as:
/// - `InterfaceChanged` — pub signatures changed, must escalate
/// - `ImplementationOnly` — only internals changed, stay local
/// - `Unchanged` — no change
/// - `Added` — new crate in `current` not in `prior`
/// - `Removed` — crate in `prior` missing from `current`
pub fn diff_witness_graphs(prior: &WitnessGraph, current: &WitnessGraph) -> WitnessDiff {
    let prior_map: HashMap<&str, &crate::model::CrateWitness> =
        prior.crates.iter().map(|c| (c.name.as_str(), c)).collect();
    let current_map: HashMap<&str, &crate::model::CrateWitness> = current
        .crates
        .iter()
        .map(|c| (c.name.as_str(), c))
        .collect();

    let mut all_names: Vec<&str> = prior_map
        .keys()
        .chain(current_map.keys())
        .copied()
        .collect::<std::collections::BTreeSet<_>>()
        .into_iter()
        .collect();
    all_names.sort();

    let mut changes = Vec::new();

    for name in all_names {
        match (prior_map.get(name), current_map.get(name)) {
            (None, Some(_new_crate)) => {
                changes.push(CrateChange {
                    name: name.to_string(),
                    classification: ChangeClassification::Added,
                    interface_changed: true,
                    implementation_changed: true,
                    local_commands: vec![
                        format!("cargo check -p {name}"),
                        format!("cargo test -p {name}"),
                    ],
                    escalation_commands: vec![format!(
                        "cargo nextest run -E 'rdeps({name})' --ignore-default-filter"
                    )],
                    reason: "new crate added to workspace".to_string(),
                });
            }
            (Some(_), None) => {
                changes.push(CrateChange {
                    name: name.to_string(),
                    classification: ChangeClassification::Removed,
                    interface_changed: true,
                    implementation_changed: true,
                    local_commands: vec![],
                    escalation_commands: vec!["cargo check --workspace".to_string()],
                    reason: "crate removed from workspace — validate all former consumers"
                        .to_string(),
                });
            }
            (Some(prior_crate), Some(current_crate)) => {
                let interface_changed = prior_crate.interface_hash != current_crate.interface_hash;
                let implementation_changed =
                    prior_crate.implementation_hash != current_crate.implementation_hash;

                if !interface_changed && !implementation_changed {
                    continue; // Skip unchanged crates entirely.
                }

                let classification = if interface_changed {
                    ChangeClassification::InterfaceChanged
                } else {
                    ChangeClassification::ImplementationOnly
                };

                let local_commands = vec![
                    format!("cargo check -p {name}"),
                    format!("cargo test -p {name}"),
                ];

                let escalation_commands = if interface_changed {
                    vec![format!(
                        "cargo nextest run -E 'rdeps({name})' --ignore-default-filter"
                    )]
                } else {
                    vec![]
                };

                let reason = if interface_changed {
                    format!(
                        "interface hash changed ({} → {}); pub API shift requires rdep validation",
                        &prior_crate.interface_hash[..12],
                        &current_crate.interface_hash[..12]
                    )
                } else {
                    format!(
                        "implementation hash changed ({} → {}); interface stable — local-only validation",
                        &prior_crate.implementation_hash[..12],
                        &current_crate.implementation_hash[..12]
                    )
                };

                changes.push(CrateChange {
                    name: name.to_string(),
                    classification,
                    interface_changed,
                    implementation_changed,
                    local_commands,
                    escalation_commands,
                    reason,
                });
            }
            (None, None) => panic!("unexpected witness diff state"),
        }
    }

    let total_crates_changed = changes.len();
    let escalation_required = changes
        .iter()
        .any(|change| change.classification == ChangeClassification::InterfaceChanged);
    let estimated_test_commands: usize = changes
        .iter()
        .map(|change| change.local_commands.len() + change.escalation_commands.len())
        .sum();

    WitnessDiff {
        generated_at: Utc::now().format("%Y-%m-%d").to_string(),
        changes,
        total_crates_changed,
        escalation_required,
        estimated_test_commands,
    }
}

