                data: Vec<u8>,
            }
        "#;
        let items = extract_pub_items("test.rs", source);
        assert_eq!(items.len(), 1);
        assert_eq!(items[0].kind, "struct");
        assert_eq!(items[0].name, "Config");
    }

    #[test]
    fn extract_pub_enum() {
        let source = r#"
            pub enum Status {
                Active,
                Inactive,
                Pending,
            }
        "#;
        let items = extract_pub_items("test.rs", source);
        assert_eq!(items.len(), 1);
        assert_eq!(items[0].kind, "enum");
        assert_eq!(items[0].name, "Status");
        assert!(items[0].signature.contains("3 variants"));
    }

    #[test]
    fn extract_pub_trait() {
        let source = r#"
            pub trait Handler {
                fn handle(&self, request: &Request) -> Response;
                fn name(&self) -> &str;
            }
        "#;
        let items = extract_pub_items("test.rs", source);
        assert_eq!(items.len(), 1);
        assert_eq!(items[0].kind, "trait");
        assert_eq!(items[0].name, "Handler");
        assert!(items[0].signature.contains("2 methods"));
    }

    #[test]
    fn extract_impl_pub_methods() {
        let source = r#"
            pub struct Foo;

            impl Foo {
                pub fn bar(&self) -> i32 { 42 }
                fn private(&self) {}
            }
        "#;
        let items = extract_pub_items("test.rs", source);
        assert_eq!(items.len(), 2);
        let fn_items: Vec<_> = items.iter().filter(|i| i.kind == "fn").collect();
        assert_eq!(fn_items.len(), 1);
        assert_eq!(fn_items[0].name, "bar");
    }

    #[test]
    fn private_items_excluded() {
        let source = r#"
            fn private_fn() -> bool { true }
            struct PrivateStruct { x: i32 }
            enum PrivateEnum { A, B }
        "#;
        let items = extract_pub_items("test.rs", source);
        assert!(items.is_empty());
    }

    #[test]
    fn deterministic_ordering() {
        let source = r#"
            pub fn zebra() {}
            pub fn alpha() {}
            pub struct Middle;
        "#;
        let items = extract_pub_items("test.rs", source);
        assert_eq!(items.len(), 3);
        assert_eq!(items[0].name, "alpha");
        assert_eq!(items[1].name, "zebra");
        assert_eq!(items[2].name, "Middle");
    }
}

//! # cargo-witness
//!
//! Witness graph and repair routing for agent-native Rust workspaces.
//!
//! This crate provides four capabilities:
//!
//! 1. **Build** — generates a witness graph with dual hashes (interface vs implementation)
//! 2. **Diff** — classifies changes between two witness graphs
//! 3. **Diagnose** — routes compile errors to owning ARCs with enriched context
//! 4. **Repair** — assembles minimal repair bundles from failure packets

pub mod diagnose;
pub mod diff;
pub mod graph;
pub mod model;
pub mod repair;

use std::path::PathBuf;

use anyhow::{Context, Result};
use clap::{Parser, Subcommand};

#[derive(Parser)]
#[command(name = "cargo-witness", bin_name = "cargo")]
#[command(about = "Witness graph and repair routing for agent-native Rust workspaces")]
struct Cli {
    #[command(subcommand)]
    command: TopLevelCommand,
}

#[derive(Subcommand)]
enum TopLevelCommand {
    /// Compatibility wrapper for `cargo witness <subcommand>`.
    Witness {
        #[command(subcommand)]
        command: Command,
    },
    /// Build the witness graph (`.witness/witness-graph.json`).
    Build {
        /// Path to Cargo.toml (defaults to workspace root).
        #[arg(long)]
        manifest_path: Option<PathBuf>,
    },
    /// Diff two witness graphs and classify changes.
    Diff {
        /// Path to the prior witness graph JSON.
        prior: PathBuf,
        /// Path to the current witness graph JSON.
        new: PathBuf,
    },
    /// Route compile diagnostics to owning ARCs.
    Diagnose {
        /// Path to Cargo.toml (defaults to workspace root).
        #[arg(long)]
        manifest_path: Option<PathBuf>,
    },
    /// Assemble a minimal repair bundle from the latest failure.
    Repair {
        /// Path to Cargo.toml (defaults to workspace root).
        #[arg(long)]
        manifest_path: Option<PathBuf>,
    },
}

#[derive(Subcommand)]
enum Command {
    /// Build the witness graph (`.witness/witness-graph.json`).
    ///
    /// Parses all pub items from workspace crates via `syn` and computes
    /// dual hashes: interface (pub signatures) and implementation (everything else).
    Build {
        /// Path to Cargo.toml (defaults to workspace root).
        #[arg(long)]
        manifest_path: Option<PathBuf>,
    },

    /// Diff two witness graphs and classify changes.
    ///
    /// For each crate, outputs: interface-changed, implementation-only,
    /// added, removed, or unchanged.
    Diff {
        /// Path to the prior witness graph JSON.
        prior: PathBuf,
        /// Path to the current witness graph JSON.
        new: PathBuf,
    },

    /// Route compile diagnostics to owning ARCs.
    ///
    /// Runs `cargo check --message-format=json` and maps each error/warning
    /// to its owning ARC with enriched context (purpose, invariants, commands).
    Diagnose {
        /// Path to Cargo.toml (defaults to workspace root).
        #[arg(long)]
        manifest_path: Option<PathBuf>,
    },

    /// Assemble a minimal repair bundle from the latest failure.
    ///
    /// Reads `target/agent/compile-packets.json` or `target/agent/last-failure.json`
    /// and merges with the witness graph to produce the smallest context an agent needs.
    Repair {
        /// Path to Cargo.toml (defaults to workspace root).
        #[arg(long)]
        manifest_path: Option<PathBuf>,
    },
}

fn main() {
    if let Err(error) = run() {
        eprintln!("cargo-witness error: {error:#}");
        std::process::exit(1);
    }
}

fn run() -> Result<()> {
    let cli = Cli::parse();
    match cli.command {
        TopLevelCommand::Witness { command } => dispatch(command),
        TopLevelCommand::Build { manifest_path } => dispatch(Command::Build { manifest_path }),
        TopLevelCommand::Diff { prior, new } => dispatch(Command::Diff { prior, new }),
        TopLevelCommand::Diagnose { manifest_path } => {
            dispatch(Command::Diagnose { manifest_path })
        }
        TopLevelCommand::Repair { manifest_path } => dispatch(Command::Repair { manifest_path }),
    }
}

fn dispatch(command: Command) -> Result<()> {
    match command {
        Command::Build { manifest_path } => {
            let workspace_root = resolve_workspace_root(manifest_path.as_deref())?;
            let graph = cargo_witness::graph::build_witness_graph(
                &workspace_root,
                manifest_path.as_deref(),
            )?;
            cargo_witness::graph::write_witness_graph(&workspace_root, &graph)?;
            let crate_count = graph.crates.len();
            let pub_items: usize = graph.crates.iter().map(|c| c.pub_items.len()).sum();
            println!(
                "witness-graph.json written: {crate_count} crates, {pub_items} pub items indexed"
            );
            Ok(())
        }

        Command::Diff { prior, new } => {
            let prior_content = std::fs::read_to_string(&prior)
                .with_context(|| format!("failed to read {}", prior.display()))?;
            let prior_graph: cargo_witness::model::WitnessGraph =
                serde_json::from_str(&prior_content)
                    .with_context(|| format!("failed to parse {}", prior.display()))?;

            let new_content = std::fs::read_to_string(&new)
                .with_context(|| format!("failed to read {}", new.display()))?;
            let new_graph: cargo_witness::model::WitnessGraph = serde_json::from_str(&new_content)
                .with_context(|| format!("failed to parse {}", new.display()))?;

            let diff = cargo_witness::diff::diff_witness_graphs(&prior_graph, &new_graph);
            println!("{}", serde_json::to_string_pretty(&diff)?);
            Ok(())
        }

        Command::Diagnose { manifest_path } => {
            let workspace_root = resolve_workspace_root(manifest_path.as_deref())?;
            let packets = cargo_witness::diagnose::diagnose_workspace(
                &workspace_root,
                manifest_path.as_deref(),
            )?;
            cargo_witness::diagnose::write_compile_packets(&workspace_root, &packets)?;
            let errors = packets.summary.total_errors;
            let warnings = packets.summary.total_warnings;
            let arcs = packets.summary.arcs_affected;
            if errors > 0 {
                println!(
                    "compile-packets.json written: {errors} errors, {warnings} warnings across {arcs} ARCs"
                );
            } else {
                println!("workspace compiles cleanly — no diagnostics to route");
            }
            Ok(())
        }

        Command::Repair { manifest_path } => {
            let workspace_root = resolve_workspace_root(manifest_path.as_deref())?;
            let bundle = cargo_witness::repair::build_repair_bundle(&workspace_root)?;
            cargo_witness::repair::write_repair_bundle(&workspace_root, &bundle)?;
            println!("{}", serde_json::to_string_pretty(&bundle)?);
            Ok(())
        }
    }
}

/// Resolve the workspace root from a manifest path or the current directory.
fn resolve_workspace_root(manifest_path: Option<&std::path::Path>) -> Result<PathBuf> {
    if let Some(path) = manifest_path {
        let path = path
            .canonicalize()
            .with_context(|| format!("failed to canonicalize {}", path.display()))?;
        Ok(path
            .parent()
            .context("manifest path has no parent")?
            .to_path_buf())
    } else {
        let metadata_query = cargo_metadata::MetadataCommand::new();
        #[rustfmt::skip]
        let metadata = metadata_query.exec().context("failed to read cargo metadata via the workspace allowlist")?;
        Ok(metadata.workspace_root.as_std_path().to_path_buf())
    }
}

use serde::{Deserialize, Serialize};

// ── Witness Graph ──────────────────────────────────────────────────────

/// A complete witness graph for a Cargo workspace.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WitnessGraph {
    pub generated_at: String,
    pub workspace_root: String,
    pub crates: Vec<CrateWitness>,
}

/// Per-crate witness data including dual hashes and pub-item inventory.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CrateWitness {
    /// Crate name (from `Cargo.toml`).
    pub name: String,

    /// SHA-256 of all `pub` item signatures, sorted deterministically.
    pub interface_hash: String,

    /// SHA-256 of all non-pub source content.
    pub implementation_hash: String,

    /// Inventory of public items with their signatures.
    #[serde(default)]
    pub pub_items: Vec<PubItem>,

    /// Direct workspace dependencies.
    #[serde(default)]
    pub direct_deps: Vec<String>,

    /// Reverse workspace dependencies (who depends on this crate).
    #[serde(default)]
    pub reverse_deps: Vec<String>,

    /// Number of source files in `src/`.
    pub file_count: usize,

    /// Total lines of Rust source.
    pub total_lines: usize,
}

/// A single public item extracted from source via `syn`.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PubItem {
    /// Kind of item: `"fn"`, `"struct"`, `"enum"`, `"trait"`, `"type"`, `"const"`, `"static"`.
    pub kind: String,

    /// Item name.
    pub name: String,

    /// Full signature as a string (name + generics + args + return type).
    pub signature: String,
}

// ── Diff / Impact Plan ─────────────────────────────────────────────────

/// Result of diffing two witness graphs.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WitnessDiff {
    pub generated_at: String,
    pub changes: Vec<CrateChange>,
    pub total_crates_changed: usize,
    pub escalation_required: bool,
    pub estimated_test_commands: usize,
}

/// Classification of a change to a single crate.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CrateChange {
    pub name: String,
    pub classification: ChangeClassification,
    pub interface_changed: bool,
    pub implementation_changed: bool,
    pub local_commands: Vec<String>,
    pub escalation_commands: Vec<String>,
    pub reason: String,
}

/// Change type classification.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "kebab-case")]
pub enum ChangeClassification {
    /// Public interface changed — must escalate to reverse deps.
    InterfaceChanged,
    /// Only internal implementation changed — stay local.
    ImplementationOnly,
    /// No change detected.
    Unchanged,
    /// New crate added.
    Added,
    /// Crate removed.
    Removed,
}

impl std::fmt::Display for ChangeClassification {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::InterfaceChanged => write!(f, "interface-changed"),
            Self::ImplementationOnly => write!(f, "implementation-only"),
            Self::Unchanged => write!(f, "unchanged"),
            Self::Added => write!(f, "added"),
            Self::Removed => write!(f, "removed"),
        }
    }
}

// ── Compile Diagnostic Packets ─────────────────────────────────────────

/// Collection of compile diagnostic packets routed to their owning ARCs.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CompilePackets {
    pub generated_at: String,
    pub packets: Vec<CompilePacket>,
    pub summary: CompileSummary,
}

/// A single compile diagnostic routed to its owning ARC.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CompilePacket {
    pub level: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub code: Option<String>,
    pub message: String,
    pub file: String,
    pub line: u32,
    pub column: u32,
    pub owning_arc: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub cell_purpose: Option<String>,
    #[serde(default)]
    pub invariants: Vec<String>,
    #[serde(default)]
    pub local_commands: Vec<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub compiler_suggestion: Option<String>,
}

/// Summary of compile diagnostic results.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CompileSummary {
    pub total_errors: usize,
    pub total_warnings: usize,
    pub arcs_affected: usize,
}

// ── Repair Bundle ──────────────────────────────────────────────────────

/// A minimal repair bundle — the smallest context an agent needs to fix an issue.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RepairBundle {
    pub status: String,
    pub failure_type: String,
    pub primary_arc: String,
    pub primary_file: String,
    pub primary_line: u32,
    pub error_summary: String,
    pub repair_context: RepairContext,
    pub validate_after_fix: Vec<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub escalate_if: Option<String>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub notes: Vec<String>,
}

/// Context embedded in a repair bundle.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RepairContext {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub cell_purpose: Option<String>,
    #[serde(default)]
    pub invariants: Vec<String>,
    #[serde(default)]
    pub pub_items_in_scope: Vec<String>,
    #[serde(default)]
    pub likely_causes: Vec<String>,
    #[serde(default)]
    pub hints: Vec<String>,
    #[serde(default)]
    pub files_to_read: Vec<String>,
    pub context_bytes: u64,
}

use std::fs;
use std::path::Path;

use anyhow::{Context, Result};

use crate::graph::load_witness_graph_if_present;
use crate::model::{CompilePackets, RepairBundle, RepairContext};

/// Assemble a minimal repair bundle from the most recent failure source.
///
/// Reads compile packets and/or runtime failure packets, merges with the
/// witness graph for dependency context, and outputs the absolute smallest
/// context an agent needs.
pub fn build_repair_bundle(workspace_root: &Path) -> Result<RepairBundle> {
    let compile_path = workspace_root.join("target/agent/compile-packets.json");
    if compile_path.exists()
        && let Some(bundle) = repair_from_compile_packets(workspace_root, &compile_path)?
    {
        return Ok(bundle);
    }

    let runtime_path = workspace_root.join("target/agent/last-failure.json");
    if runtime_path.exists() {
        return repair_from_runtime_packet(workspace_root, &runtime_path);
    }

    Ok(no_failure_bundle(
        "No compile diagnostics or runtime repair packets are present.",
        vec![
            "Run `cargo run -p cargo-witness -- diagnose` or `cargo run -p cargo-witness -- witness diagnose` after a compile failure.".to_string(),
            "Trigger a runtime failure with `witness-rt` installed to capture `target/agent/last-failure.json`.".to_string(),
        ],
    ))
}

/// Build a repair bundle from compile diagnostic packets.
fn repair_from_compile_packets(
    workspace_root: &Path,
    compile_path: &Path,
) -> Result<Option<RepairBundle>> {
    let content = fs::read_to_string(compile_path)
        .with_context(|| format!("failed to read {}", compile_path.display()))?;
    let packets: CompilePackets = serde_json::from_str(&content)
        .with_context(|| format!("failed to parse {}", compile_path.display()))?;

    // Find the first error (highest priority).
    let primary = match packets.packets.iter().find(|p| p.level == "error") {
        Some(err) => err,
        None => match packets.packets.first() {
            Some(first) => first,
            None => return Ok(None),
        },
    };

    // Check witness graph for pub-item context.
    let witness = load_witness_graph_if_present(workspace_root);
    let pub_items_in_scope = match witness
        .as_ref()
        .and_then(|graph| graph.crates.iter().find(|c| c.name == primary.owning_arc))
    {
        Some(crate_witness) => crate_witness
            .pub_items
            .iter()
            .map(|item| item.signature.clone())
            .collect::<Vec<_>>(),
        None => Vec::new(),
    };

    // Estimate context bytes from the primary file.
    let context_bytes = fs::metadata(workspace_root.join(&primary.file))
        .map(|meta| meta.len())
        .unwrap_or(0);

    Ok(Some(RepairBundle {
        status: "action-required".to_string(),
        failure_type: "compile-error".to_string(),
        primary_arc: primary.owning_arc.clone(),
        primary_file: primary.file.clone(),
        primary_line: primary.line,
        error_summary: primary.message.clone(),
        repair_context: RepairContext {
            cell_purpose: primary.cell_purpose.clone(),
            invariants: primary.invariants.clone(),
            pub_items_in_scope,
            likely_causes: primary.compiler_suggestion.iter().cloned().collect(),
            hints: vec![],
            files_to_read: vec![primary.file.clone()],
            context_bytes,
        },
        validate_after_fix: primary.local_commands.clone(),
        escalate_if: Some("interface hash changes after fix".to_string()),
        notes: vec!["Derived from the highest-priority compile diagnostic packet.".to_string()],
    }))
}

/// Build a repair bundle from a runtime failure (panic hook) packet.
fn repair_from_runtime_packet(workspace_root: &Path, runtime_path: &Path) -> Result<RepairBundle> {
    let content = fs::read_to_string(runtime_path)
        .with_context(|| format!("failed to read {}", runtime_path.display()))?;
    let packet: witness_rt::RepairPacket = serde_json::from_str(&content)
        .with_context(|| format!("failed to parse {}", runtime_path.display()))?;

    let witness = load_witness_graph_if_present(workspace_root);
    let pub_items_in_scope = match &packet.cell {
        Some(cell) => match witness
            .as_ref()
            .and_then(|graph| graph.crates.iter().find(|c| &c.name == cell))
        {
            Some(crate_witness) => crate_witness
                .pub_items
                .iter()
                .map(|item| item.signature.clone())
                .collect::<Vec<_>>(),
            None => Vec::new(),
        },
        None => Vec::new(),
    };

    let context_bytes = fs::metadata(workspace_root.join(&packet.file))
        .map(|meta| meta.len())
        .unwrap_or(0);

    Ok(RepairBundle {
        status: "action-required".to_string(),
        failure_type: "runtime-panic".to_string(),
        primary_arc: match packet.cell.clone() {
            Some(cell) => cell,
            None => "<unmatched>".into(),
        },
        primary_file: packet.file.clone(),
        primary_line: packet.line,
        error_summary: format!("[{}] {}", packet.code, packet.message),
        repair_context: RepairContext {
            cell_purpose: packet.cell_purpose.clone(),
            invariants: packet.invariants.clone(),
            pub_items_in_scope,
            likely_causes: packet.likely_causes.clone(),
            hints: packet.hints.clone(),
            files_to_read: vec![packet.file.clone()],
            context_bytes,
        },
        validate_after_fix: packet.local_commands.clone(),
        escalate_if: Some("interface hash changes after fix".to_string()),
        notes: packet
            .match_provenance
            .iter()
            .map(|provenance| format!("Runtime packet matched via {provenance}."))
            .collect(),
    })
}

fn no_failure_bundle(summary: &str, notes: Vec<String>) -> RepairBundle {
    RepairBundle {
        status: "no-failure".to_string(),
        failure_type: "no-failure".to_string(),
        primary_arc: "<none>".to_string(),
        primary_file: String::new(),
        primary_line: 0,
        error_summary: summary.to_string(),
        repair_context: RepairContext {
            cell_purpose: None,
            invariants: Vec::new(),
            pub_items_in_scope: Vec::new(),
            likely_causes: Vec::new(),
            hints: Vec::new(),
            files_to_read: Vec::new(),
            context_bytes: 0,
        },
        validate_after_fix: Vec::new(),
        escalate_if: None,
        notes,
    }
}

/// Write a repair bundle to disk as JSON.
pub fn write_repair_bundle(workspace_root: &Path, bundle: &RepairBundle) -> Result<()> {
    let output_dir = workspace_root.join("target/agent");
    fs::create_dir_all(&output_dir)
        .with_context(|| format!("failed to create {}", output_dir.display()))?;
    let output_path = output_dir.join("repair-bundle.json");
    let json = serde_json::to_string_pretty(bundle)?;
    fs::write(&output_path, json)
        .with_context(|| format!("failed to write {}", output_path.display()))?;
    Ok(())
}

#[cfg(test)]
mod tests {
    use std::path::PathBuf;

    use super::*;

    fn temp_dir(name: &str) -> PathBuf {
        let path = std::env::temp_dir().join(format!(
            "how_to_code_rust-{name}-{}",
            match std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH) {
                Ok(elapsed) => elapsed.as_nanos(),
                Err(_) => 0,
            }
        ));
        fs::create_dir_all(&path).expect("create scratch dir");
        path
    }

    #[test]
    fn repair_bundle_is_noop_when_no_packets_exist() {
        let root = temp_dir("repair-noop");
        let bundle = build_repair_bundle(&root).expect("build repair bundle");
        assert_eq!(bundle.status, "no-failure");
        assert_eq!(bundle.failure_type, "no-failure");
        assert!(
            bundle
                .notes
                .iter()
                .any(|note| note.contains("compile failure"))
        );
    }

    #[test]
    fn repair_bundle_skips_empty_compile_packets() {
        let root = temp_dir("repair-empty-compile");
        let agent_dir = root.join("target/agent");
        fs::create_dir_all(&agent_dir).expect("create agent dir");
        fs::write(
            agent_dir.join("compile-packets.json"),
            serde_json::to_string(&CompilePackets {
                generated_at: "2026-03-31".into(),
                packets: Vec::new(),
                summary: crate::model::CompileSummary {
                    total_errors: 0,
                    total_warnings: 0,
                    arcs_affected: 0,
                },
            })
            .expect("serialize compile packets"),
        )
        .expect("write compile packets");

        let bundle = build_repair_bundle(&root).expect("build repair bundle");
        assert_eq!(bundle.status, "no-failure");
        assert_eq!(bundle.primary_arc, "<none>");
    }
}

