                          COUNT(*) AS runs
                     FROM ci_job_runs
                    WHERE project_id = ? AND duration_secs IS NOT NULL
                    GROUP BY job_name, stage, runner_pool
                    ORDER BY avg_duration_secs DESC
                    LIMIT ?"#,
            )
            .bind(project_id)
