    ) -> Result<Option<TestExecution>> {
        sqlx::query_as(
            r#"
            SELECT id, test_name, version, duration_ms, status, created_at
            FROM test_executions
            WHERE test_name = ? AND status = 'success'
            ORDER BY created_at DESC
            LIMIT 1
            "#,
        )
        .bind(test_name)
