    }

    pub async fn get_test_bottlenecks(
        &self,
        mode: &str,
        limit: i64,
    ) -> Result<Vec<TestBottleneck>> {
        if mode == "average" {
            sqlx::query_as(
                r#"
                SELECT test_name,
                       AVG(duration_ms) as avg_duration_ms,
                       MAX(duration_ms) as latest_duration_ms,
                       COUNT(*) as count
                FROM test_executions
                GROUP BY test_name
                ORDER BY avg_duration_ms DESC
                LIMIT ?
                "#,
            )
            .bind(limit)
            .fetch_all(&self.pool)
            .await
            .map_err(Into::into)
        } else {
            // mode == "latest"
            sqlx::query_as(
                r#"
                SELECT test_name,
                       AVG(duration_ms) as avg_duration_ms,
                       (SELECT duration_ms FROM test_executions t2 WHERE t2.test_name = t1.test_name ORDER BY created_at DESC LIMIT 1) as latest_duration_ms,
                       COUNT(*) as count
                FROM test_executions t1
                GROUP BY test_name
                ORDER BY latest_duration_ms DESC
                LIMIT ?
                "#
            )
            .bind(limit)
            .fetch_all(&self.pool)
            .await
            .map_err(Into::into)
        }
    }

