    const AGENT_REF: &str = "refs/heads/agent/demo-branch";

    fn zero_sha() -> String {
        format!("{:040x}", 0u8)
    }

    fn head_sha() -> String {
        format!("{:040x}", 81_985_529_216_486_895_u128)
    }

    #[test]
