pub struct AgentSession {
    pub id: String,
    pub objective: String,
    pub state: AgentState,
    pub branch: Option<String>,
    pub mr_iid: Option<i64>,
    pub head_sha: Option<String>,
    pub trust_tier: TrustTier,
