}

impl Default for AgentSession {
    fn default() -> Self {
        let now = Utc::now();
        Self {
            id: String::new(), objective: String::new(),
            state: AgentState::Spawning, branch: None, mr_iid: None,
            head_sha: None, trust_tier: TrustTier::Untrusted,
