//! Owner: TUI Control-Plane API — view-specific snapshot builders
//! Proof: `cargo nextest run -p jeryu -- api::snapshot`
//! Invariants: Snapshot builders produce typed view models from raw control-plane state.

use serde::{Deserialize, Serialize};

use super::entity::EntityRef;
use crate::tui::action_registry::RiskTier;

/// VTI (Validated Test Intelligence) status for a job or test.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum VtiStatus {
    /// Test was selected by the VTI engine.
    Selected { reason: String, confidence: f64 },
    /// Test was skipped by the VTI engine.
    Skipped { reason: String, confidence: f64 },
    /// Test was accelerated (cache hit or reuse). 🔥
    Accelerated { reason: String, time_saved_secs: i64 },
    /// Full suite run (no VTI filtering applied).
    FullSuite,
}

impl VtiStatus {
    pub fn badge(&self) -> &'static str {
        match self {
            Self::Selected { .. } => "[SEL]",
            Self::Skipped { .. } => "[SKIP]",
            Self::Accelerated { .. } => "[🔥 VTI]",
            Self::FullSuite => "[FULL]",
        }
    }
    pub fn is_accelerated(&self) -> bool { matches!(self, Self::Accelerated { .. }) }
    pub fn is_skipped(&self) -> bool { matches!(self, Self::Skipped { .. }) }
}

/// Cache verdict for a job.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum CacheVerdict {
    Hit { trust: CacheTrust },
    Miss,
    Tainted { reason: String },
    Denied { reason: String },
}

impl CacheVerdict {
    pub fn badge(&self) -> &'static str {
        match self {
            Self::Hit { .. } => "[HIT]",
            Self::Miss => "[MISS]",
            Self::Tainted { .. } => "[TAINT]",
            Self::Denied { .. } => "[DENIED]",
        }
    }
}

#[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "snake_case")]
pub enum CacheTrust { Trusted, Untrusted, Verified }

/// Edge classification for the flow graph.
#[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "snake_case")]
pub enum EdgeKind {
    /// Real GitLab `needs:` dependency ──▶
    GitlabNeeds,
    /// Artifact dependency ══▶
    ArtifactDep,
    /// Inferred stage ordering - -▶
    StageOrder,
    /// VTI skip edge ··▶
    VtiSkipped,
    /// Blocked dependency ✗─▶
    Blocked,
    /// Downstream child pipeline ──▷
    ChildPipeline,
}

impl EdgeKind {
    pub fn glyph(self) -> &'static str {
        match self {
            Self::GitlabNeeds => "──▶",
            Self::ArtifactDep => "══▶",
            Self::StageOrder => "- -▶",
            Self::VtiSkipped => "··▶",
            Self::Blocked => "✗─▶",
            Self::ChildPipeline => "──▷",
        }
    }
}

