pub(crate) async fn gitlab_artifact_size_check() -> HostDoctorCheck {
    let env_file = crate::config::env_file();
    let script = format!(
        "set -a; . '{}'; set +a; curl -fsS -H \"PRIVATE-TOKEN: $GITLAB_PAT\" http://localhost:{}/api/v4/application/settings",
