//! Owner: CLI Git wrappers
//! Proof: `cargo test -p jeryu -- git_passthrough`
//! Invariants: These wrappers never terminate the process directly; `main` owns final exit handling.

use anyhow::Result;
use jeryu::{git, state};

fn code_from_result(code: i32) -> i32 {
    code
}

pub async fn execute_git_passthrough(db: Option<&state::Db>, args: &[String]) -> Result<i32> {
    git::executor::execute_git(db, args).await
}

pub async fn execute_save(db: Option<&state::Db>, message: &str) -> Result<i32> {
    println!("Saving work...");
    let add_code = git::executor::execute_git(db, &["add".into(), ".".into()]).await?;
    if add_code != 0 {
        println!("Failed to stage changes.");
        return Ok(code_from_result(add_code));
    }

    let commit_code =
        git::executor::execute_git(db, &["commit".into(), "-m".into(), message.into()]).await?;
    if commit_code == 0 {
        println!("✅ Work saved locally.");
    } else {
        println!("Failed to save changes.");
    }
    Ok(code_from_result(commit_code))
}

pub async fn execute_sync(db: Option<&state::Db>) -> Result<i32> {
    println!("Syncing with remote...");
    let pull_code = git::executor::execute_git(db, &["pull".into(), "--rebase".into()]).await?;
    if pull_code != 0 {
        return Ok(code_from_result(pull_code));
    }

    let push_code = git::executor::execute_git(db, &["push".into()]).await?;
    if push_code == 0 {
        println!("✅ Synced successfully.");
    }
    Ok(code_from_result(push_code))
}

pub async fn execute_undo(db: Option<&state::Db>) -> Result<i32> {
    println!("Undoing last save...");
    let code =
        git::executor::execute_git(db, &["reset".into(), "HEAD~1".into(), "--soft".into()]).await?;
    if code == 0 {
        println!("✅ Last commit undone (changes kept in staging).");
    }
    Ok(code)
}

use crate::cli::HostCommands;
use anyhow::Result;
use jeryu::{cache, reclaim, state};

pub(crate) async fn execute_host_commands(subcmd: HostCommands) -> Result<i32> {
    match subcmd {
        HostCommands::StorageAudit => {
            reclaim::run_storage_audit().await?;
        }
        HostCommands::Doctor { json } => {
            let report = cache::SmartCache::new(state::Db::open().await?)
                .host_doctor_report()
                .await?;
            if json {
                println!("{}", serde_json::to_string_pretty(&report)?);
            } else {
                cache::print_host_doctor_report(&report);
            }
            if !report.ok {
                anyhow::bail!("host doctor found unhealthy CI host state");
            }
        }
        HostCommands::InstallGcTimer { allow_sudo } => {
            jeryu::host::install_gc_timer(allow_sudo).await?;
        }
        HostCommands::Reclaim { mode, plan, apply } => {
            if mode != "aggressive" {
                anyhow::bail!("Only --mode aggressive is currently supported for host reclaim.");
            }
            if !plan && !apply {
                anyhow::bail!("You must specify either --plan or --apply.");
            }
            reclaim::run_aggressive_reclaim(apply).await?;
        }
    }
    Ok(0)
}

//! Owner: Install command wrappers
//! Proof: `cargo test -p jeryu -- install`
//! Invariants: Install commands stay user-space by default and avoid shell scripts.

use anyhow::Result;

use crate::cli::{InstallActionCommands, InstallCommand};
use jeryu::install::{self, InstallOptions};
use jeryu::install_demo;

pub(crate) async fn execute_install_command(cmd: InstallCommand) -> Result<i32> {
    let opts = InstallOptions {
        prefix: cmd.prefix,
        dry_run: cmd.dry_run,
        json: cmd.json,
        yes: cmd.yes,
        color: cmd.color,
        interactive: cmd.interactive,
        path_mode: cmd.path_mode,
        verbose: cmd.verbose,
        install_deps: cmd.install_deps,
        allow_sudo: cmd.allow_sudo,
    };
    match cmd.action {
        None => install::run_local(&opts).await,
        Some(InstallActionCommands::Doctor) => install::run_doctor(&opts).await,
        Some(InstallActionCommands::Smoke) => install::run_smoke(&opts).await,
        Some(InstallActionCommands::Server) => install::run_server(&opts).await,
        Some(InstallActionCommands::Uninstall) => install::run_uninstall(&opts).await,
        Some(InstallActionCommands::RenderDemo { output, png }) => {
            if opts.json {
                println!(
                    "{}",
                    serde_json::to_string_pretty(&serde_json::json!({
                        "action": "render-demo",
                        "output": output,
                        "png": png,
                        "dry_run": opts.dry_run,
                    }))?
                );
            }
            if opts.dry_run {
                println!(
                    "dry-run: would render install demo GIF to {}",
                    output.display()
                );
                return Ok(0);
            }
            install_demo::render_install_demo(&install_demo::Args { output, png })?;
            println!("install demo rendered");
            Ok(0)
        }
    }
}

use crate::cli::JobCommands;
use crate::dispatch::load_client;
use anyhow::Result;
use jeryu::{logs, state};

pub(crate) async fn execute_job_commands(subcmd: JobCommands) -> Result<()> {
    let (client, _) = load_client()?;

    match subcmd {
        JobCommands::Clear => {
            let db = state::Db::open().await?;
            db.clear_history().await?;
            println!("🗑 All jobs and pipelines cleared from local DB.");
        }
        JobCommands::List { project_id, status } => {
            let scopes: Vec<&str> = status.split(',').collect();
            let jobs = client.list_jobs(project_id, &scopes).await?;
            println!(
                "{:<8} {:<20} {:<12} {:<10}",
                "ID", "NAME", "STATUS", "STAGE"
            );
            for j in &jobs {
                println!(
                    "{:<8} {:<20} {:<12} {:<10}",
                    j.id, j.name, j.status, j.stage
                );
            }
        }
        JobCommands::Trace { project_id, job_id } => {
            let trace = client.job_trace(project_id, job_id).await?;
            logs::print_trace(project_id, job_id, &trace);
        }
        JobCommands::Play { project_id, job_id } => {
            client.play_job(project_id, job_id).await?;
            println!("▶ Job {} triggered", job_id);
        }
        JobCommands::Cancel { project_id, job_id } => {
            client.cancel_job(project_id, job_id).await?;
            println!("⏹ Job {} cancelled", job_id);
        }
        JobCommands::Retry { project_id, job_id } => {
            client.requeue_job(project_id, job_id).await?;
            println!("🔄 Job {} requeued", job_id);
        }
        JobCommands::Explain { project_id, job_id } => {
            let db = state::Db::open().await?;
            if let Some(capsule) = db.latest_evidence_for_job(project_id, job_id).await? {
                let decision_record = db.latest_job_decision(project_id, job_id).await?;
                println!("Job:          {}", capsule.job_id);
                println!("Pipeline:     {}", capsule.pipeline_id.unwrap_or(0));
                println!("Stage:        {}", capsule.stage);
                println!("Ref:          {}", capsule.ref_name);
                println!("Commit:       {}", capsule.commit_sha);
                println!("Failure kind: {}", capsule.failure_kind);
                println!("Classified:   {:?}", capsule.classify());
                println!("Recovery advice: {:?}", capsule.recommended_recovery());
                println!("Summary:      {}", capsule.summary);
                if let Some(record) = decision_record {
                    println!("Last attempt: {} ({})", record.decision, record.reason);
                }
                println!("\nLog snippet:\n{}", capsule.log_snippet);
            } else {
                println!("No structured evidence capsule found for job {}", job_id);
            }
        }
    }
    Ok(())
}

