use crate::cli::PipelineCommands;
use crate::dispatch::{fetch_ci_job_runs, load_client};
use anyhow::Result;
use jeryu::{release, state};

pub(crate) async fn execute_pipeline_commands(subcmd: PipelineCommands) -> Result<()> {
    let (client, _) = load_client()?;
    match subcmd {
        PipelineCommands::Explain {
            project_id,
            pipeline_id,
            json,
        } => {
            let report =
                release::build_pipeline_explain_report(&client, project_id, pipeline_id).await?;
            if json {
                println!("{}", serde_json::to_string_pretty(&report)?);
            } else {
                print!("{}", release::render_pipeline_explain_text(&report));
            }
        }
        PipelineCommands::Doctor {
            project_id,
            pipeline_id,
            json,
        } => {
            let report =
                release::build_pipeline_doctor_report(&client, project_id, pipeline_id).await?;
            if json {
                println!("{}", serde_json::to_string_pretty(&report)?);
            } else {
                print!("{}", release::render_pipeline_doctor_text(&report));
            }
        }
        PipelineCommands::Jobs {
            project_id,
            pipeline_id,
            ingest,
            json,
        } => {
            let db = state::Db::open().await?;
            let runs = fetch_ci_job_runs(&client, project_id, pipeline_id).await?;
            if ingest {
                db.upsert_ci_job_runs(&runs).await?;
            }
            if json {
                println!("{}", serde_json::to_string_pretty(&runs)?);
            } else {
                println!("Pipeline {} — {} jobs", pipeline_id, runs.len());
                for run in &runs {
                    let dur = match run.duration_secs {
                        Some(value) => format!("{value:.1}s"),
                        None => "-".to_string(),
                    };
                    let queue = match run.queued_duration_secs {
                        Some(value) => format!("{value:.1}s"),
                        None => "-".to_string(),
                    };
                    println!(
                        "  {:<34} {:<10} stage={:<14} run={:>8} queue={:>8} pipe={:<8} root={:<8} start={} finish={}",
                        run.job_name,
                        run.status,
                        run.stage,
                        dur,
                        queue,
                        run.pipeline_id,
                        run.root_pipeline_id,
                        run.started_at.as_deref().unwrap_or("-"),
                        run.finished_at.as_deref().unwrap_or("-")
                    );
                }
            }
        }
        PipelineCommands::Ingest {
            project_id,
            pipeline_id,
        } => {
            let db = state::Db::open().await?;
            let runs = fetch_ci_job_runs(&client, project_id, pipeline_id).await?;
            db.upsert_ci_job_runs(&runs).await?;
            println!(
                "ingested {} job runs for pipeline {}",
                runs.len(),
                pipeline_id
            );
        }
        PipelineCommands::Cancel {
            project_id,
            pipeline_id,
        } => {
            client.cancel_pipeline(project_id, pipeline_id).await?;
            println!("cancelled pipeline {}", pipeline_id);
        }
        PipelineCommands::Bottlenecks {
            project_id,
            ref_name,
            limit,
            json,
        } => {
            let db = state::Db::open().await?;
            let rows = db
                .ci_job_bottlenecks(project_id, ref_name.as_deref(), limit)
                .await?;
            if json {
                println!("{}", serde_json::to_string_pretty(&rows)?);
            } else {
                println!("CI bottlenecks — project {}", project_id);
                for row in &rows {
                    println!(
                        "  {:<34} avg={:>7.1}s latest={:>7} max={:>7} runs={:<4} stage={} pool={}",
                        row.job_name,
                        row.avg_duration_secs,
                        match row.latest_duration_secs {
                            Some(value) => format!("{value:.1}s"),
                            None => "-".to_string(),
                        },
                        match row.max_duration_secs {
                            Some(value) => format!("{value:.1}s"),
                            None => "-".to_string(),
                        },
                        row.runs,
                        row.stage,
                        row.runner_pool.as_deref().unwrap_or("-")
                    );
                }
            }
        }
    }
    Ok(())
}

use crate::cli::PoolCommands;
use anyhow::Result;
use jeryu::{docker, pool, state};

pub(crate) async fn execute_pool_commands(subcmd: PoolCommands) -> Result<()> {
    let (client, _) = crate::dispatch::load_client()?;
    let db = state::Db::open().await?;
    let docker_ctl = docker::DockerCtl::connect()?;

    match subcmd {
        PoolCommands::List => {
            let pools = db.list_pools().await?;
            println!(
                "{:<15} {:<8} {:<10} {:<8} {:<12} {:<8}",
                "NAME", "PAUSED", "EXECUTOR", "WARM", "LIVE/DB/MAX", "RUNNER"
            );
            for p in &pools {
                let active = db.count_active_managers(&p.name).await.unwrap_or(0);
                let running = pool::count_running_managers(&db, &docker_ctl, &p.name)
                    .await
                    .unwrap_or(0);
                let manager_status = format!("{running}/{active}/{}", p.max_managers);
                println!(
                    "{:<15} {:<8} {:<10} {:<8} {:<12} {:<8}",
                    p.name,
                    if p.paused { "yes" } else { "no" },
                    p.executor,
                    p.min_warm,
                    manager_status,
                    p.gitlab_runner_id,
                );
            }
        }
        PoolCommands::Scale { name, count } => {
            let started = pool::scale_pool_to(&db, &docker_ctl, &client, &name, count).await?;
            println!(
                "✅ Pool '{}' scaled to {} (started {} new)",
                name, count, started
            );
        }
        PoolCommands::Pause { name } => {
            pool::pause_pool(&db, &client, &name).await?;
            println!("⏸  Pool '{}' paused", name);
        }
        PoolCommands::Resume { name } => {
            pool::resume_pool(&db, &client, &name).await?;
            println!("▶  Pool '{}' resumed", name);
        }
        PoolCommands::Drain { name } => {
            pool::drain_pool(&db, &docker_ctl, &client, &name).await?;
            println!("✅ Pool '{}' drained", name);
        }
        PoolCommands::Remove { name } => {
            pool::delete_pool(&db, &docker_ctl, &client, &name).await?;
            println!("✅ Pool '{}' deleted", name);
        }
        PoolCommands::RotateToken { name } => {
            let new_token = pool::rotate_pool_token(&db, &docker_ctl, &client, &name).await?;
            println!(
                "🔑 Pool '{}' token rotated: {}...{}",
                name,
                &new_token[..8],
                &new_token[new_token.len() - 4..]
            );
        }
    }
    Ok(())
}

use crate::cli::ReleaseCommands;
use crate::dispatch::load_client;
use anyhow::Result;
use jeryu::{release, state};

pub(crate) async fn execute_release_commands(subcmd: ReleaseCommands) -> Result<()> {
    match subcmd {
        ReleaseCommands::Status {
            project_id,
            ref_name,
            sha,
            limit,
            json,
        } => {
            let db = state::Db::open().await?;
            let report = release::build_release_status_report(
                &db,
                release::ReleaseStatusQuery {
                    project_id: Some(project_id),
                    ref_name: Some(ref_name),
                    sha,
                    limit,
                },
            )
            .await?;
            if json {
                println!("{}", serde_json::to_string_pretty(&report)?);
            } else {
                print!("{}", release::render_release_status_text(&report));
            }
        }
        ReleaseCommands::Watch {
            project_id,
            ref_name,
            sha,
            limit,
            interval_secs,
            json,
        } => {
            let db = state::Db::open().await?;
            release::watch_release_status(
                &db,
                release::ReleaseStatusQuery {
                    project_id: Some(project_id),
                    ref_name: Some(ref_name),
                    sha,
                    limit,
                },
                json,
                interval_secs,
            )
            .await?;
        }
        ReleaseCommands::Reconcile {
            project_id,
            ref_name,
            json,
        } => {
            let (client, _) = load_client()?;
            let db = state::Db::open().await?;
            let report =
                release::reconcile_release_for_ref(&db, &client, project_id, &ref_name).await?;
            if json {
                println!("{}", serde_json::to_string_pretty(&report)?);
            } else {
                print!("{}", release::render_release_status_text(&report));
            }
        }
        ReleaseCommands::PromoteProd {
            project_id,
            ref_name,
            version,
        } => {
            let (client, _) = load_client()?;
            let db = state::Db::open().await?;
            let pipeline_id =
                release::trigger_production_promotion(&db, &client, project_id, &ref_name, version)
                    .await?;
            println!("Triggered production-promotion pipeline {pipeline_id}");
        }
        ReleaseCommands::Preflight { ssh_host, json } => {
            let report = release::release_preflight(ssh_host.as_deref()).await;
            if json {
                println!("{}", serde_json::to_string_pretty(&report)?);
            } else {
                let status = if report.ok { "PASS" } else { "FAIL" };
                println!("Preflight: {status}");
                for (k, v) in &report.checks {
                    println!("  {k}: {v}");
                }
                if !report.blockers.is_empty() {
                    println!("\nBlockers:");
                    for b in &report.blockers {
                        println!("  [{}] {} — {}", b.code, b.detail, b.recommended_action);
                    }
                }
            }
            if !report.ok {
                std::process::exit(1);
            }
        }
        ReleaseCommands::Doctor {
            version,
            preflight,
            json,
        } => {
            let db = state::Db::open().await?;
            let ver = if let Some(v) = version {
                v
            } else {
                // Use latest known version from release status
                let report = release::build_release_status_report(
                    &db,
                    release::ReleaseStatusQuery {
                        project_id: Some(release::DEFAULT_RELEASE_PROJECT_ID),
                        ref_name: Some("main".into()),
                        sha: None,
                        limit: 1,
                    },
                )
                .await?;
                if let Some(latest) = report.latest.as_ref() {
                    latest.attempt.version.clone()
                } else {
                    return Err(anyhow::anyhow!("no known release version; use --version"));
                }
            };
            let report = release::release_doctor(&ver, preflight).await;
            if json {
                println!("{}", serde_json::to_string_pretty(&report)?);
            } else {
                let status = if report.blockers.is_empty() {
                    "OK"
                } else {
                    "BLOCKED"
                };
                println!("Doctor [{status}]: {}", report.version);
                println!("  next_action: {}", report.next_action);
                println!("  canary_complete: {}", report.canary_complete);
                println!("  prod_complete: {}", report.prod_complete);
                println!("  safe_to_reconcile: {}", report.safe_to_reconcile);
                if !report.preflight.is_empty() {
                    println!("\nPreflight:");
                    for (k, v) in &report.preflight {
                        println!("  {k}: {v}");
                    }
                }
                println!("\nGates:");
                for (k, v) in &report.gates {
                    println!("  {k}: {}", if *v { "present" } else { "MISSING" });
                }
                if !report.blockers.is_empty() {
                    println!("\nBlockers:");
                    for b in &report.blockers {
                        println!("  [{}] {} — {}", b.code, b.detail, b.recommended_action);
                    }
                }
            }
        }
    }
    Ok(())
}

//! Owner: Remote command wrappers
//! Proof: `cargo test -p jeryu -- remote`
//! Invariants: Remote commands orchestrate SSH and remote bootstrap from Rust only.

use anyhow::Result;

use crate::cli::{RemoteActionCommands, RemoteCommand};
use jeryu::remote::{self, RemoteAction, RemoteCommonOptions};

fn map_remote_command(cmd: RemoteCommand) -> (RemoteAction, RemoteCommonOptions) {
    let opts = RemoteCommonOptions {
        dry_run: cmd.dry_run,
        json: cmd.json,
        yes: cmd.yes,
        color: cmd.color,
        interactive: cmd.interactive,
        service_mode: cmd.service_mode,
        verbose: cmd.verbose,
    };
    let action = match cmd.action {
        RemoteActionCommands::Install {
            target,
            alias,
            setup_key,
            identity,
        } => RemoteAction::Install {
            target,
            alias,
            setup_key,
            identity,
        },
        RemoteActionCommands::Refresh { alias } => RemoteAction::Targeted {
            alias,
            op: remote::RemoteOperation::Refresh,
        },
        RemoteActionCommands::Doctor { alias } => RemoteAction::Targeted {
            alias,
            op: remote::RemoteOperation::Doctor,
        },
        RemoteActionCommands::Status { alias } => RemoteAction::Targeted {
            alias,
            op: remote::RemoteOperation::Status,
        },
        RemoteActionCommands::Logs { alias } => RemoteAction::Targeted {
            alias,
            op: remote::RemoteOperation::Logs,
        },
        RemoteActionCommands::Restart { alias } => RemoteAction::Targeted {
            alias,
            op: remote::RemoteOperation::Restart,
        },
        RemoteActionCommands::Stop { alias } => RemoteAction::Targeted {
            alias,
            op: remote::RemoteOperation::Stop,
        },
        RemoteActionCommands::Start { alias } => RemoteAction::Targeted {
            alias,
            op: remote::RemoteOperation::Start,
        },
        RemoteActionCommands::Ssh { alias } => RemoteAction::Targeted {
            alias,
            op: remote::RemoteOperation::Ssh,
        },
        RemoteActionCommands::Run { alias, command } => RemoteAction::Targeted {
            alias,
            op: remote::RemoteOperation::Run { command },
        },
        RemoteActionCommands::Tunnel { alias } => RemoteAction::Targeted {
            alias,
            op: remote::RemoteOperation::Tunnel,
        },
        RemoteActionCommands::Uninstall { alias } => RemoteAction::Targeted {
            alias,
            op: remote::RemoteOperation::Uninstall,
        },
    };
    (action, opts)
}

pub(crate) async fn execute_remote_command(cmd: RemoteCommand) -> Result<i32> {
    let (action, opts) = map_remote_command(cmd);
    remote::execute_remote(action, opts).await
}

#[cfg(test)]
mod tests {
    use super::*;
    use jeryu::install::{ColorMode, InteractiveMode};
    use jeryu::remote::ServiceMode;

