pub(crate) async fn execute_secrets_commands(subcmd: SecretsCommands) -> Result<()> {
    let db = state::Db::open().await?;
    match subcmd {
        SecretsCommands::Init => {
            let report = secrets::run_secrets_init(Some(&db)).await?;
            println!(
                "Vault initialized at {} (mount={}, prefix={})",
                report.addr, report.mount, report.prefix
            );
        }
        SecretsCommands::Status { json } => {
            let report = secrets::vault_status(Some(&db)).await?;
            if json {
                println!("{}", serde_json::to_string_pretty(&report)?);
            } else {
                println!("━━━ jeryu secrets status ━━━");
                println!("  Vault:       {}", report.addr);
                println!("  Initialized: {}", report.initialized);
                println!("  Sealed:      {}", report.sealed);
                println!("  Healthy:     {}", report.healthy);
                println!("  Token:       {}", report.token_present);
                println!("  Mount:       {}", report.mount);
                println!("  Prefix:      {}", report.prefix);
                println!("  Bootstrap:   {}", report.bootstrap_file);
                println!("  Env file:    {}", report.env_file);
                if let Some(secret_set) = db
                    .latest_release_secret_set(&crate::cli::infer_repo_name())
                    .await?
                {
                    println!("\n  Latest release secret set:");
                    println!("    Version:   {}", secret_set.version);
                    println!("    Target:    {}", secret_set.target);
                    println!("    Status:    {}", secret_set.status);
                    println!("    Runtime:   {}", secret_set.rendered_runtime_env_path);
                    if let Some(report_path) = secret_set.report_path {
                        println!("    Report:    {}", report_path);
                    }
                }
            }
        }
        SecretsCommands::Rotate {
            repo,
            version,
            target,
        } => {
            let target = target.parse::<secrets::SecretTarget>()?;
            let (repo_root, deploy_env, runtime_env) = secrets::default_release_paths();
            let outcome = secrets::rotate_release_secrets(
                &db,
                &repo_root,
                &repo,
                &version,
                target,
                &deploy_env,
                &runtime_env,
            )
            .await?;
            println!("{}", serde_json::to_string_pretty(&outcome)?);
        }
        SecretsCommands::Finalize {
            repo,
            version,
            target,
        } => {
            let target = target.parse::<secrets::SecretTarget>()?;
            let (repo_root, deploy_env, runtime_env) = secrets::default_release_paths();
            let path = secrets::finalize_release_secrets(
                &db,
                &repo_root,
                &repo,
                &version,
                target,
                &deploy_env,
                &runtime_env,
            )
            .await?;
            println!("Finalized runtime env: {}", path.display());
        }
        SecretsCommands::Report { repo, version } => {
            let (repo_root, _, _) = secrets::default_release_paths();
            let path =
                secrets::build_release_secret_report(&db, &repo_root, &repo, &version).await?;
            println!("Release report: {}", path.display());
        }
        SecretsCommands::Recover { repo, version } => {
            let (repo_root, _, _) = secrets::default_release_paths();
            secrets::recover_release_secrets(&db, &repo_root, &repo, &version).await?;
        }
    }
    Ok(())
}

//! Owner: Settings repair/reset commands
//! Proof: `cargo test -p jeryu -- settings`
//! Invariants: Corrupt settings are repaired from backups or reset explicitly; nothing silently falls back.

use anyhow::{Result, bail};
use std::fs;
use std::path::PathBuf;

pub(crate) async fn execute_settings_commands(cmd: crate::cli::SettingsCommands) -> Result<()> {
    match cmd {
        crate::cli::SettingsCommands::Repair => repair_settings().await,
        crate::cli::SettingsCommands::Reset { force } => reset_settings(force).await,
    }
}

async fn repair_settings() -> Result<()> {
    match jeryu::settings::load() {
        Ok(_) => {
            println!("✅ settings.json is valid.");
            Ok(())
        }
        Err(err) => {
            let path = jeryu::settings::settings_path();
            let backup = if let Some(backup) = newest_backup(&path) {
                backup
            } else {
                return Err(anyhow::anyhow!(
                    "settings.json is corrupt and no backup was found: {}",
                    err
                ));
            };
            fs::copy(&backup, &path)?;
            let _ = jeryu::settings::load()?;
            println!("✅ restored settings.json from backup {}", backup.display());
            Ok(())
        }
    }
}

async fn reset_settings(force: bool) -> Result<()> {
    let path = jeryu::settings::settings_path();
    if path.exists() && !force {
        bail!("refusing to reset existing settings without --force");
    }
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }
    let defaults = jeryu::settings::Settings::default();
    fs::write(&path, serde_json::to_string_pretty(&defaults)?)?;
    println!("✅ reset settings.json to defaults");
    Ok(())
}

fn newest_backup(path: &PathBuf) -> Option<PathBuf> {
    let dir = path.parent()?;
    let mut entries: Vec<PathBuf> = fs::read_dir(dir)
        .ok()?
        .filter_map(|entry| entry.ok().map(|entry| entry.path()))
        .filter(|entry| {
            entry
                .file_name()
                .and_then(|name| name.to_str())
                .map(|name| name.starts_with("settings.json.bad."))
                .unwrap_or(false)
        })
        .collect();
    entries.sort();
    entries.pop()
}

use crate::dispatch::load_client;
use anyhow::Result;
use jeryu::{config, docker, gitlab_client, pool, release, secrets, state};

pub async fn execute_down() -> Result<()> {
    let (client, _) = load_client()?;
    let db = state::Db::open().await?;
    let docker_ctl = docker::DockerCtl::connect()?;

    println!("Draining all pools...");
    let pools = db.list_pools().await?;
    for p in &pools {
        pool::drain_pool(&db, &docker_ctl, &client, &p.name)
            .await
            .ok();
        println!("  ✅ Pool '{}' drained", p.name);
    }

    println!("Stopping GitLab...");
    docker_ctl.compose_down().await?;
    println!("✅ Everything stopped.");
    Ok(())
}

