    }

    #[test]
    fn risk_gate_denies_failed_refs() {
        let result = evaluate_risk_gate(
            TrustTier::Trusted,
            1,
            0,
            1,
            &RequiredEvidencePolicy::default(),
        );
        assert_eq!(result.decision, RiskGateDecision::Deny);
    }

