#[derive(Debug, Deserialize)]
struct PipelineHookPayload {
    project: Option<ProjectInfo>,
    object_attributes: Option<PipelineAttributes>,
}

#[derive(Debug, Deserialize)]
struct ProjectInfo {
    id: Option<i64>,
}

#[derive(Debug, Deserialize)]
struct PipelineAttributes {
    id: Option<i64>,
    status: Option<String>,
    sha: Option<String>,
    #[serde(rename = "ref")]
    ref_name: Option<String>,
}

pub(crate) async fn handle_pipeline_event_from_body(
    state: SharedState,
    body: &str,
) -> Result<(), serde_json::Error> {
    let payload = serde_json::from_str::<PipelineHookPayload>(body)?;
    handle_pipeline_event(state, payload).await;
    Ok(())
}

pub(crate) async fn handle_pipeline_event(state: SharedState, payload: PipelineHookPayload) {
    if let Some(attrs) = payload.object_attributes {
        info!(
            pipeline_id = attrs.id,
            status = attrs.status,
            ref_name = attrs.ref_name,
            "pipeline event"
        );

        if let (Some(pipeline_id), Some(status), Some(ref_name), Some(sha)) =
            (attrs.id, attrs.status, attrs.ref_name, attrs.sha)
        {
            let ref_name = normalize_ref(&ref_name);
            let project_id = match payload.project.and_then(|project| project.id) {
                Some(id) => id,
                None => 0,
            };
            let _ = state
                .db
                .upsert_tracked_pipeline(&TrackedPipeline {
                    pipeline_id,
                    project_id,
                    ref_name: ref_name.clone(),
                    sha: sha.clone(),
                    status: status.clone(),
                    updated_at: chrono::Utc::now().to_rfc3339(),
                })
                .await;

            if ref_name == "main" && status == "success" {
                if let Ok(Some(attempt)) = state
                    .db
                    .release_attempt_by_production_pipeline_id(pipeline_id)
                    .await
                {
                    if let Err(err) = state
                        .db
                        .update_production_pipeline_status(pipeline_id, &status)
                        .await
                    {
                        error!(
                            project_id,
                            pipeline_id,
                            sha = %sha,
                            error = %err,
                            "failed to refresh production pipeline status"
                        );
                    } else {
                        info!(
                            project_id,
                            pipeline_id,
                            sha = %attempt.sha,
                            version = %attempt.version,
                            "production-promotion pipeline passed"
                        );
                    }
                    return;
                }

                if let Ok(Some(attempt)) = state
                    .db
                    .release_attempt_by_release_pipeline_id(pipeline_id)
                    .await
                {
                    if let Err(err) = state
                        .db
                        .update_release_pipeline_status(pipeline_id, &status)
                        .await
                    {
                        error!(
                            project_id,
                            pipeline_id,
                            sha = %sha,
                            error = %err,
                            "failed to refresh release pipeline status"
                        );
                    } else {
                        info!(
                            project_id,
                            pipeline_id,
                            sha = %attempt.sha,
                            version = %attempt.version,
                            "release-execution pipeline passed"
                        );
                    }
                    let state = state.clone();
                    let ref_name = ref_name.clone();
                    tokio::spawn(async move {
                        if let Err(err) = release::maybe_trigger_production_promotion(
                            &state.db,
                            &state.client,
                            project_id,
                            &ref_name,
                            Some(&attempt.sha),
                            Some(&attempt.version),
                        )
                        .await
                        {
                            error!(
                                project_id,
                                pipeline_id,
                                sha = %attempt.sha,
                                version = %attempt.version,
                                error = %err,
                                "automatic production promotion check failed"
                            );
                        }
                    });
                    return;
                }

                let state = state.clone();
                let ref_name = ref_name.clone();
                let sha = sha.clone();
                tokio::spawn(async move {
                    if let Err(err) = release::launch_canary_for_green_pipeline(
                        &state.db,
                        &state.client,
                        project_id,
                        &ref_name,
                        &sha,
                        pipeline_id,
                    )
                    .await
                    {
                        error!(
                            project_id,
                            pipeline_id,
                            sha = %sha,
                            error = %err,
                            "automatic canary launch failed"
                        );
                    }
                });
            } else if ref_name == "main"
                && matches!(status.as_str(), "failed" | "canceled" | "skipped")
            {
                match state
                    .db
                    .release_attempt_by_release_pipeline_id(pipeline_id)
                    .await
                {
                    Ok(Some(attempt)) => {
                        if let Err(err) = state
                            .db
                            .update_release_pipeline_status(pipeline_id, &status)
                            .await
                        {
                            error!(
                                project_id,
                                pipeline_id,
                                status = %status,
                                error = %err,
                                "failed to refresh failed release-execution pipeline status"
                            );
                        } else {
                            let note = format!(
                                "release-execution pipeline {pipeline_id} ended with status {status}"
                            );
                            let _ = state
                                .db
                                .finish_release_canary(
                                    project_id,
                                    &ref_name,
                                    &attempt.sha,
                                    "failed",
                                    Some(&note),
                                )
                                .await;
                        }
                    }
                    Ok(None) => {
                        if let Ok(Some(_attempt)) = state
                            .db
                            .release_attempt_by_production_pipeline_id(pipeline_id)
                            .await
                            && let Err(err) = state
                                .db
                                .update_production_pipeline_status(pipeline_id, &status)
                                .await
                        {
                            error!(
                                project_id,
                                pipeline_id,
                                status = %status,
                                error = %err,
                                "failed to refresh failed production-promotion pipeline status"
                            );
                        }
                    }
                    Err(err) => {
                        debug!(
                            project_id,
                            pipeline_id,
                            status = %status,
                            error = %err,
                            "pipeline was not a tracked release pipeline"
                        );
                    }
                }
            }
        }
    }
}

use anyhow::Result;
use serde::Deserialize;
use tracing::{debug, error, info};

use super::super::EngineState;
use super::SharedState;
use crate::decision::{
    RetryDecision as RecoveryDecision, SupersedenceAction, SupersedenceDecision,
};
use crate::impact;
use crate::state::TrackedPipeline;

#[derive(Debug, Deserialize)]
struct PushHookPayload {
    project_id: i64,
    before: String,
    after: String,
    #[serde(rename = "ref")]
    ref_name: String,
}

pub(crate) async fn handle_push_event_from_body(
    state: SharedState,
    body: &str,
) -> Result<(), serde_json::Error> {
    let payload = serde_json::from_str::<PushHookPayload>(body)?;
    handle_push_event(state, payload).await;
    Ok(())
}

pub(crate) async fn handle_push_event(state: SharedState, payload: PushHookPayload) {
    let ref_name = super::normalize_ref(&payload.ref_name);
    info!(
        project_id = payload.project_id,
        ref_name = %ref_name,
        before = %payload.before,
        after = %payload.after,
        "intercepted Push Hook for Semantic CI Evaluation"
    );

    if ref_name.starts_with("jeryu-test-") {
        debug!(
            project_id = payload.project_id,
            ref_name = %ref_name,
            "skipping supersedence/impact for ephemeral test branch"
        );
        return;
    }

    if crate::decision::is_branch_creation_push(&payload.before) {
        debug!(
            project_id = payload.project_id,
            "semantic evaluation bypassed: branch creation event"
        );
        return;
    }

    if let Err(e) = handle_supersedence(&state, payload.project_id, &ref_name, &payload.after).await
    {
        error!(error = %e, project_id = payload.project_id, ref_name = %ref_name, "supersedence evaluation failed");
    }

    match impact::plan_for_push(
        &state.client,
        payload.project_id,
        &payload.before,
        &payload.after,
    )
    .await
    {
        Ok(plan) => {
            let payload_json = impact::render_plan_payload(&plan);
            if let Err(e) = state
                .db
                .append_event(
                    "impact_decision",
                    Some(payload.project_id),
                    None,
                    "engine",
                    &payload_json.to_string(),
                )
                .await
            {
                error!(error = %e, "failed to persist impact decision");
            }

            info!(
                project_id = payload.project_id,
                ref_name = %ref_name,
                lanes = ?plan.selected_lanes,
                recovery_path = plan.widened_to_full,
                "semantic CI impact plan computed"
            );

            if !plan.affected_paths.is_empty() {
                let vti_plan = crate::test_intel::planner::plan_tests(&plan.affected_paths);
                let vti_json = crate::test_intel::explain::explain_json(&vti_plan);
                let mode = format!("{:?}", vti_plan.mode);
                let subsystems = vti_plan.affected_subsystems.join(",");
                if let Err(e) = state
                    .db
                    .record_test_plan(
                        payload.project_id,
                        &payload.before,
                        &payload.after,
                        &mode,
                        vti_plan.confidence,
                        vti_plan.selected_tests.len() as i64,
                        vti_plan.skipped_subsystems.len() as i64,
                        &subsystems,
                        vti_plan.repair_reason(),
                        &vti_json.to_string(),
                    )
                    .await
                {
                    error!(error = %e, "failed to persist VTI test plan");
                } else {
                    info!(
                        project_id = payload.project_id,
                        mode = %mode,
                        confidence = vti_plan.confidence,
                        selected = vti_plan.selected_tests.len(),
                        skipped = vti_plan.skipped_subsystems.len(),
                        "VTI test plan recorded"
                    );
                }
            }
        }
        Err(e) => {
            error!(error = %e, project_id = payload.project_id, ref_name = %ref_name, "impact analysis failed");
        }
    }
}

async fn handle_supersedence(
    state: &EngineState,
    project_id: i64,
    ref_name: &str,
    newest_sha: &str,
) -> Result<()> {
    let pipelines = state
        .client
        .list_pipelines(project_id, Some(ref_name))
        .await?;

    for pipeline in pipelines {
        state
            .db
            .upsert_tracked_pipeline(&TrackedPipeline {
                pipeline_id: pipeline.id,
                project_id,
                ref_name: pipeline.ref_name.clone(),
                sha: pipeline.sha.clone(),
                status: pipeline.status.clone(),
                updated_at: chrono::Utc::now().to_rfc3339(),
            })
            .await?;

        if pipeline.sha == newest_sha {
            continue;
        }

        if !matches!(pipeline.status.as_str(), "pending" | "running" | "created") {
            continue;
        }

        let decision = SupersedenceDecision {
            project_id,
            ref_name: ref_name.to_string(),
            newest_sha: newest_sha.to_string(),
            superseded_pipeline_id: pipeline.id,
            superseded_sha: pipeline.sha.clone(),
            action: SupersedenceAction::Cancel,
            reason: "newer commit superseded older in-flight pipeline on the same ref".to_string(),
        };

        state
            .db
            .append_event(
                "pipeline_superseded",
                Some(project_id),
                None,
                "engine",
                &serde_json::to_string(&decision)?,
            )
            .await?;

        state
            .client
            .cancel_pipeline(project_id, pipeline.id)
            .await?;
        state
            .db
            .append_event(
                "pipeline_cancel_requested",
                Some(project_id),
                None,
                "engine",
                &serde_json::json!({
                    "pipeline_id": pipeline.id,
                    "sha": pipeline.sha,
                    "ref_name": ref_name,
                })
                .to_string(),
            )
            .await?;
    }

    Ok(())
}

//! Owner: Epoch-Based Cache Invalidation
//! Proof: `cargo test -p jeryu -- epoch`
//! Invariants: Epoch bumps are recorded with author_job_id and reason; is_valid fails closed (returns false) on lookup failure; epochs are per-scope and never shared across scopes

use anyhow::Result;
use cache_brain_adapter::{AdapterBackend, AnyPool};

use crate::state::StateBackend;

fn adapter_backend(backend: StateBackend) -> AdapterBackend {
    match backend {
        StateBackend::Sqlite => AdapterBackend::Sqlite,
        StateBackend::Postgres => AdapterBackend::Postgres,
    }
}

/// Manages epoch-based cache invalidation.
///
/// Instead of scanning and deleting massive graphs of files on disk,
/// we simply bump an epoch pointer. Any cache lookups for objects
/// tied to an older epoch strictly fail, immediately isolating poisoned trees.
#[derive(Clone)]
pub struct EpochManager {
    pool: AnyPool,
    backend: StateBackend,
}

impl EpochManager {
    pub fn new(pool: AnyPool) -> Self {
        Self::with_backend(pool, StateBackend::Sqlite)
    }

    pub fn with_backend(pool: AnyPool, backend: StateBackend) -> Self {
        Self { pool, backend }
    }

    /// Retrieve the current epoch for a given boundary scope (e.g., "global", "project:123", "runner:456").
    pub async fn get_epoch(&self, scope: &str) -> Result<u64> {
        let epoch = cache_brain_adapter::current_epoch_for(
            &self.pool,
            adapter_backend(self.backend),
            scope,
        )
        .await?;
        Ok(epoch as u64)
    }

    /// Bump the epoch, instantly invalidating all cache entries tied to the previous epoch.
    pub async fn bump_epoch(&self, scope: &str, author_job_id: i64, reason: &str) -> Result<u64> {
        let current = self.get_epoch(scope).await?;
        let next = current + 1;

        cache_brain_adapter::upsert_epoch_for(
            &self.pool,
            adapter_backend(self.backend),
            scope,
            next as i64,
            &chrono::Utc::now().to_rfc3339(),
            author_job_id,
            reason,
        )
        .await?;

        tracing::warn!(
            "Escalated cache epoch for scope `{}` -> {}. Reason: {}",
            scope,
            next,
            reason
        );
        Ok(next)
    }

    /// Verifies if a cached object's epoch is still valid relative to the active scope epoch.
    /// Returns true if it is safe to use.
    pub async fn is_valid(&self, scope: &str, object_epoch: u64) -> Result<bool> {
        let current = self.get_epoch(scope).await?;
        Ok(object_epoch >= current)
    }
}

use anyhow::Result;
use tracing::info;

use super::support::env_string_or_default;

/// Handles `jeryu exec cleanup`
/// Tears down the sandbox.
pub async fn run_cleanup() -> Result<()> {
    let job_id = env_string_or_default("CUSTOM_ENV_CI_JOB_ID", "unknown");
    let project_id_str = env_string_or_default("CUSTOM_ENV_CI_PROJECT_ID", "");
    let project_dir = env_string_or_default("CUSTOM_ENV_CI_PROJECT_DIR", "/tmp/jeryu-job");

    info!(job_id, "Driver: cleaning up sandbox");

    let sandbox_path = format!("{}-sandbox", project_dir);
    let quarantine_marker = std::path::Path::new(&sandbox_path).join(".jeryu_quarantine");

    if quarantine_marker.exists() {
        tracing::error!(
            "🚨 Sandbox {} is quarantined. Skipping workspace destruction for forensics.",
            sandbox_path
        );

        let db = crate::state::Db::open().await?;
        let payload = serde_json::json!({
            "action": "quarantine_skip",
            "sandbox_path": sandbox_path,
        });
        db.append_event(
            "executor_cleanup_quarantined",
            project_id_str.parse().ok(),
            job_id.parse().ok(),
            "jeryu-exec",
            &payload.to_string(),
        )
        .await?;

        return Ok(());
    }

    if std::path::Path::new(&sandbox_path).exists() {
        let _ = std::fs::remove_dir_all(&sandbox_path);
        info!("removed sandbox fast clone at {}", sandbox_path);
    }

    let db = crate::state::Db::open().await?;
    let payload = serde_json::json!({
        "action": "cleanup",
        "sandbox_path": sandbox_path,
        "build_failure_exit_code": env_string_or_default("BUILD_FAILURE_EXIT_CODE", ""),
        "system_failure_exit_code": env_string_or_default("SYSTEM_FAILURE_EXIT_CODE", ""),
    });

    db.append_event(
        "executor_cleanup",
        project_id_str.parse().ok(),
        job_id.parse().ok(),
        "jeryu-exec",
        &payload.to_string(),
    )
    .await?;

    Ok(())
}

//! Owner: Custom Executor & Sandbox Isolation
//! Proof: `cargo test -p jeryu -- exec`
//! Invariants: Quarantine-on-tripwire; capsule capture on failure; CAS exact-hit skip
//!
//! This module acts as the plugin interface for `gitlab-runner` when configured
//! as `executor = "custom"`. It handles the lifecycle of the actual job execution:
//! configuration, provisioning the sandbox, running the user script, and cleaning up.

mod support;
mod stage;
mod cleanup;

pub use support::*;
pub use stage::*;
pub use cleanup::*;

use anyhow::Result;
use std::path::{Component, Path};

/// Handles `jeryu exec config`
/// Tells GitLab Runner what capabilities this driver supports.
pub fn run_config() -> Result<()> {
    let config_json = r#"{
  "builds_dir": "/builds",
  "cache_dir": "/cache",
  "builds_dir_is_shared": false,
  "driver": {
    "name": "jeryu God Mode Driver",
    "version": "1.0.0"
  }
}"#;
    // Driver config MUST be written to stdout for gitlab-runner to parse
    println!("{}", config_json);
    Ok(())
}

pub fn validate_script_path(script_path: &str) -> Result<()> {
    let path = Path::new(script_path);

    if script_path.trim().is_empty() {
        anyhow::bail!("custom executor script path must not be empty");
    }

    if path.is_absolute() {
        anyhow::bail!("custom executor script path must be relative");
    }

    if path.components().any(|component| {
        matches!(
            component,
            Component::ParentDir | Component::Prefix(_) | Component::RootDir
        )
    }) {
        anyhow::bail!("custom executor script path must not traverse out of the sandbox");
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::validate_script_path;

    #[test]
    fn validate_script_path_accepts_relative_paths_only() {
        assert!(validate_script_path("build.sh").is_ok());
        assert!(validate_script_path("ci/build_script.sh").is_ok());
        assert!(validate_script_path("").is_err());
        assert!(validate_script_path("/tmp/build.sh").is_err());
        assert!(validate_script_path("../build.sh").is_err());
    }
}

use anyhow::Result;
use std::env;
use tracing::info;

use super::support::{
    ensure_custom_executor_tools, env_bool_or_default, env_i64_or_default,
    env_string_or_default,
};

/// Handles `jeryu exec prepare`
/// Provisions the actual job container sandbox.
pub async fn run_prepare() -> Result<()> {
    let job_id = env_string_or_default("CUSTOM_ENV_CI_JOB_ID", "unknown");
    let project_dir = env_string_or_default("CUSTOM_ENV_CI_PROJECT_DIR", "/tmp/jeryu-job");

    info!(
        job_id,
        project_dir, "Driver: preparing custom execution sandbox"
    );

    let sandbox_path = format!("{}-sandbox", project_dir);

    if super::support::fast_clone(&project_dir, &sandbox_path).is_err() {
        let _ = std::fs::create_dir_all(&sandbox_path);
    }

    crate::honeypot::seed_sandbox(&sandbox_path);

    Ok(())
}

/// Handles `jeryu exec run`
/// Executes a specific stage of the pipeline (step_script, build_script, etc.)
pub async fn run_stage(script_path: &str, stage: &str) -> Result<()> {
    let job_id = env_i64_or_default("CUSTOM_ENV_CI_JOB_ID", 0);
    let project_id_str = env_string_or_default("CUSTOM_ENV_CI_PROJECT_ID", "");
    let project_id = project_id_str.parse::<i64>().ok();

    super::validate_script_path(script_path)?;

    info!(job_id, stage, script_path, "Driver: running job stage");

    if stage == "build_script" {
        ensure_custom_executor_tools().await?;
    }

    let project_dir = env_string_or_default("CUSTOM_ENV_CI_PROJECT_DIR", "/tmp/jeryu-job");
    let sandbox_path = format!("{}-sandbox", project_dir);

    let db = crate::state::Db::open().await?;
    let epoch_manager = crate::epoch::EpochManager::with_backend(db.pool(), db.backend());
    let taint_manager = crate::taint::TaintManager::with_backend(db.pool(), db.backend());
    let store = cache_brain_adapter::create_action_store(
        db.pool(),
        match db.backend() {
            crate::state::StateBackend::Sqlite => cache_brain_adapter::AdapterBackend::Sqlite,
            crate::state::StateBackend::Postgres => cache_brain_adapter::AdapterBackend::Postgres,
        },
    );
    let cache_brain =
        crate::cache_brain::CacheBrain::with_store(epoch_manager, taint_manager, store);

    let mut build_unit: Option<crate::cache_brain::BuildUnit> = None;

    if stage == "build_script"
        && env::var("CUSTOM_ENV_JERYU_FORCE_REFRESH").ok().as_deref() != Some("1")
    {
        let is_rust_build = script_path.contains("cargo build")
            && !script_path.contains("cargo test")
            && !script_path.contains("cargo check")
            && !script_path.contains("cargo clippy");
        let dockerfile = std::path::Path::new(&sandbox_path).join("Dockerfile");

        build_unit = if dockerfile.exists() {
            if let Ok(witness) = crate::witness::WitnessBuilder::docker_build_witness(
                project_id.unwrap_or(0),
                &dockerfile,
                std::path::Path::new(&sandbox_path),
            )
            .await
            {
                Some(crate::cache_brain::BuildUnit {
                    unit_type: crate::cache_brain::BuildUnitType::DockerBuild {
                        stage: "build".into(),
                    },
                    input_signature: witness.key,
                    environment_signature: env_string_or_default("DOCKER_DEFAULT_PLATFORM", ""),
                    scope: format!("project:{}", project_id.unwrap_or(0)),
                    trust_tier: crate::policy::TrustTier::Untrusted,
                })
            } else {
                None
            }
        } else if is_rust_build {
            let cargo_lock = std::path::Path::new(&sandbox_path).join("Cargo.lock");
            if let Ok(witness) = crate::witness::WitnessBuilder::rust_build_witness(
                project_id.unwrap_or(0),
                &cargo_lock,
                "1.74.0",
                Some("cargo-witness"),
                "x86_64-unknown-linux-gnu",
                "release",
                "",
            )
            .await
            {
                Some(crate::cache_brain::BuildUnit {
                    unit_type: crate::cache_brain::BuildUnitType::CargoBuild {
                        target: "x86_64-unknown-linux-gnu".into(),
                        profile: "release".into(),
                        features: "".into(),
                    },
                    input_signature: witness.key,
                    environment_signature: env_string_or_default("RUSTFLAGS", ""),
                    scope: format!("project:{}", project_id.unwrap_or(0)),
                    trust_tier: crate::policy::TrustTier::Untrusted,
                })
            } else {
                None
            }
        } else {
            None
        };

        if let Some(ref unit) = build_unit {
            let verdict = cache_brain.plan_step(unit).await?;
            tracing::info!("CacheBrain Verdict: {:?}", verdict);

            let verdict_str = format!("{:?}", verdict);
            let reasons_str = match serde_json::to_string(&verdict) {
                Ok(s) => s,
                Err(_) => String::new(),
            };
            let _ = db
                .store_test_verdict(
                    job_id,
                    &unit.input_signature,
                    &unit.input_signature,
                    &unit.input_signature,
                    &verdict_str,
                    &format!("{:?}", unit.trust_tier),
                    &reasons_str,
                )
                .await;

            if verdict.is_hit() {
                let cas_path = crate::config::data_dir()
                    .join("cas")
                    .join(&unit.input_signature);
                let manifest_path = cas_path.join("manifest.json");
                let payload_path = cas_path.join("payload.tar.zst");
                let manifest_exists = tokio::fs::try_exists(&manifest_path).await.unwrap_or(false);
                let payload_exists = tokio::fs::try_exists(&payload_path).await.unwrap_or(false);

                if manifest_exists && payload_exists {
                    let extract_status = tokio::process::Command::new("tar")
                        .arg("-I")
                        .arg("zstd")
                        .arg("-xf")
                        .arg(&payload_path)
                        .arg("-C")
                        .arg(&sandbox_path)
                        .status()
                        .await;

                    match extract_status {
                        Ok(s) if s.success() => {
                            tracing::info!(
                                "✅ Exact-Hit: extracted CAS payload {:?} into {}. Skipping execution.",
                                payload_path,
                                sandbox_path
                            );
                            std::process::exit(0);
                        }
                        Ok(s) => {
                            tracing::warn!(
                                "CAS extraction failed with exit code {:?}; falling back to cold execution.",
                                s.code()
                            );
                        }
                        Err(e) => {
                            tracing::warn!(
                                "CAS extraction error: {:?}; falling back to cold execution.",
                                e
                            );
                        }
                    }
                } else {
                    tracing::warn!(
                        "Exact-hit verdict but CAS payload incomplete (manifest={}, payload={}); falling back to cold execution.",
                        manifest_exists,
                        payload_exists
                    );
                }
            } else {
                tracing::info!("Cache Brain produced Miss/Deny verdict, falling to cold execution.");
            }
        }
    }

    let buildkit_mgr = crate::buildkit::BuildKitManager::new("untrusted");
    let mut extra_envs = buildkit_mgr.inject_env();
    extra_envs.push(("PIP_BREAK_SYSTEM_PACKAGES".to_string(), "1".to_string()));
    extra_envs.push(("PIP_ROOT_USER_ACTION".to_string(), "ignore".to_string()));

    let cargo_available = std::process::Command::new("cargo")
        .arg("--version")
        .output()
        .is_ok();
    let rustc_available = std::process::Command::new("rustc")
        .arg("--version")
        .output()
        .is_ok();

    if cargo_available && rustc_available {
        let pool_cache_root = env_string_or_default("JERYU_CARGO_CACHE_ROOT", "/pool-cache");
        let cargo_cache_enabled = env_bool_or_default("JERYU_CARGO_CACHE", true);
        let project_scope = match env::var("CUSTOM_ENV_CI_PROJECT_PATH_SLUG") {
            Ok(value) if !value.trim().is_empty() => value,
            _ => match env::var("CUSTOM_ENV_CI_PROJECT_DIR") {
                Ok(project_dir) => {
                    match crate::cargo_cache::canonical_repo_key(std::path::Path::new(&project_dir))
                    {
                        Ok(value) if !value.trim().is_empty() => value,
                        _ => "unknown-project".to_string(),
                    }
                }
                Err(_) => "unknown-project".to_string(),
            },
        };
        let isolate_job =
            if std::env::var("JERYU_CARGO_TARGET_ISOLATE").ok().as_deref() == Some("job") {
                std::env::var("CUSTOM_ENV_CI_JOB_ID").ok()
            } else {
                None
            };
        let incremental_override = std::env::var("JERYU_CARGO_INCREMENTAL").ok();
        let cargo_layout = crate::cargo_cache::runner_cargo_layout(
            std::path::Path::new(&pool_cache_root),
            &project_scope,
            cargo_cache_enabled,
            isolate_job.as_deref(),
            incremental_override.as_deref(),
        )?;
        if let Some(target_dir) = cargo_layout.env.get("CARGO_TARGET_DIR") {
            let _ = std::fs::create_dir_all(target_dir);
        }
        if let Some(sccache_dir) = cargo_layout.env.get("SCCACHE_DIR") {
            let _ = std::fs::create_dir_all(sccache_dir);
        }
        extra_envs.extend(cargo_layout.env.into_iter());
    }

    let cargo_dir = std::path::Path::new(&sandbox_path).join(".cargo");
    let _ = std::fs::create_dir_all(&cargo_dir);
    let cargo_toml = r#"
[source.crates-io]
replace-with = "jeryu-proxy"

[source.jeryu-proxy]
registry = "sparse+http://127.0.0.1:19800/api/v1/crates"
"#
    .to_string();
    let _ = std::fs::write(cargo_dir.join("config.toml"), cargo_toml);

    tracing::info!("Injecting sandbox environment variables ({:?})", extra_envs);

    let sandbox = crate::sandbox::ExecutorSandbox::new(crate::sandbox::SandboxConfig {
        use_strict_network_isolation: crate::settings::get().sandbox.strict_network_isolation,
        proxy_host: String::new(),
        proxy_port: 0,
        bind_workspace: sandbox_path.clone(),
        extra_envs,
    });

    let mut child = sandbox.spawn_script(script_path)?;

    let _tripwire = if let Some(pid) = child.id() {
        crate::honeypot::start_tripwire(
            pid,
            crate::honeypot::get_tokens(&sandbox_path),
            sandbox_path.clone(),
        )
        .ok()
    } else {
        None
    };

    let stdout = child.stdout.take().unwrap();
    let stderr = child.stderr.take().unwrap();

    let log_buffer = std::sync::Arc::new(std::sync::Mutex::new(Vec::with_capacity(4096)));
    let log_buffer_cloned = log_buffer.clone();

    let stdout_task = tokio::spawn(async move {
        let mut reader = tokio::io::BufReader::new(stdout);
        let mut line = String::new();
        while let Ok(n) = tokio::io::AsyncBufReadExt::read_line(&mut reader, &mut line).await {
            if n == 0 {
                break;
            }
            print!("{}", line);
            let mut buf = log_buffer.lock().unwrap();
            if buf.len() > 3000 {
                buf.drain(0..1000);
            }
            buf.extend_from_slice(line.as_bytes());
            line.clear();
        }
    });

    let log_buffer_cloned_stderr = log_buffer_cloned.clone();
    let stderr_task = tokio::spawn(async move {
        let mut reader = tokio::io::BufReader::new(stderr);
        let mut line = String::new();
        while let Ok(n) = tokio::io::AsyncBufReadExt::read_line(&mut reader, &mut line).await {
            if n == 0 {
                break;
            }
            eprint!("{}", line);
            let mut buf = log_buffer_cloned_stderr.lock().unwrap();
            if buf.len() > 3000 {
                buf.drain(0..1000);
            }
            buf.extend_from_slice(line.as_bytes());
            line.clear();
        }
    });

    let status = child.wait().await?;
    let _ = tokio::join!(stdout_task, stderr_task);

    let exit_code = status.code().unwrap_or(1);
    let quarantine_marker = std::path::Path::new(&sandbox_path).join(".jeryu_quarantine");
    let is_quarantined = quarantine_marker.exists();

    if is_quarantined {
        let reason = match std::fs::read_to_string(&quarantine_marker) {
            Ok(text) => text,
            Err(_) => String::new(),
        };
        let log_snippet = String::from_utf8_lossy(&log_buffer_cloned.lock().unwrap()).to_string();
        let capsule = crate::capsule::FailureCapsule::capture(
            job_id,
            project_id.unwrap_or(0),
            stage,
            999,
            format!("🚨 QUARANTINED: {}\n\nLogs:\n{}", reason, log_snippet),
            &format!("bash {}", script_path),
        );
        db.insert_evidence_capsule("quarantine_capsule", &capsule)
            .await?;
        db.append_event(
            "quarantine_capsule",
            project_id,
            Some(job_id),
            "jeryu-exec",
            &capsule.to_json(),
        )
        .await?;
        std::process::exit(1);
    }

    if !status.success() {
        let log_snippet = String::from_utf8_lossy(&log_buffer_cloned.lock().unwrap()).to_string();
        let capsule = crate::capsule::FailureCapsule::capture(
            job_id,
            project_id.unwrap_or(0),
            stage,
            exit_code,
            log_snippet,
            &format!("bash {}", script_path),
        );

        db.insert_evidence_capsule("failure_capsule", &capsule)
            .await?;
        db.append_event(
            "failure_capsule",
            project_id,
            Some(job_id),
            "jeryu-exec",
            &capsule.to_json(),
        )
        .await?;

        std::process::exit(exit_code);
    }

    let payload = serde_json::json!({
        "stage": stage,
        "script_path": script_path,
        "exit_code": exit_code,
    });

    db.append_event(
        "stage_execution",
        project_id,
        Some(job_id),
        "jeryu-exec",
        &payload.to_string(),
    )
    .await?;

    if stage == "build_script"
        && let Some(ref unit) = build_unit
    {
        let namespace = match unit.trust_tier {
            crate::policy::TrustTier::Trusted => "trusted",
            crate::policy::TrustTier::Untrusted => "untrusted",
            crate::policy::TrustTier::Quarantine => "quarantine",
        };
        let manifest = serde_json::json!({
            "unit_type": unit.unit_type,
            "environment_signature": unit.environment_signature,
            "scope": unit.scope,
            "job_id": job_id,
            "project_id": project_id,
            "created_at": chrono::Utc::now().to_rfc3339(),
        });
        let _ = db
            .upsert_action_cache(&unit.input_signature, &manifest.to_string(), namespace)
            .await;
        tracing::info!(
            "Populated action_cache for signature {} in namespace {}",
            unit.input_signature,
            namespace
        );

        let cas_dir = crate::config::data_dir()
            .join("cas")
            .join(&unit.input_signature);
        if let Ok(()) = tokio::fs::create_dir_all(&cas_dir).await {
            let payload_path = cas_dir.join("payload.tar.zst");
            let manifest_path = cas_dir.join("manifest.json");
            let archive_status = tokio::process::Command::new("tar")
                .arg("-I")
                .arg("zstd")
                .arg("-cf")
                .arg(&payload_path)
                .arg("-C")
                .arg(&sandbox_path)
                .arg(".")
                .status()
                .await;
            match archive_status {
                Ok(s) if s.success() => {
                    let _ = tokio::fs::write(&manifest_path, manifest.to_string()).await;
                    tracing::info!("Archived build output to CAS: {:?}", cas_dir);
                }
                _ => {
                    tracing::warn!(
                        "Failed to archive build output to CAS; future exact-hit will miss."
                    );
                }
            }
        }
    }

    Ok(())
}

use anyhow::{Context, Result};
use std::env;
use thiserror::Error;

/// Run a command with inherited stdio and bail with `error_message` on failure.
pub async fn run_status_check(
    cmd: &mut tokio::process::Command,
    error_message: &str,
) -> Result<()> {
    let status = cmd
        .stdin(std::process::Stdio::inherit())
        .stdout(std::process::Stdio::inherit())
        .stderr(std::process::Stdio::inherit())
        .status()
        .await
        .with_context(|| error_message.to_string())?;
    if !status.success() {
        anyhow::bail!("{} (exit code: {:?})", error_message, status.code());
    }
    Ok(())
}

/// Spawn a command, stream `stdin_data` into its stdin, and bail on failure.
pub async fn run_with_stdin(
    cmd: &mut tokio::process::Command,
    stdin_data: &[u8],
    error_message: &str,
) -> Result<()> {
    use tokio::io::AsyncWriteExt;
    let mut child = cmd
        .stdin(std::process::Stdio::piped())
        .stdout(std::process::Stdio::inherit())
        .stderr(std::process::Stdio::inherit())
        .spawn()
        .with_context(|| error_message.to_string())?;
    let mut stdin = child
        .stdin
        .take()
        .with_context(|| format!("{} (opening stdin)", error_message))?;
    stdin
        .write_all(stdin_data)
        .await
        .with_context(|| format!("{} (streaming stdin)", error_message))?;
    drop(stdin);
    let status = child
        .wait()
        .await
        .with_context(|| error_message.to_string())?;
    if !status.success() {
        anyhow::bail!("{} (exit code: {:?})", error_message, status.code());
    }
    Ok(())
}

#[derive(Debug, Error)]
pub enum ExecError {
    #[error("custom executor dependency bootstrap failed with status {0:?}")]
    BootstrapFailed(Option<i32>),
    #[error("failed to copy working directory to sandbox")]
    SandboxCopyFailed,
}

fn custom_executor_bootstrap_script() -> &'static str {
    r#"
set -eu
if ! command -v docker >/dev/null 2>&1; then
  (apt-get -qq update)>/dev/null
  DEBIAN_FRONTEND=noninteractive apt-get -y -qq install docker.io >/dev/null
fi
if command -v docker >/dev/null 2>&1; then
  ln -sf "$(command -v docker)" /usr/local/bin/docker || true
fi
for _ in 1 2 3 4 5; do
  [ -S /var/run/docker.sock ] && break
  sleep 1
done
[ -S /var/run/docker.sock ] || { echo "custom executor: docker socket is missing" >&2; exit 1; }
for _ in 1 2 3 4 5; do
  docker info >/dev/null 2>&1 && break
  sleep 1
done
docker info >/dev/null 2>&1 || { echo "custom executor: docker info failed against mounted socket" >&2; exit 1; }
"#
}

pub async fn ensure_custom_executor_tools() -> Result<()> {
    let status = tokio::process::Command::new("sh")
        .arg("-lc")
        .arg(custom_executor_bootstrap_script())
        .status()
        .await?;

    if !status.success() {
        return Err(ExecError::BootstrapFailed(status.code()).into());
    }

    Ok(())
}

pub fn env_string_or_default(name: &str, default: &str) -> String {
    match env::var(name) {
        Ok(value) => value,
        Err(_) => default.to_string(),
    }
}

pub fn env_i64_or_default(name: &str, default: i64) -> i64 {
    match env::var(name) {
        Ok(value) => match value.parse::<i64>() {
            Ok(parsed) => parsed,
            Err(_) => default,
        },
        Err(_) => default,
    }
}

pub fn env_bool_or_default(key: &str, default: bool) -> bool {
    match env::var(key) {
        Ok(value) => value.trim() != "0",
        Err(_) => default,
    }
}

pub fn fast_clone(src: &str, dst: &str) -> Result<()> {
    if !std::path::Path::new(src).exists() {
        return Ok(());
    }

    let _ = std::fs::remove_dir_all(dst);

    #[cfg(target_os = "macos")]
    {
        let status = std::process::Command::new("cp")
            .arg("-c")
            .arg("-r")
            .arg(src)
            .arg(dst)
            .status()?;
        if status.success() {
            return Ok(());
        }
    }

    #[cfg(target_os = "linux")]
    {
        let status = std::process::Command::new("cp")
            .arg("--reflink=auto")
            .arg("-r")
            .arg(src)
            .arg(dst)
            .status()?;
        if status.success() {
            return Ok(());
        }
    }

    let status = std::process::Command::new("cp")
        .arg("-r")
        .arg(src)
        .arg(dst)
        .status()?;

    if !status.success() {
        return Err(ExecError::SandboxCopyFailed.into());
    }

    Ok(())
}

