//! Owner: Pipeline Explain subsystem
//! Proof: `cargo nextest run -p jeryu -- explain`
//! Invariants: Explanations are derived from recorded state and do not mutate control-plane data.
use serde::{Deserialize, Serialize};

/// Indicates the outcome of a fetch or execution cache evaluation.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub enum CacheVerdict {
    /// The exact required output was found and fully restored without execution.
    HitExact,
    /// Partial reuse was achieved (e.g. some layers/crates cached, but others needed building).
    HitPartial {
        reused: Vec<String>,
        rebuilt: Vec<String>,
    },
    /// A rebuild was required. Includes the exact reasons *why* it was required.
    Miss { reasons: Vec<MissReason> },
    /// Caching was explicitly bypassed by user/system rule.
    Bypass { rule: String },
    /// Access to the cached object was denied due to trust, namespace, or quarantine policy.
    Denied { policy: String },
}

/// A structured reason why an action missed the cache.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub enum MissReason {
    InputDigestChanged {
        component: String,
        prior: String,
        new: String,
    },
    ToolchainChanged {
        field: String,
        prior: String,
        new: String,
    },
    EnvChanged {
        var: String,
    },
    LockfileChanged,
    BaseImageDigestChanged {
        tag: String,
        prior_digest: String,
        new_digest: String,
    },
    BuildScriptRerunTriggered {
        path: String,
    },
    ForcedEpochBump {
        scope: String,
        epoch: u64,
    },
    TrustNamespaceMismatch,
    SecretEpochChanged {
        id: String,
    },
    NotCacheable {
        reason: String,
    },
    NoLocalCache,
}

impl CacheVerdict {
    pub fn is_hit(&self) -> bool {
        matches!(self, Self::HitExact | Self::HitPartial { .. })
    }
}

//! Owner: Cache Gateway subsystem — Cargo registry proxy
//! Proof: `cargo nextest run -p jeryu -- gateway::cargo`
//! Invariants: Cargo registry caching never crosses trust namespaces or serves unverified content as trusted.
use super::{fetch_bytes_with_singleflight, singleflight::Singleflight};
use anyhow::Result;
use std::sync::Arc;

use reqwest::Client;

// We will use an Arc-wrapped Singleflight so we can clone it across concurrent actors.
#[derive(Clone)]
pub struct CargoAdapter {
    upstream_url: String,
    http_client: Client,
    // Coalesce fetches of the same crate name + version
    fetch_coalescer: Arc<Singleflight<Result<Vec<u8>, String>>>,
}

impl CargoAdapter {
    pub fn new(upstream_url: &str) -> Self {
        Self {
            upstream_url: upstream_url.to_string(),
            http_client: super::oci::build_http_client(30),
            fetch_coalescer: Arc::new(Singleflight::new()),
        }
    }

    /// Fetch a crate tarball, utilizing the singleflight mechanism to coalesce concurrent requests
    /// for the same crate and version.
    pub async fn fetch_crate(&self, name: &str, version: &str) -> Result<Vec<u8>> {
        let key = format!("{}:{}", name, version);
        let url = format!(
            "{}/api/v1/crates/{}/{}/download",
            self.upstream_url, name, version
        );
        fetch_bytes_with_singleflight(
            &self.fetch_coalescer,
            &key,
            "cargo crate",
            "cargo crate",
            || self.http_client.get(&url).send(),
        )
        .await
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use axum::{Router, routing::get};
    use std::sync::atomic::{AtomicUsize, Ordering};
    use tokio::net::TcpListener;

    #[tokio::test]
    async fn test_cargo_singleflight_coalescence_with_real_server() -> Result<()> {
        // Shared counter to verify how many times the upstream API was ACTUALLY hit
        let hit_count = Arc::new(AtomicUsize::new(0));
        let hit_count_clone = hit_count.clone();

        // Spin up a mock axum server on a random port
        let app = Router::new().route(
            "/api/v1/crates/test-crate/1.0.0/download",
            get(move || {
                let count = hit_count_clone.clone();
                async move {
                    count.fetch_add(1, Ordering::SeqCst);
                    // Add an artificial delay to guarantee we have overlapping concurrent requests
                    tokio::time::sleep(std::time::Duration::from_millis(50)).await;
                    "mock_tarball_content".to_string()
                }
            }),
        );
        let listener = match TcpListener::bind("127.0.0.1:0").await {
            Ok(listener) => listener,
            Err(err) if err.kind() == std::io::ErrorKind::PermissionDenied => {
                eprintln!("skipping local listener test: {err}");
                return Ok(());
            }
            Err(err) => return Err(err.into()),
        };
        let port = listener.local_addr()?.port();
        tokio::spawn(async move {
            axum::serve(listener, app).await.unwrap();
        });

        // Give the server a tiny moment to bind
        tokio::time::sleep(std::time::Duration::from_millis(10)).await;

        let upstream_url = format!("http://127.0.0.1:{}", port);
        let adapter = CargoAdapter::new(&upstream_url);

        // Spawn 20 concurrent fetch requests for the exact same crate
        let mut handlers = Vec::new();
        for _ in 0..20 {
            let ad = adapter.clone();
            handlers.push(tokio::spawn(async move {
                ad.fetch_crate("test-crate", "1.0.0").await
            }));
        }

        // Wait for all fetches to finish
        for handle in handlers {
            let result = handle.await??;
            assert_eq!(result, b"mock_tarball_content");
        }

        // If singleflight works correctly, out of 20 concurrent requests, exactly 1 should hit the server.
        let total_hits = hit_count.load(Ordering::SeqCst);
        assert_eq!(
            total_hits, 1,
            "Expected exactly 1 request to hit the server due to singleflight coalescence, but got {}",
            total_hits
        );
        Ok(())
    }
}

//! Owner: Cache Gateway subsystem — Git objects proxy
//! Proof: `cargo nextest run -p jeryu -- gateway::git`
//! Invariants: Git object reuse remains content-addressed and scoped to the requesting namespace.
use anyhow::Result;
use std::path::{Path, PathBuf};
use tokio::process::Command;

/// Git cache adapter for maintaining bare mirrors and performing fast reference clones.
#[derive(Clone)]
pub struct GitAdapter {
    cache_dir: PathBuf,
}

impl GitAdapter {
    pub fn new(cache_dir: PathBuf) -> Self {
        Self { cache_dir }
    }

    fn mirror_path(&self, repo_url: &str) -> PathBuf {
        // Sanitize URL for directory name
        let sanitized = repo_url
            .replace("https://", "")
            .replace("http://", "")
            .replace("git@", "")
            .replace([':', '/'], "_");
        self.cache_dir.join(format!("{}.git", sanitized))
    }

    /// Refresh or initialize a bare mirror for a repository.
    pub async fn refresh_mirror(&self, repo_url: &str) -> Result<PathBuf> {
        let mirror_dir = self.mirror_path(repo_url);

        if mirror_dir.exists() {
            tracing::info!("Updating existing Git mirror for {}", repo_url);
            let status = Command::new("git")
                .arg("--git-dir")
                .arg(&mirror_dir)
                .arg("fetch")
                .arg("--prune")
                .arg("origin")
                .arg("+refs/heads/*:refs/heads/*")
                .status()
                .await?;

            if !status.success() {
                anyhow::bail!("Failed to fetch mirror: {}", status);
            }
        } else {
            tracing::info!("Initializing new Git mirror for {}", repo_url);
            std::fs::create_dir_all(&self.cache_dir)?;
            let status = Command::new("git")
                .arg("clone")
                .arg("--bare")
                .arg(repo_url)
                .arg(&mirror_dir)
                .status()
                .await?;

            if !status.success() {
                anyhow::bail!("Failed to clone mirror: {}", status);
            }
        }

        Ok(mirror_dir)
    }

    /// Fast clone into a target directory using `--reference-if-able`.
    pub async fn reference_clone(&self, repo_url: &str, target_dir: &Path) -> Result<()> {
        let mirror_dir = self.refresh_mirror(repo_url).await?;

        tracing::info!("Performing reference clone to {}", target_dir.display());
        let status = Command::new("git")
            .arg("clone")
            .arg("--reference-if-able")
            .arg(&mirror_dir)
            .arg("--dissociate") // Important for untrusted sandboxes so they don't corrupt the mirror
            .arg(repo_url)
            .arg(target_dir)
            .status()
            .await?;

        if !status.success() {
            anyhow::bail!("Failed reference clone: {}", status);
        }

        Ok(())
    }
}

//! Owner: Cache Gateway subsystem (module root)
//! Proof: `cargo nextest run -p jeryu -- gateway`
//! Invariants: Gateway modules preserve namespace isolation, singleflight behavior, and upstream recovery semantics.
pub mod cargo;
pub mod git;
pub mod npm;
pub mod oci;
pub mod singleflight;

use anyhow::Result;
use singleflight::{Singleflight, SingleflightGuard};
use std::{future::Future, sync::Arc};

/// Coalesce concurrent byte-fetch requests for `key` through `fetch_coalescer`.
///
/// Joiners wait on the broadcast channel; the elected fetcher invokes `request`
/// and broadcasts the resulting bytes (or error string) to waiters. A
/// `SingleflightGuard` ensures the singleflight slot is released even if the
/// fetcher panics.
pub(crate) async fn fetch_bytes_with_singleflight<F, Fut>(
    fetch_coalescer: &Arc<Singleflight<Result<Vec<u8>, String>>>,
    key: &str,
    join_label: &'static str,
    start_label: &'static str,
    request: F,
) -> Result<Vec<u8>>
where
    F: FnOnce() -> Fut,
    Fut: Future<Output = Result<reqwest::Response, reqwest::Error>>,
{
    if let Some(mut rx) = fetch_coalescer.join_or_start(key) {
        tracing::info!(
            "Singleflight: joining active fetch for {} {}",
            join_label,
            key
        );
        match rx.recv().await {
            Ok(Ok(bytes)) => return Ok(bytes),
            Ok(Err(e)) => anyhow::bail!("Coalesced {} fetch failed: {}", join_label, e),
            Err(_) => anyhow::bail!("Fetch coalescer sender dropped for {}", key),
        }
    }

    tracing::info!("Singleflight: initiating fetch for {} {}", start_label, key);
    let guard = SingleflightGuard::new(fetch_coalescer, key);
    let resp_result = request().await;

    let result = match resp_result {
        Ok(resp) if resp.status().is_success() => {
            resp.bytes().await.map(|b| b.to_vec()).map_err(|e| e.into())
        }
        Ok(resp) => Err(anyhow::anyhow!("HTTP error: {}", resp.status())),
        Err(e) => Err(e.into()),
    };

    match &result {
        Ok(bytes) => guard.complete(Ok(bytes.clone())),
        Err(e) => guard.complete(Err(e.to_string())),
    }

    result
}

