//! Owner: Git repository state snapshot
//! Proof: `cargo test -p jeryu -- git_snapshot`
//! Invariants: Snapshots are read-only and resilient to non-repository paths.

use anyhow::Result;
use git2::{Repository, Status, StatusOptions};
use serde::{Deserialize, Serialize};
use std::path::Path;

#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct GitSnapshot {
    pub repo_root: Option<String>,
    pub head: Option<String>,
    pub branch: Option<String>,
    pub dirty: Option<bool>,
}

impl GitSnapshot {
    pub fn empty() -> Self {
        Self::default()
    }
}

pub fn capture(cwd: &Path) -> Result<GitSnapshot> {
    let repo = match Repository::discover(cwd) {
        Ok(repo) => repo,
        Err(_) => return Ok(GitSnapshot::empty()),
    };

    let repo_root = repo.workdir().map(|path| path.display().to_string());
    let head = repo
        .head()
        .ok()
        .and_then(|reference| reference.target())
        .map(|oid| oid.to_string());
    let branch = repo
        .head()
        .ok()
        .and_then(|reference| reference.shorthand().map(str::to_string));

    let mut options = StatusOptions::new();
    options.include_untracked(true).recurse_untracked_dirs(true);
    let dirty = repo.statuses(Some(&mut options)).ok().map(|statuses| {
        statuses
            .iter()
            .any(|entry| entry.status() != Status::CURRENT)
    });

    Ok(GitSnapshot {
        repo_root,
        head,
        branch,
        dirty,
    })
}

pub fn snapshot_or_empty(cwd: &Path) -> GitSnapshot {
    match capture(cwd) {
        Ok(snapshot) => snapshot,
        Err(_) => GitSnapshot::empty(),
    }
}

//! Owner: Git event persistence
//! Proof: `cargo test -p jeryu -- git_store`
//! Invariants: All SQL remains centralized in `state::Db` methods.

use anyhow::Result;
use chrono::Utc;

use crate::git::event::GitCommandEvent;
use crate::git::invocation::GitInvocation;
use crate::git::mirror::PushMirrorPlan;
use crate::git::snapshot::GitSnapshot;
use crate::state::Db;
use crate::state::GitMirrorJob;

pub async fn store_git_event(db: &Db, event: &GitCommandEvent) -> Result<i64> {
    db.record_git_command_event(event).await
}

pub async fn store_git_side_effects(
    db: &Db,
    invocation: &GitInvocation,
    before: &GitSnapshot,
    after: Option<&GitSnapshot>,
    mirror_status: &str,
    mirror_plan: Option<&PushMirrorPlan>,
    sidecar_status: &mut String,
) {
    if let Some(plan) = mirror_plan {
        let branch_name = match plan.ref_name.as_ref() {
            Some(name) => name.clone(),
            None => "HEAD".to_string(),
        };
        let job = GitMirrorJob {
            id: 0,
            request_id: invocation.request_id.clone(),
            remote_name: plan.remote_name.clone(),
            branch_name: Some(branch_name),
            status: mirror_status.to_string(),
            detail: plan.git_args.join(" "),
            created_at: Utc::now().to_rfc3339(),
        };
        if let Err(err) = db.record_git_mirror_job(&job).await {
            tracing::warn!(error = %err, request_id = %invocation.request_id, "failed to record git mirror job");
            *sidecar_status = "db_write_failed".to_string();
        }
    }

    if let Some(after) = after {
        let changed = before.head != after.head || before.branch != after.branch;
        if changed || invocation.is_push() {
            let ref_name = match after.branch.clone() {
                Some(name) => name,
                None => match before.branch.clone() {
                    Some(name) => name,
                    None => "HEAD".to_string(),
                },
            };
            let status = if invocation.is_push() {
                mirror_status.to_string()
            } else {
                "observed".to_string()
            };
            if let Err(err) = db
                .record_git_ref_change(
                    invocation.request_id.clone(),
                    ref_name,
                    before.head.clone(),
                    after.head.clone(),
                    status,
                    Utc::now().to_rfc3339(),
                )
                .await
            {
                tracing::warn!(error = %err, request_id = %invocation.request_id, "failed to record git ref change");
                *sidecar_status = "db_write_failed".to_string();
            }
        }
    }
}

//! Owner: System Git resolution
//! Proof: `cargo test -p jeryu -- git_system`
//! Invariants: The resolver never falls back to a hard-coded `/usr/bin/git`.

use anyhow::{Context, Result};
use std::path::{Path, PathBuf};
use std::process::{Command, Output, Stdio};

#[derive(Debug, Clone)]
pub struct SystemGit {
    pub path: PathBuf,
}

impl SystemGit {
    pub fn resolve() -> Result<Self> {
        if let Some(path) = std::env::var("JERYU_SYSTEM_GIT")
            .ok()
            .filter(|path| !path_is_recursive_bridge(Path::new(path)))
        {
            return Ok(Self {
                path: PathBuf::from(path),
            });
        }

        if let Some(path) = crate::settings::get()
            .git
            .system_git
            .clone()
            .filter(|path| !path_is_recursive_bridge(Path::new(path)))
        {
            return Ok(Self {
                path: PathBuf::from(path),
            });
        }

        if let Some(path) = find_git_on_path() {
            return Ok(Self {
                path: PathBuf::from(path),
            });
        }

        Err(anyhow::anyhow!("unable to resolve system git binary"))
    }

    pub fn command(&self, cwd: &Path, args: &[&str]) -> Command {
        let mut command = Command::new(&self.path);
        command.current_dir(cwd);
        command.args(args);
        command.env("JERYU_GIT_RECURSION_GUARD", "1");
        command.stdin(Stdio::inherit());
        command.stdout(Stdio::inherit());
        command.stderr(Stdio::inherit());
        command
    }

    pub fn output(&self, cwd: &Path, args: &[&str]) -> Result<Output> {
        self.command(cwd, args)
            .output()
            .with_context(|| format!("running git {:?}", args))
    }

    pub fn status(&self, cwd: &Path, args: &[&str]) -> Result<std::process::ExitStatus> {
        self.command(cwd, args)
            .status()
            .with_context(|| format!("running git {:?}", args))
    }
}

fn find_git_on_path() -> Option<String> {
    let path = std::env::var_os("PATH")?;
    for dir in std::env::split_paths(&path) {
        let candidate = dir.join("git");
        if candidate.is_file() && !path_is_recursive_bridge(&candidate) {
            return Some(candidate.display().to_string());
        }
    }
    None
}

fn path_is_recursive_bridge(path: &Path) -> bool {
    if path_matches_current_exe(path) {
        return true;
    }

    std::fs::read_to_string(path)
        .map(|script| script.contains("jeryu git") || script.contains("jeryu\" \"git"))
        .unwrap_or(false)
}

fn path_matches_current_exe(path: &Path) -> bool {
    let Ok(current) = std::env::current_exe() else {
        return false;
    };
    let current = match std::fs::canonicalize(current) {
        Ok(value) => value,
        Err(_) => PathBuf::new(),
    };
    let candidate = match std::fs::canonicalize(path) {
        Ok(value) => value,
        Err(_) => path.to_path_buf(),
    };
    !current.as_os_str().is_empty() && current == candidate
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::fs;
    use std::os::unix::fs::PermissionsExt;
    use std::sync::{LazyLock, Mutex};

    static ENV_LOCK: LazyLock<Mutex<()>> = LazyLock::new(|| Mutex::new(()));

    fn set_env(key: &str, value: impl AsRef<std::ffi::OsStr>) {
        // SAFETY: tests isolate the process environment with a mutex.
        unsafe {
            std::env::set_var(key, value);
        }
    }

    fn remove_env(key: &str) {
        // SAFETY: tests isolate the process environment with a mutex.
        unsafe {
            std::env::remove_var(key);
        }
    }

    fn write_executable(path: &Path, body: &str) {
        fs::write(path, body).unwrap();
        let mut perms = fs::metadata(path).unwrap().permissions();
        perms.set_mode(0o755);
        fs::set_permissions(path, perms).unwrap();
    }

    #[test]
    fn path_lookup_is_optional() {
        let _ = find_git_on_path();
    }

    #[test]
    fn env_resolution_is_not_globally_cached() {
        let _guard = ENV_LOCK.lock().unwrap();
        let dir = tempfile::tempdir().unwrap();
        let first = dir.path().join("git-one");
        let second = dir.path().join("git-two");
        write_executable(&first, "#!/usr/bin/env sh\nexit 0\n");
        write_executable(&second, "#!/usr/bin/env sh\nexit 0\n");

        set_env("JERYU_SYSTEM_GIT", &first);
        let resolved_first = SystemGit::resolve().unwrap();
        set_env("JERYU_SYSTEM_GIT", &second);
        let resolved_second = SystemGit::resolve().unwrap();
        remove_env("JERYU_SYSTEM_GIT");

        assert_eq!(resolved_first.path, first);
        assert_eq!(resolved_second.path, second);
    }

    #[test]
    fn guarded_path_lookup_skips_jeryu_git_bridge() {
        let _guard = ENV_LOCK.lock().unwrap();
        let dir = tempfile::tempdir().unwrap();
        let bridge_dir = dir.path().join("bridge");
        let real_dir = dir.path().join("real");
        fs::create_dir_all(&bridge_dir).unwrap();
        fs::create_dir_all(&real_dir).unwrap();
        let bridge = bridge_dir.join("git");
        let real = real_dir.join("git");
        write_executable(&bridge, "#!/usr/bin/env sh\nexec jeryu git \"$@\"\n");
        write_executable(&real, "#!/usr/bin/env sh\nexit 0\n");

        let original_path = std::env::var_os("PATH");
        set_env(
            "PATH",
            std::env::join_paths([bridge_dir, real_dir]).unwrap(),
        );
        set_env("JERYU_GIT_RECURSION_GUARD", "1");
        remove_env("JERYU_SYSTEM_GIT");

        let resolved = SystemGit::resolve().unwrap();

        match original_path {
            Some(path) => set_env("PATH", path),
            None => remove_env("PATH"),
        }
        remove_env("JERYU_GIT_RECURSION_GUARD");

        assert_eq!(resolved.path, real);
    }
}

