    pub async fn list_issues_by_labels(
        &self,
        project_id: i64,
        labels: &[&str],
        state: Option<&str>,
    ) -> Result<Vec<Issue>> {
        let mut params = vec!["per_page=100".to_string()];
        if !labels.is_empty() {
            params.push(format!("labels={}", urlencoding::encode(&labels.join(","))));
        }
        if let Some(state) = state {
