    ) -> Result<()> {
        const ACTION: &str = "create";
        self.commit_file(
            project_id,
            branch,
            file_path,
            content,
            commit_message,
            ACTION,
        )
        .await
    }

    pub async fn update_file(
        &self,
        project_id: i64,
        branch: &str,
        file_path: &str,
        content: &str,
        commit_message: &str,
    ) -> Result<()> {
        self.commit_file(
            project_id,
            branch,
            file_path,
            content,
            commit_message,
            "update",
        )
        .await
    }

    pub async fn commit_file(
        &self,
        project_id: i64,
        branch: &str,
        file_path: &str,
        content: &str,
        commit_message: &str,
        action: &str,
    ) -> Result<()> {
        self.commit_actions(
            project_id,
            branch,
            commit_message,
            &[(action, file_path, content)],
        )
        .await
    }

    pub async fn update_files(
        &self,
        project_id: i64,
        branch: &str,
        commit_message: &str,
        files: &[(&str, &str)],
    ) -> Result<()> {
        let actions: Vec<(&str, &str, &str)> =
            files.iter().map(|(p, c)| ("update", *p, *c)).collect();
        self.commit_actions(project_id, branch, commit_message, &actions)
            .await
    }

    pub async fn commit_actions(
        &self,
        project_id: i64,
        branch: &str,
        commit_message: &str,
        files: &[(&str, &str, &str)],
    ) -> Result<()> {
        self.commit_actions_with_sha(project_id, branch, commit_message, files)
            .await
            .map(|_| ())
    }

    /// Commit a batch of file actions and return the GitLab commit SHA.
    pub async fn commit_actions_with_sha(
        &self,
        project_id: i64,
        branch: &str,
        commit_message: &str,
        files: &[(&str, &str, &str)],
    ) -> Result<String> {
        let actions: Vec<CommitAction> = files
            .iter()
            .map(|(action, path, content)| CommitAction {
                action,
                file_path: path,
                content,
            })
            .collect();

        let commit: CreateCommitResp = self
            .api_post_json(
                self.api_url(&format!("/projects/{}/repository/commits", project_id)),
                &CreateCommitReq {
                    branch,
                    commit_message,
                    actions,
                },
            )
            .await?;
        info!(
            project_id,
            branch,
            commit_sha = commit.id,
            files_count = files.len(),
            "committed files"
        );
        Ok(commit.id)
    }
}

