//! Owner: Supply-Chain Detonation / Honey Token Detection
//! Proof: `cargo test -p jeryu -- honeypot`
//! Invariants: Honey tokens are seeded before untrusted workload starts; Tripwire kills the target process on any touch; never remove paths from the watch list without an AER

use notify::{EventKind, RecursiveMode, Watcher};
use std::fs;
use std::path::{Path, PathBuf};
use tracing::{error, info};

/// Seeds the sandbox with honey tokens.
/// Returns the list of files to watch.
pub fn seed_sandbox(sandbox_dir: &str) -> Vec<PathBuf> {
    let mut tokens = Vec::new();
    let base = Path::new(sandbox_dir);

    // 1. Decoy AWS marker
    let aws_dir = base.join(".aws");
    if fs::create_dir_all(&aws_dir).is_ok() {
        let creds = aws_dir.join("credentials");
        let fake_aws = "aws-honey-marker";
        if fs::write(&creds, fake_aws).is_ok() {
            tokens.push(creds);
        }
    }

    // 2. Decoy NPM marker
    let npmrc = base.join(".npmrc");
    let fake_npm = "npm-honey-marker";
    if fs::write(&npmrc, fake_npm).is_ok() {
        tokens.push(npmrc);
    }

    info!(
        "Seeded {} honey tokens in sandbox {}",
        tokens.len(),
        sandbox_dir
    );
    tokens
}

/// Retrieves the predefined honey token paths to monitor.
pub fn get_tokens(sandbox_dir: &str) -> Vec<PathBuf> {
    let base = Path::new(sandbox_dir);
    vec![base.join(".aws").join("credentials"), base.join(".npmrc")]
}

/// A wrapper struct to keep the notify watcher alive
pub struct Tripwire {
    _watcher: notify::RecommendedWatcher,
}

/// Starts watching the honey tokens and kills the target process if touched.
pub fn start_tripwire(
    pid: u32,
    tokens: Vec<PathBuf>,
    sandbox_dir: String,
) -> anyhow::Result<Tripwire> {
    let (tx, rx) = std::sync::mpsc::channel();

    let mut watcher = notify::recommended_watcher(move |res: notify::Result<notify::Event>| {
        if let Ok(event) = res {
            // Check for any access or modify events
            if matches!(event.kind, EventKind::Access(_) | EventKind::Modify(_)) {
                // Ignore events on paths we don't care about, though we only subscribed to tokens
                tx.send(event.paths).ok();
            }
        }
    })?;

    for token in &tokens {
        if let Err(e) = watcher.watch(token, RecursiveMode::NonRecursive) {
            tracing::warn!("Failed to watch honey token {:?}: {}", token, e);
        }
    }

    // Spawn the active killer thread
    std::thread::spawn(move || {
        if let Ok(tripped_paths) = rx.recv() {
            error!(
                "🚨 DETONATION LANE TRIGGERED 🚨 Malicious action detected on honey tokens: {:?}",
                tripped_paths
            );

            // Force kill the pipeline process
            let _ = std::process::Command::new("kill")
                .arg("-9")
                .arg(pid.to_string())
                .status();

            // Drop a quarantine marker so `cleanup` knows to skip sandbox destruction
            let marker = Path::new(&sandbox_dir).join(".jeryu_quarantine");
            let _ = fs::write(
                &marker,
                format!("Quarantined due to touching: {:?}", tripped_paths),
            );
        }
    });

    Ok(Tripwire { _watcher: watcher })
}

use anyhow::{Context, Result, bail};
use std::fs;
use std::path::PathBuf;
use tokio::process::Command;

use crate::exec::run_status_check;

pub async fn install_gc_timer(allow_sudo: bool) -> Result<i32> {
    let unit_dir = PathBuf::from("/etc/systemd/system");
    let service_src = repo_file("ops/ci/jeryu-gc.service");
    let timer_src = repo_file("ops/ci/jeryu-gc.timer");
    let service_dst = unit_dir.join("jeryu-gc.service");
    let timer_dst = unit_dir.join("jeryu-gc.timer");

    if !allow_sudo && !is_root() {
        bail!("install-gc-timer requires --allow-sudo unless run as root");
    }

    if is_root() {
        fs::copy(&service_src, &service_dst)
            .with_context(|| format!("copying {}", service_dst.display()))?;
        fs::copy(&timer_src, &timer_dst)
            .with_context(|| format!("copying {}", timer_dst.display()))?;
    } else {
        run_sudo_copy(&service_src, &service_dst).await?;
        run_sudo_copy(&timer_src, &timer_dst).await?;
    }

    run_systemctl(&["daemon-reload"]).await?;
    run_systemctl(&["enable", "--now", "jeryu-gc.timer"]).await?;
    run_systemctl(&["status", "jeryu-gc.timer", "--no-pager"]).await?;
    Ok(0)
}

fn repo_file(rel: &str) -> PathBuf {
    match std::env::current_dir() {
        Ok(mut dir) => loop {
            let candidate = dir.join(rel);
            if candidate.exists() {
                return candidate;
            }
            if !dir.pop() {
                return PathBuf::from(rel);
            }
        },
        Err(_) => PathBuf::from(rel),
    }
}

fn is_root() -> bool {
    // SAFETY: geteuid is a pure libc query with no aliasing or lifetime concerns.
    unsafe { libc::geteuid() == 0 }
}

async fn run_sudo_copy(src: &PathBuf, dst: &PathBuf) -> Result<()> {
    let mut cmd = Command::new("sudo");
    cmd.args(["install", "-m", "0644"]).arg(src).arg(dst);
    run_status_check(&mut cmd, "copying systemd unit with sudo").await
}

async fn run_systemctl(args: &[&str]) -> Result<()> {
    let mut cmd = Command::new("systemctl");
    cmd.args(args);
    run_status_check(&mut cmd, "running systemctl").await
}

//! Owner: Change Impact Analysis
//! Proof: `cargo test -p jeryu -- impact`
//! Invariants: Conservative widening on empty diff or broad config change; docs-only skips heavy validation

use anyhow::{Context, Result};
use git2::{Cred, DiffOptions, FetchOptions, Oid, RemoteCallbacks, Repository, build::RepoBuilder};

use crate::decision::{ImpactDecision, ImpactLane};
use crate::gitlab_client::GitlabClient;

pub async fn plan_for_push(
    client: &GitlabClient,
    project_id: i64,
    before: &str,
    after: &str,
) -> Result<ImpactDecision> {
    if before.chars().all(|c| c == '0') {
        return Ok(ImpactDecision {
            project_id,
            before: before.to_string(),
            after: after.to_string(),
            affected_paths: Vec::new(),
            selected_lanes: vec![ImpactLane::Full],
            reason_codes: vec!["new_branch_push".to_string(), "widened_to_full".to_string()],
            widened_to_full: true,
        });
    }

    let changed_paths = changed_paths_from_repo(client, project_id, before, after).await?;
    Ok(plan_from_changed_paths(
        project_id,
        before,
        after,
        changed_paths,
    ))
}

pub fn plan_from_changed_paths(
    project_id: i64,
    before: &str,
    after: &str,
    changed_paths: Vec<String>,
) -> ImpactDecision {
    let mut lanes = Vec::new();
    let mut reasons = Vec::new();
    let mut widened_to_full = false;

    if changed_paths.is_empty() {
        lanes.push(ImpactLane::Full);
        reasons.push("empty_diff".to_string());
        reasons.push("widened_to_full".to_string());
        widened_to_full = true;
    } else {
        let touches_src = changed_paths
            .iter()
            .any(|p| p.starts_with("src/") && p.ends_with(".rs"));
        let touches_tests = changed_paths.iter().any(|p| p.starts_with("tests/"));
        let touches_broad = changed_paths.iter().any(|p| {
            p.starts_with(".github/")
                || p.contains(".gitlab-ci")
                || p == "Cargo.toml"
                || p == "Cargo.lock"
                || p == "rust-toolchain.toml"
                || p.starts_with(".cargo/")
        });
        let touches_docs_only = !touches_src
            && !touches_tests
            && !touches_broad
            && changed_paths.iter().all(|p| {
                p.ends_with(".md") || p.starts_with("docs/") || p == "LICENSE" || p == ".gitignore"
            });

        if touches_broad {
            lanes.push(ImpactLane::Full);
            reasons.push("broad_config_change".to_string());
            widened_to_full = true;
        } else if touches_docs_only {
            lanes.push(ImpactLane::DocsOnly);
            reasons.push("docs_only_change".to_string());
        } else {
            if touches_src {
                lanes.push(ImpactLane::Unit);
                reasons.push("changed_src_rust".to_string());
            }
            if touches_tests {
                lanes.push(ImpactLane::Integration);
                reasons.push("changed_tests".to_string());
            }
            if lanes.is_empty() {
                lanes.push(ImpactLane::Full);
                reasons.push("unknown_file_change".to_string());
                reasons.push("widened_to_full".to_string());
                widened_to_full = true;
            }
        }
    }

    lanes.sort_by_key(|lane| match lane {
        ImpactLane::Full => 0,
        ImpactLane::Unit => 1,
        ImpactLane::Integration => 2,
        ImpactLane::DocsOnly => 3,
    });
    lanes.dedup();

    ImpactDecision {
        project_id,
        before: before.to_string(),
        after: after.to_string(),
        affected_paths: changed_paths,
        selected_lanes: lanes,
        reason_codes: reasons,
        widened_to_full,
    }
}

fn build_dynamic_yaml(plan: &ImpactDecision) -> String {
    if plan.selected_lanes.contains(&ImpactLane::Full) {
        return "image: rust:latest\n\nfull-validation:\n  script:\n    - cargo test --all-targets --all-features\n".to_string();
    }

    let mut jobs = String::from("image: rust:latest\n\n");
    if plan.selected_lanes.contains(&ImpactLane::Unit) {
        jobs.push_str("unit-validation:\n  script:\n    - cargo test --lib --bins\n\n");
    }
    if plan.selected_lanes.contains(&ImpactLane::Integration) {
        jobs.push_str("integration-validation:\n  script:\n    - cargo test --tests\n\n");
    }
    if plan.selected_lanes.contains(&ImpactLane::DocsOnly) {
        jobs.push_str("docs-validation:\n  script:\n    - echo 'Docs-only change detected; no heavy validation required.'\n");
    }
    jobs
}

pub fn render_plan_payload(plan: &ImpactDecision) -> serde_json::Value {
    serde_json::json!({
        "project_id": plan.project_id,
        "before": plan.before,
        "after": plan.after,
        "affected_paths": plan.affected_paths,
        "selected_lanes": plan.selected_lanes,
        "reason_codes": plan.reason_codes,
        "widened_to_full": plan.widened_to_full,
        "generated_ci_yaml": build_dynamic_yaml(plan),
    })
}

async fn changed_paths_from_repo(
    client: &GitlabClient,
    project_id: i64,
    before: &str,
    after: &str,
) -> Result<Vec<String>> {
    let project = client.get_project(project_id).await?;
    let clone_dir = std::env::temp_dir().join(format!("jeryu-impact-{}", uuid::Uuid::new_v4()));
    let repo = clone_project(client, &project.web_url, &clone_dir)
        .with_context(|| format!("cloning project {} for impact analysis", project.web_url))?;

    let before_commit = repo.find_commit(Oid::from_str(before)?)?;
    let after_commit = repo.find_commit(Oid::from_str(after)?)?;
    let before_tree = before_commit.tree()?;
    let after_tree = after_commit.tree()?;
    let mut diff_opts = DiffOptions::new();
    let diff =
        repo.diff_tree_to_tree(Some(&before_tree), Some(&after_tree), Some(&mut diff_opts))?;

    let mut changed_paths = Vec::new();
    diff.foreach(
        &mut |delta, _| {
            if let Some(path) = delta.new_file().path().or(delta.old_file().path()) {
                changed_paths.push(path.to_string_lossy().to_string());
            }
            true
        },
        None,
        None,
        None,
    )?;

    let _ = std::fs::remove_dir_all(&clone_dir);
    Ok(changed_paths)
}

fn clone_project(
    client: &GitlabClient,
    web_url: &str,
    clone_dir: &std::path::Path,
) -> Result<Repository> {
    let mut callbacks = RemoteCallbacks::new();
    let pat = match client.pat_value_for_clone() {
        Some(value) => value,
        None => String::new(),
    };
    callbacks.credentials(move |_url, _username, _types| Cred::userpass_plaintext("oauth2", &pat));

    let mut fetch_options = FetchOptions::new();
    fetch_options.remote_callbacks(callbacks);

    let mut builder = RepoBuilder::new();
    builder.fetch_options(fetch_options);
    builder
        .clone(&format!("{}.git", web_url), clone_dir)
        .map_err(Into::into)
}

