            "export BEFORE=1\n",
            "# >>> jeryu path >>>\n",
            "export PATH=\"/tmp/jeryu:$PATH\"\n",
            "# <<< jeryu path <<<\n",
            "alias gs='git status'\n",
        );
        let (updated, removed) = install_runtime::strip_jeryu_path_block(text);
        assert!(removed);
        assert_eq!(updated, "export BEFORE=1\nalias gs='git status'\n");
    }

