/// Get recent log lines from a runner manager container.
pub async fn tail_manager(
    db: &Db,
    docker: &DockerCtl,
    manager_id: &str,
    lines: usize,
) -> Result<Vec<String>> {
    let manager = match db.get_manager(manager_id).await? {
        Some(manager) => manager,
        None => return Err(anyhow::anyhow!("manager '{}' not found", manager_id)),
    };

    let logs = docker
        .manager_logs(&manager.docker_container_id, lines)
        .await?;

    Ok(logs)
}

