//! Owner: CLI dispatcher — no business logic
//! Proof: `cargo check -p jeryu --message-format=json`
//! Invariants: Main only initializes runtime state and delegates behavior to dispatch/modules.
//! jeryu — Headless GitLab with Rust god-mode control.
//!
//! A single binary to bootstrap, operate, and extend a local GitLab
//! instance with full programmatic control over runners, CI/CD,
//! issues, and autonomous agents.
//!
//! Structure:
//!   cli.rs      — clap struct/enum definitions (pure data)
//!   dispatch.rs — command→module wiring (no business logic)
//!   lib.rs      — domain modules

#![allow(dead_code)]

pub mod cli;
pub mod commands;
pub mod dispatch;

use anyhow::Result;
use clap::Parser;
use tracing_subscriber::EnvFilter;

#[tokio::main]
async fn main() -> Result<()> {
    let cli = cli::Cli::parse();
    let is_tui = matches!(cli.command, cli::Commands::Tui { .. });

    if !is_tui {
        let env_filter = match EnvFilter::try_from_default_env() {
            Ok(filter) => filter,
            Err(_) => EnvFilter::new("info"),
        };
        tracing_subscriber::fmt()
            .with_env_filter(env_filter)
            .with_target(false)
            .init();
    }

    witness_rt::register_cells(vec![
        witness_rt::CellRegistration {
            id: "cache".into(),
            purpose: "LRU manager cache GC and eviction".into(),
            owned_paths: vec!["src/cache.rs".into(), "src/cache_brain.rs".into(), "src/cache_proxy.rs".into()],
            invariants: vec!["root disk pressure is classified from free bytes; warning below 80GiB and emergency below 40GiB".into()],
            local_commands: vec!["cargo nextest run -p jeryu --lib -E 'test(/cache/)'".into()],
            escalate_commands: vec![],
            hints: vec![],
        },
        witness_rt::CellRegistration {
            id: "engine".into(),
            purpose: "Health loop and GC orchestration".into(),
            owned_paths: vec!["src/engine.rs".into()],
            invariants: vec!["emergency tier triggers below 40GiB free space, pass limit is 20 with stall detection".into()],
            local_commands: vec!["cargo nextest run -p jeryu --lib -E 'test(/engine/)'".into()],
            escalate_commands: vec![],
            hints: vec![],
        },
        witness_rt::CellRegistration {
            id: "reclaim".into(),
            purpose: "Artifact and Docker volume cleanup".into(),
            owned_paths: vec!["src/reclaim.rs".into()],
            invariants: vec!["is_emergency forces 30m artifact age threshold".into()],
            local_commands: vec!["cargo nextest run -p jeryu --lib -E 'test(/reclaim/)'".into()],
            escalate_commands: vec![],
            hints: vec![],
        },
        witness_rt::CellRegistration {
            id: "state".into(),
            purpose: "Postgres-primary state schema and accessor boundary".into(),
            owned_paths: vec!["src/state.rs".into()],
            invariants: vec!["all mutations go through state::Db methods or backend-neutral state helpers".into()],
            local_commands: vec!["cargo nextest run -p jeryu --lib -E 'test(/state/)'".into()],
            escalate_commands: vec![],
            hints: vec![],
        },
        witness_rt::CellRegistration {
            id: "release".into(),
            purpose: "Tag negotiation, artifact publication, and rollback".into(),
            owned_paths: vec!["src/release.rs".into()],
            invariants: vec!["release pipeline is a transaction — partial completion triggers rollback".into()],
            local_commands: vec!["cargo nextest run -p jeryu --lib -E 'test(/release/)'".into()],
            escalate_commands: vec![],
            hints: vec![],
        },
        witness_rt::CellRegistration {
            id: "test-intel".into(),
            purpose: "Smart test selection (VTI)".into(),
            owned_paths: vec!["src/test_intel/".into()],
            invariants: vec!["TestPlan selected_tests with kind=unit_filter contain full nextest -E command strings".into()],
            local_commands: vec!["cargo nextest run -p jeryu --lib -E 'test(/test_intel/)'".into()],
            escalate_commands: vec![],
            hints: vec![],
        },
    ]);
    witness_rt::install_panic_hook(witness_rt::HookConfig::new("."));

    // Load ~/.jeryu/settings.json (creates with defaults on first run).
    jeryu::settings::init()?;

    let exit_code = if let Some(subcmd) = cli::exec_subcommand(&cli.command) {
        commands::exec::execute_exec_commands(subcmd).await?
    } else {
        dispatch::run(cli).await?
    };
    if exit_code != 0 {
        std::process::exit(exit_code);
    }
    Ok(())
}

//! Owner: MCP adapter for external coding agents
//! Proof: `cargo check -p jeryu --message-format=json` and `cargo test -p jeryu --lib mcp`
//! Invariants: MCP request handling must remain a thin adapter over the capability policy;
//!             it must not bypass grant checks, evidence handling, or merge/release gates.

use anyhow::{Result, bail};
use serde::Deserialize;
use serde_json::Value;
use tokio::io::{AsyncBufReadExt, AsyncWriteExt, BufReader, BufWriter};

use super::{MCP_PROTOCOL_VERSION, TOOL_PREFIX};

#[derive(Debug, Clone, Deserialize)]
struct Implementation {
    name: String,
    version: Option<String>,
}

#[derive(Debug, Clone, Deserialize)]
struct InitializeRequestParams {
    #[serde(rename = "protocolVersion")]
    protocol_version: String,
    #[serde(rename = "clientCapabilities", default)]
    _client_capabilities: Option<Value>,
    #[serde(rename = "clientInfo")]
    client_info: Option<Implementation>,
}

#[derive(Debug, Clone, Deserialize)]
struct ListToolsRequestParams {
    #[serde(default)]
    #[serde(rename = "cursor")]
    _cursor: Option<String>,
}

#[derive(Debug, Clone, Deserialize)]
struct CallToolRequestParams {
    name: String,
    #[serde(default, rename = "arguments")]
    arguments: Option<Value>,
}

#[derive(Debug, Clone, Deserialize)]
pub(crate) struct JsonRpcRequest {
    pub(crate) jsonrpc: String,
    #[serde(default)]
    pub(crate) id: Option<Value>,
    pub(crate) method: String,
    #[serde(default)]
    pub(crate) params: Option<Value>,
}

#[derive(Debug, Clone, Deserialize)]
#[serde(untagged)]
enum IncomingMessage {
    Request(JsonRpcRequest),
    Batch(Vec<JsonRpcRequest>),
    Raw(Value),
}

pub(crate) struct McpSessionState {
    initialized: bool,
    client_actor: String,
}

impl McpSessionState {
    pub(crate) fn new() -> Self {
        Self {
            initialized: false,
            client_actor: "mcp-client".to_string(),
        }
    }
}

#[derive(Clone)]
pub(crate) struct McpCore {
    client: crate::gitlab_client::GitlabClient,
}

impl McpCore {
    pub(crate) fn new(client: crate::gitlab_client::GitlabClient) -> Self {
        Self { client }
    }

    pub(crate) async fn handle_line(&self, state: &mut McpSessionState, line: &str) -> Vec<Value> {
        let parsed = match serde_json::from_str::<IncomingMessage>(line) {
            Ok(message) => message,
            Err(err) => return vec![jsonrpc_error(None, -32700, &format!("parse error: {err}"))],
        };

        match parsed {
            IncomingMessage::Request(request) => match self.handle_request(state, request).await {
                Some(response) => vec![response],
                None => vec![],
            },
            IncomingMessage::Batch(requests) => {
                let mut responses = Vec::new();
                for request in requests {
                    if let Some(response) = self.handle_request(state, request).await {
                        responses.push(response);
                    }
                }
                responses
            }
            IncomingMessage::Raw(value) => match value {
                Value::Object(_) => vec![jsonrpc_error(None, -32600, "invalid request")],
                Value::Array(_) => vec![jsonrpc_error(None, -32600, "invalid request batch")],
                _ => vec![jsonrpc_error(None, -32700, "parse error")],
            },
        }
    }

    pub(crate) async fn handle_request(
        &self,
        state: &mut McpSessionState,
        request: JsonRpcRequest,
    ) -> Option<Value> {
        if request.jsonrpc != "2.0" {
            return Some(jsonrpc_error(request.id, -32600, "invalid jsonrpc version"));
        }

        if request.method.starts_with("notifications/") && request.id.is_none() {
            self.handle_notification(state, &request.method, request.params)
                .await;
            return None;
        }

        let Some(id) = request.id else {
            return Some(jsonrpc_error(None, -32600, "request id is required"));
        };

        match request.method.as_str() {
            "initialize" => Some(self.handle_initialize(state, id, request.params).await),
            "ping" => Some(jsonrpc_result(id, serde_json::json!({}))),
            "tools/list" => Some(self.handle_tools_list(state, id, request.params).await),
            "tools/call" => Some(self.handle_tools_call(state, id, request.params).await),
            other => Some(jsonrpc_error(
                Some(id),
                -32601,
                &format!("method not found: {other}"),
            )),
        }
    }

    async fn handle_notification(
        &self,
        state: &mut McpSessionState,
        method: &str,
        params: Option<Value>,
    ) {
        if method == "notifications/initialized" {
            state.initialized = true;
            if let Some(Value::Object(map)) = params
                && let Some(Value::String(description)) = map.get("description")
            {
                state.client_actor = description.clone();
            }
        }
    }

    async fn handle_initialize(
        &self,
        state: &mut McpSessionState,
        id: Value,
        params: Option<Value>,
    ) -> Value {
        let params = match params {
            Some(value) => value,
            None => return jsonrpc_error(Some(id), -32602, "initialize params are required"),
        };
        let req: InitializeRequestParams = match serde_json::from_value(params) {
            Ok(value) => value,
            Err(err) => {
                return jsonrpc_error(
                    Some(id),
                    -32602,
                    &format!("invalid initialize params: {err}"),
                );
            }
        };
        if req.protocol_version != MCP_PROTOCOL_VERSION {
            return jsonrpc_error(
                Some(id),
                -32602,
                &format!(
                    "unsupported protocolVersion '{}', expected '{}'",
                    req.protocol_version, MCP_PROTOCOL_VERSION
                ),
            );
        }

        state.initialized = true;
        state.client_actor = match req.client_info.as_ref() {
            Some(info) => {
                let version = match info.version.as_deref() {
                    Some(version) => version,
                    None => "unknown",
                };
                format!("mcp:{}:{version}", info.name)
            }
            None => "mcp-client".to_string(),
        };

        jsonrpc_result(
            id,
            serde_json::json!({
                "protocolVersion": MCP_PROTOCOL_VERSION,
                "capabilities": {
                    "tools": { "listChanged": false }
                },
                "serverInfo": {
                    "name": "jeryu",
                    "version": env!("CARGO_PKG_VERSION"),
                    "description": "MCP adapter over jeryu capability policy"
                },
                "instructions": "Use tools/list to discover the jeryu tool surface. Each tool executes through the same policy, grant, and evidence gates as the capability socket."
            }),
        )
    }

    async fn handle_tools_list(
        &self,
        state: &mut McpSessionState,
        id: Value,
        params: Option<Value>,
    ) -> Value {
        if let Err(err) = ensure_initialized(state) {
            return jsonrpc_error(Some(id), -32002, &err.to_string());
        }

        if let Some(params) = params {
            let _: ListToolsRequestParams = match serde_json::from_value(params) {
                Ok(value) => value,
                Err(err) => {
                    return jsonrpc_error(
                        Some(id),
                        -32602,
                        &format!("invalid tools/list params: {err}"),
                    );
                }
            };
        }

        jsonrpc_result(
            id,
            serde_json::json!({ "tools": super::tools::tool_manifest() }),
        )
    }

    async fn handle_tools_call(
        &self,
        state: &mut McpSessionState,
        id: Value,
        params: Option<Value>,
    ) -> Value {
        if let Err(err) = ensure_initialized(state) {
            return jsonrpc_error(Some(id), -32002, &err.to_string());
        }

        let params = match params {
            Some(value) => value,
            None => return jsonrpc_error(Some(id), -32602, "tools/call params are required"),
        };
        let call: CallToolRequestParams = match serde_json::from_value(params) {
            Ok(value) => value,
            Err(err) => {
                return jsonrpc_error(
                    Some(id),
                    -32602,
                    &format!("invalid tools/call params: {err}"),
                );
            }
        };

        let Some(tool) = super::tools::tool_definition(call.name.trim_start_matches(TOOL_PREFIX))
        else {
            return jsonrpc_error(Some(id), -32601, &format!("unknown tool: {}", call.name));
        };

        let Some(intent) = tool.build_intent(call.arguments.unwrap_or(Value::Null)) else {
            return jsonrpc_error(Some(id), -32602, "invalid tool arguments");
        };

        let ctx = crate::capability::CapabilityContext::mcp(
            format!("mcp-{}", id),
            state.client_actor.clone(),
            MCP_PROTOCOL_VERSION.to_string(),
        );
        let response = crate::capability::execute_intent(intent, &ctx, &self.client).await;
        let is_error = !response.success;
        let message = response.message.clone();

        jsonrpc_result(
            id,
            serde_json::json!({
                "content": [ { "type": "text", "text": message } ],
                "structuredContent": response,
                "isError": is_error,
            }),
        )
    }
}

pub async fn start_mcp_stdio(client: crate::gitlab_client::GitlabClient) -> Result<()> {
    let stdin = BufReader::new(tokio::io::stdin());
    let mut stdout = BufWriter::new(tokio::io::stdout());
    let mut lines = stdin.lines();
    let core = McpCore::new(client);
    let mut state = McpSessionState::new();

    while let Some(line) = lines.next_line().await? {
        let line = line.trim();
        if line.is_empty() {
            continue;
        }

        let responses = core.handle_line(&mut state, line).await;
        if responses.is_empty() {
            continue;
        }

        let payload = if responses.len() == 1 {
            serde_json::to_vec(&responses[0])?
        } else {
            serde_json::to_vec(&responses)?
        };
        stdout.write_all(&payload).await?;
        stdout.write_all(b"\n").await?;
        stdout.flush().await?;
    }

    Ok(())
}

fn ensure_initialized(state: &McpSessionState) -> Result<()> {
    if state.initialized {
        Ok(())
    } else {
        bail!("server not initialized")
    }
}

pub(crate) fn jsonrpc_result(id: Value, result: Value) -> Value {
    serde_json::json!({
        "jsonrpc": "2.0",
        "id": id,
        "result": result,
    })
}

pub(crate) fn jsonrpc_error(id: Option<Value>, code: i64, message: &str) -> Value {
    let mut obj = serde_json::json!({
        "jsonrpc": "2.0",
        "error": {
            "code": code,
            "message": message,
        }
    });
    if let Some(id) = id {
        obj.as_object_mut()
            .expect("json object")
            .insert("id".to_string(), id);
    }
    obj
}

//! Owner: MCP adapter for external coding agents
//! Proof: `cargo check -p jeryu --message-format=json` and `cargo test -p jeryu --lib mcp`
//! Invariants: HTTP transport is loopback-only, validates MCP session headers, and routes
//!             tool execution through the same capability policy path as stdio.

use std::{collections::HashMap, net::SocketAddr, sync::Arc};

use anyhow::{Result, bail};
use axum::{
    Json, Router,
    body::Bytes,
    extract::State,
    http::{HeaderMap, HeaderValue, StatusCode, header},
    response::{IntoResponse, Response},
    routing::post,
};
use serde_json::Value;
use tokio::sync::Mutex;
use uuid::Uuid;

use super::{
    MCP_PROTOCOL_VERSION,
    core::{JsonRpcRequest, McpCore, McpSessionState, jsonrpc_error},
};

#[derive(Clone)]
pub(crate) struct McpHttpState {
    core: McpCore,
    sessions: Arc<Mutex<HashMap<String, McpSessionState>>>,
}

impl McpHttpState {
    pub(crate) fn new(client: crate::gitlab_client::GitlabClient) -> Self {
        Self {
            core: McpCore::new(client),
            sessions: Arc::new(Mutex::new(HashMap::new())),
        }
    }
}

pub(crate) fn mcp_router(state: Arc<McpHttpState>) -> Router {
    Router::new()
        .route(
            "/mcp",
            post(handle_mcp_post)
                .delete(handle_mcp_delete)
                .get(handle_mcp_get),
        )
        .with_state(state)
}

pub async fn start_mcp_http(client: crate::gitlab_client::GitlabClient, bind: &str) -> Result<()> {
    let addr: SocketAddr = bind
        .parse()
        .map_err(|err| anyhow::anyhow!("invalid MCP HTTP bind '{}': {err}", bind))?;
    if !addr.ip().is_loopback() {
        bail!("MCP HTTP bind must be loopback-only; got {addr}");
    }

    let state = Arc::new(McpHttpState::new(client));
    let app = mcp_router(state);

    let listener = tokio::net::TcpListener::bind(addr).await?;
    tracing::info!(addr = %addr, "MCP HTTP server listening");
    axum::serve(listener, app).await?;
    Ok(())
}

pub(crate) async fn handle_mcp_get() -> Response {
    (
        StatusCode::METHOD_NOT_ALLOWED,
        [("Allow", "POST, DELETE")],
        "Streamable HTTP GET is not enabled for jeryu MCP",
    )
        .into_response()
}

pub(crate) async fn handle_mcp_delete(
    State(state): State<Arc<McpHttpState>>,
    headers: HeaderMap,
) -> Response {
    if let Err(response) = validate_mcp_http_headers(&headers, false) {
        return response;
    }

    let Some(session_id) = header_value(&headers, "Mcp-Session-Id") else {
        return http_error(StatusCode::BAD_REQUEST, "Mcp-Session-Id header is required");
    };

    let mut sessions = state.sessions.lock().await;
    if sessions.remove(session_id).is_some() {
        (
            StatusCode::NO_CONTENT,
            [("MCP-Protocol-Version", MCP_PROTOCOL_VERSION)],
            (),
        )
            .into_response()
    } else {
        http_error(StatusCode::NOT_FOUND, "unknown MCP session")
    }
}

pub(crate) async fn handle_mcp_post(
    State(state): State<Arc<McpHttpState>>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    if let Err(response) = validate_mcp_http_headers(&headers, true) {
        return response;
    }

    let raw = match serde_json::from_slice::<Value>(&body) {
        Ok(value) => value,
        Err(err) => return http_jsonrpc_error(None, -32700, &format!("parse error: {err}")),
    };
    if raw.is_array() {
        return http_error(
            StatusCode::BAD_REQUEST,
            "batch requests are not supported over MCP HTTP",
        );
    }

    let request: JsonRpcRequest = match serde_json::from_value(raw) {
        Ok(value) => value,
        Err(err) => return http_jsonrpc_error(None, -32600, &format!("invalid request: {err}")),
    };

    let method_header = match header_value(&headers, "Mcp-Method") {
        Some(value) => value.to_string(),
        None => return http_error(StatusCode::BAD_REQUEST, "Mcp-Method header is required"),
    };
    if method_header != request.method {
        return http_error(
            StatusCode::BAD_REQUEST,
            "Mcp-Method header does not match body",
        );
    }

    if request.method == "initialize" {
        if header_value(&headers, "Mcp-Session-Id").is_some() {
            return http_error(
                StatusCode::BAD_REQUEST,
                "Mcp-Session-Id must be omitted for initialize",
            );
        }
        let mut session = McpSessionState::new();
        let response = state.core.handle_request(&mut session, request).await;
        let Some(result) = response else {
            return StatusCode::NO_CONTENT.into_response();
        };

        let session_id = Uuid::new_v4().to_string();
        let mut sessions = state.sessions.lock().await;
        sessions.insert(session_id.clone(), session);

        return http_jsonrpc_response(
            StatusCode::OK,
            result,
            Some((
                header::HeaderName::from_static("mcp-session-id"),
                session_id,
            )),
        );
    }

    let Some(protocol_version) = header_value(&headers, "MCP-Protocol-Version") else {
        return http_error(
            StatusCode::BAD_REQUEST,
            "MCP-Protocol-Version header is required",
        );
    };
    if protocol_version != MCP_PROTOCOL_VERSION {
        return http_error(
            StatusCode::BAD_REQUEST,
            "unsupported MCP-Protocol-Version header",
        );
    }

    let Some(session_id) = header_value(&headers, "Mcp-Session-Id") else {
        return http_error(StatusCode::BAD_REQUEST, "Mcp-Session-Id header is required");
    };

    if request.method == "tools/call" {
        let Some(name_header) = header_value(&headers, "Mcp-Name") else {
            return http_error(StatusCode::BAD_REQUEST, "Mcp-Name header is required");
        };
        if let Some(params) = request.params.as_ref()
            && let Some(name) = params.get("name").and_then(Value::as_str)
            && name != name_header
        {
            return http_error(
                StatusCode::BAD_REQUEST,
                "Mcp-Name header does not match body",
            );
        }
    }

    let mut sessions = state.sessions.lock().await;
    let Some(mut session) = sessions.remove(session_id) else {
        return http_error(StatusCode::NOT_FOUND, "unknown MCP session");
    };
    drop(sessions);

    let response = state.core.handle_request(&mut session, request).await;

    let mut sessions = state.sessions.lock().await;
    sessions.insert(session_id.to_string(), session);

    match response {
        Some(result) => http_jsonrpc_response(StatusCode::OK, result, None),
        None => StatusCode::ACCEPTED.into_response(),
    }
}

fn validate_mcp_http_headers(
    headers: &HeaderMap,
    allow_body: bool,
) -> std::result::Result<(), Response> {
    if let Some(origin) = header_value(headers, header::ORIGIN.as_str())
        && !is_loopback_origin(origin)
    {
        return Err(http_error(
            StatusCode::FORBIDDEN,
            "non-loopback Origin rejected",
        ));
    }

    if !allow_body
        && let Some(method) = headers.get(header::CONTENT_TYPE)
        && method
            .to_str()
            .map(|s| s.starts_with("application/json"))
            .unwrap_or(false)
    {
        return Err(http_error(
            StatusCode::METHOD_NOT_ALLOWED,
            "JSON body not accepted for this method",
        ));
    }

    Ok(())
}

fn header_value<'a>(headers: &'a HeaderMap, name: &str) -> Option<&'a str> {
    headers
        .get(name)
        .and_then(|v| v.to_str().ok())
        .map(str::trim)
}

pub(crate) fn is_loopback_origin(origin: &str) -> bool {
    let origin = origin.trim();
    for scheme in ["http://", "https://"] {
        if let Some(rest) = origin.strip_prefix(scheme) {
            let host = rest.split(['/', '?', '#']).next().unwrap_or(rest);
            return matches!(
                host,
                "127.0.0.1" | "localhost" | "[::1]" | "127.0.0.1:0" | "localhost:0" | "[::1]:0"
            ) || host.starts_with("127.0.0.1:")
                || host.starts_with("localhost:")
                || host.starts_with("[::1]:");
        }
    }
    false
}

fn http_jsonrpc_error(id: Option<Value>, code: i64, message: &str) -> Response {
    http_jsonrpc_response(StatusCode::OK, jsonrpc_error(id, code, message), None)
}

fn http_jsonrpc_response(
    status: StatusCode,
    body: Value,
    extra_header: Option<(axum::http::HeaderName, String)>,
) -> Response {
    let mut response = (status, Json(body)).into_response();
    response.headers_mut().insert(
        header::CONTENT_TYPE,
        HeaderValue::from_static("application/json"),
    );
    response.headers_mut().insert(
        header::HeaderName::from_static("mcp-protocol-version"),
        HeaderValue::from_static(MCP_PROTOCOL_VERSION),
    );
    if let Some((name, value)) = extra_header
        && let Ok(value) = HeaderValue::from_str(&value)
    {
        response.headers_mut().insert(name, value);
    }
    response
}

fn http_error(status: StatusCode, message: &str) -> Response {
    (
        status,
        [("Content-Type", "text/plain; charset=utf-8")],
        message.to_string(),
    )
        .into_response()
}

//! Owner: MCP adapter for external coding agents
//! Proof: `cargo check -p jeryu --message-format=json` and `cargo test -p jeryu --lib mcp`
//! Invariants: These tests guard the adapter behavior and must not mutate policy state.

use std::sync::Arc;

use axum::http::StatusCode;
use serde_json::json;

use super::{
    MCP_PROTOCOL_VERSION,
    core::{McpCore, McpSessionState},
    http::{McpHttpState, mcp_router},
    tool_manifest,
};

async fn spawn_http_server() -> (String, tokio::task::JoinHandle<()>) {
    let client = crate::gitlab_client::GitlabClient::new("http://127.0.0.1:9", None);
    let state = Arc::new(McpHttpState::new(client));
    let app = mcp_router(state);
    let listener = tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();
    let server = tokio::spawn(async move {
        axum::serve(listener, app).await.unwrap();
    });
    (format!("http://{addr}"), server)
}

async fn initialize_session(
    client: &reqwest::Client,
    base: &str,
    origin: &str,
    init_body: serde_json::Value,
) -> (reqwest::Response, String) {
    let resp = client
        .post(format!("{base}/mcp"))
        .header("Origin", origin)
        .header("Mcp-Method", "initialize")
        .json(&init_body)
        .send()
        .await
        .unwrap();
    let session = resp
        .headers()
        .get("Mcp-Session-Id")
        .and_then(|v| v.to_str().ok())
        .unwrap()
        .to_string();
    (resp, session)
}

fn authenticated_post<'a>(
    client: &'a reqwest::Client,
    base: &str,
    origin: &str,
    session: &str,
    method: &str,
) -> reqwest::RequestBuilder {
    client
        .post(format!("{base}/mcp"))
        .header("Origin", origin)
        .header("Mcp-Session-Id", session)
        .header("MCP-Protocol-Version", MCP_PROTOCOL_VERSION)
        .header("Mcp-Method", method)
}

/// Spawn a test HTTP server, create an HTTP client, perform an MCP initialize
/// handshake, and return `(base_url, client, session_id, server_handle)`.
async fn setup_authenticated_session()
-> (String, reqwest::Client, String, tokio::task::JoinHandle<()>) {
    let (base, server) = spawn_http_server().await;
    let client = reqwest::Client::new();
    let origin = base.clone();
    let (_init_resp, session) = initialize_session(
        &client,
        &base,
        &origin,
        json!({
            "jsonrpc": "2.0",
            "id": 1,
            "method": "initialize",
            "params": {
                "protocolVersion": MCP_PROTOCOL_VERSION
            }
        }),
    )
    .await;
    (base, client, session, server)
}

