//! Owner: MCP adapter for external coding agents
//! Proof: `cargo check -p jeryu --message-format=json` and `cargo test -p jeryu --lib mcp`
//! Invariants: The MCP tool catalog must stay in sync with the capability-surface registry
//!             and must map directly onto existing capability intents.

use serde_json::Value;

use super::TOOL_PREFIX;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub(crate) enum ToolKind {
    FetchCapsule,
    GetSystemSnapshot,
    GetPipelineJobs,
    GetCiBottlenecks,
    ExplainBlockers,
    PlanValidation,
    RunTests,
    ProposePatch,
    RacePatches,
    RequestMerge,
}

#[derive(Debug, Clone)]
pub(crate) struct ToolDefinition {
    title: &'static str,
    description: &'static str,
    annotations: Value,
    input_schema: Value,
    output_schema: Value,
    kind: ToolKind,
}

impl ToolDefinition {
    fn to_json(&self, action_id: &str) -> Value {
        serde_json::json!({
            "name": format!("{TOOL_PREFIX}{action_id}"),
            "title": self.title,
            "description": self.description,
            "inputSchema": self.input_schema,
            "outputSchema": self.output_schema,
            "annotations": self.annotations,
        })
    }

    pub(crate) fn build_intent(&self, args: Value) -> Option<crate::capability::AgentIntent> {
        use crate::capability::AgentIntent;

        match self.kind {
            ToolKind::FetchCapsule => Some(AgentIntent::FetchCapsule {
                job_id: args.get("job_id")?.as_i64()?,
            }),
            ToolKind::GetSystemSnapshot => Some(AgentIntent::GetSystemSnapshot),
            ToolKind::GetPipelineJobs => Some(AgentIntent::GetPipelineJobs {
                project_id: args.get("project_id")?.as_i64()?,
                pipeline_id: args.get("pipeline_id")?.as_i64()?,
            }),
            ToolKind::GetCiBottlenecks => Some(AgentIntent::GetCiBottlenecks {
                project_id: args.get("project_id")?.as_i64()?,
                ref_name: args
                    .get("ref_name")
                    .and_then(Value::as_str)
                    .map(ToString::to_string),
                limit: args.get("limit").and_then(Value::as_i64),
            }),
            ToolKind::ExplainBlockers => Some(AgentIntent::ExplainBlockers {
                entity_type: args.get("entity_type")?.as_str()?.to_string(),
                entity_id: args.get("entity_id")?.as_i64()?,
            }),
            ToolKind::PlanValidation => Some(AgentIntent::PlanValidation {
                project_id: args.get("project_id")?.as_i64()?,
                test_ids: parse_string_array(args.get("test_ids")?)?,
                ref_name: args.get("ref_name")?.as_str()?.to_string(),
            }),
            ToolKind::RunTests => Some(AgentIntent::RunTests {
                project_id: args.get("project_id")?.as_i64()?,
                target_ref: args.get("target_ref")?.as_str()?.to_string(),
                test_scope: args.get("test_scope")?.as_str()?.to_string(),
            }),
            ToolKind::ProposePatch => Some(AgentIntent::ProposePatch {
                project_id: args.get("project_id")?.as_i64()?,
                branch_name: args.get("branch_name")?.as_str()?.to_string(),
                base_ref: args.get("base_ref")?.as_str()?.to_string(),
                commit_message: args.get("commit_message")?.as_str()?.to_string(),
                modifications: parse_modifications(args.get("modifications")?)?,
                mr_title: args
                    .get("mr_title")
                    .and_then(Value::as_str)
                    .map(ToString::to_string),
            }),
            ToolKind::RacePatches => Some(AgentIntent::RacePatches {
                project_id: args.get("project_id")?.as_i64()?,
                base_branch: args.get("base_branch")?.as_str()?.to_string(),
                commit_message: args.get("commit_message")?.as_str()?.to_string(),
                hypotheses: parse_hypotheses(args.get("hypotheses")?)?,
            }),
            ToolKind::RequestMerge => Some(AgentIntent::RequestMerge {
                project_id: args.get("project_id")?.as_i64()?,
                mr_iid: args.get("mr_iid")?.as_i64()?,
                source_branch: args.get("source_branch")?.as_str()?.to_string(),
                target_branch: args.get("target_branch")?.as_str()?.to_string(),
            }),
        }
    }
}

pub fn tool_manifest() -> Vec<Value> {
    use crate::tui::action_registry::{self, Surface};

    action_registry::REGISTRY
        .iter()
        .filter(|entry| entry.surfaces.contains(&Surface::Capability))
        .filter_map(|entry| tool_definition(entry.id).map(|def| def.to_json(entry.id)))
        .collect()
}

pub(crate) fn tool_definition(action_id: &str) -> Option<ToolDefinition> {
    let (title, description, annotations, kind) = match action_id {
        "fetch_capsule" => (
            "Fetch capsule",
            "Fetch the latest structured failure capsule for a job.",
            tool_annotations(true, false, true, false),
            ToolKind::FetchCapsule,
        ),
        "get_system_snapshot" => (
            "System snapshot",
            "Get a full system state summary.",
            tool_annotations(true, false, true, false),
            ToolKind::GetSystemSnapshot,
        ),
        "get_pipeline_jobs" => (
            "Pipeline jobs",
            "Fetch the downstream-expanded job list for a pipeline.",
            tool_annotations(true, false, true, false),
            ToolKind::GetPipelineJobs,
        ),
        "get_ci_bottlenecks" => (
            "CI bottlenecks",
            "Return historical CI bottlenecks for a project and optional ref.",
            tool_annotations(true, false, true, false),
            ToolKind::GetCiBottlenecks,
        ),
        "explain_blockers" => (
            "Explain blockers",
            "Explain why a job, release, or merge is blocked.",
            tool_annotations(true, false, true, false),
            ToolKind::ExplainBlockers,
        ),
        "plan_validation" => (
            "Plan validation",
            "Validate a proposed test plan against selector-miss history.",
            tool_annotations(true, false, true, false),
            ToolKind::PlanValidation,
        ),
        "run_tests" => (
            "Run tests",
            "Create an ephemeral branch and trigger CI for a test scope.",
            tool_annotations(false, false, false, true),
            ToolKind::RunTests,
        ),
        "propose_patch" => (
            "Propose patch",
            "Create a branch, apply a patch, and open an MR.",
            tool_annotations(false, false, false, true),
            ToolKind::ProposePatch,
        ),
        "race_patches" => (
            "Race patches",
            "Launch multiple patch hypotheses and keep the first green.",
            tool_annotations(false, false, false, true),
            ToolKind::RacePatches,
        ),
        "request_merge" => (
            "Request merge",
            "Evaluate whether an MR can be merged through the risk gate.",
            tool_annotations(false, true, false, true),
            ToolKind::RequestMerge,
        ),
        _ => return None,
    };

    let input_schema = match action_id {
        "fetch_capsule" => object_schema(&["job_id"], &[("job_id", integer_schema())]),
        "get_system_snapshot" => object_schema(&[], &[]),
        "get_pipeline_jobs" => object_schema(
            &["project_id", "pipeline_id"],
            &[
                ("project_id", integer_schema()),
                ("pipeline_id", integer_schema()),
            ],
        ),
        "get_ci_bottlenecks" => object_schema(
            &["project_id"],
            &[
                ("project_id", integer_schema()),
                ("ref_name", string_schema_optional()),
                ("limit", integer_schema()),
            ],
        ),
        "explain_blockers" => object_schema(
            &["entity_type", "entity_id"],
            &[
                ("entity_type", string_schema()),
                ("entity_id", integer_schema()),
            ],
        ),
        "plan_validation" => object_schema(
            &["project_id", "test_ids", "ref_name"],
            &[
                ("project_id", integer_schema()),
                ("test_ids", array_schema(string_schema())),
                ("ref_name", string_schema()),
            ],
        ),
        "run_tests" => object_schema(
            &["project_id", "target_ref", "test_scope"],
            &[
                ("project_id", integer_schema()),
                ("target_ref", string_schema()),
                (
                    "test_scope",
                    enum_schema(&["unit", "integration", "lint", "full"]),
                ),
            ],
        ),
        "propose_patch" => object_schema(
            &[
                "project_id",
                "branch_name",
                "base_ref",
                "commit_message",
                "modifications",
            ],
            &[
                ("project_id", integer_schema()),
                ("branch_name", string_schema()),
                ("base_ref", string_schema()),
                ("commit_message", string_schema()),
                (
                    "modifications",
                    array_schema(object_schema(
                        &["file_path", "content"],
                        &[("file_path", string_schema()), ("content", string_schema())],
                    )),
                ),
                ("mr_title", string_schema_optional()),
            ],
        ),
        "race_patches" => object_schema(
            &["project_id", "base_branch", "commit_message", "hypotheses"],
            &[
                ("project_id", integer_schema()),
                ("base_branch", string_schema()),
                ("commit_message", string_schema()),
                (
                    "hypotheses",
                    array_schema(object_schema(
                        &["branch_suffix", "modifications"],
                        &[
                            ("branch_suffix", string_schema()),
                            (
                                "modifications",
                                array_schema(object_schema(
                                    &["file_path", "content"],
                                    &[("file_path", string_schema()), ("content", string_schema())],
                                )),
                            ),
                        ],
                    )),
                ),
            ],
        ),
        "request_merge" => object_schema(
            &["project_id", "mr_iid", "source_branch", "target_branch"],
            &[
                ("project_id", integer_schema()),
                ("mr_iid", integer_schema()),
                ("source_branch", string_schema()),
                ("target_branch", string_schema()),
            ],
        ),
        _ => return None,
    };

    let output_schema = serde_json::json!({
        "type": "object",
        "properties": {
            "success": { "type": "boolean" },
            "message": { "type": "string" },
            "data": {}
        },
        "required": ["success", "message"]
    });

    Some(ToolDefinition {
        title,
        description,
        annotations,
        input_schema,
        output_schema,
        kind,
    })
}

fn tool_annotations(
    read_only: bool,
    destructive: bool,
    idempotent: bool,
    open_world: bool,
) -> Value {
    serde_json::json!({
        "readOnlyHint": read_only,
        "destructiveHint": destructive,
        "idempotentHint": idempotent,
        "openWorldHint": open_world,
    })
}

fn object_schema(required: &[&str], props: &[(&str, Value)]) -> Value {
    let properties = props
        .iter()
        .map(|(k, v)| ((*k).to_string(), v.clone()))
        .collect::<serde_json::Map<_, _>>();
    serde_json::json!({
        "type": "object",
        "properties": properties,
        "required": required,
    })
}

fn string_schema() -> Value {
    serde_json::json!({ "type": "string" })
}

fn string_schema_optional() -> Value {
    serde_json::json!({ "type": "string" })
}

fn integer_schema() -> Value {
    serde_json::json!({ "type": "integer" })
}

fn array_schema(items: Value) -> Value {
    serde_json::json!({ "type": "array", "items": items })
}

fn enum_schema(values: &[&str]) -> Value {
    serde_json::json!({ "type": "string", "enum": values })
}

fn parse_string_array(value: &Value) -> Option<Vec<String>> {
    let items = value.as_array()?;
    let mut out = Vec::with_capacity(items.len());
    for item in items {
        out.push(item.as_str()?.to_string());
    }
    Some(out)
}

fn parse_modifications(value: &Value) -> Option<Vec<crate::capability::FileModification>> {
    let items = value.as_array()?;
    let mut out = Vec::with_capacity(items.len());
    for item in items {
        let file_path = item.get("file_path")?.as_str()?.to_string();
        let content = item.get("content")?.as_str()?.to_string();
        out.push(crate::capability::FileModification { file_path, content });
    }
    Some(out)
}

fn parse_hypotheses(value: &Value) -> Option<Vec<crate::capability::HypothesisPatch>> {
    let items = value.as_array()?;
    let mut out = Vec::with_capacity(items.len());
    for item in items {
        let branch_suffix = item.get("branch_suffix")?.as_str()?.to_string();
        let modifications = parse_modifications(item.get("modifications")?)?;
        out.push(crate::capability::HypothesisPatch {
            branch_suffix,
            modifications,
        });
    }
    Some(out)
}

//! Owner: MCP adapter for external coding agents
//! Proof: `cargo check -p jeryu` and `cargo test -p jeryu mcp`
//! Invariants: MCP is a transport adapter over the existing capability policy;
//!             it must not bypass grant checks, evidence handling, or merge/release gates.

mod core;
mod http;
mod tools;

#[cfg(test)]
mod tests;

pub use core::start_mcp_stdio;
pub use http::start_mcp_http;
pub use tools::tool_manifest;

pub(crate) const MCP_PROTOCOL_VERSION: &str = "2025-11-25";
pub(crate) const TOOL_PREFIX: &str = "jeryu.";

//! Owner: Trust Policy (TrustTier, Cache Promotion Gates)
//! Proof: `cargo test -p jeryu -- policy`
//! Invariants: PolicyEngine::can_consume is the single gate for cache promotion across trust boundaries; higher-trust tier may not consume lower-trust output without explicit approval

use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, Default)]
pub enum TrustTier {
    Trusted,
    #[default]
    Untrusted,
    Quarantine,
}

pub struct PolicyEngine;

impl PolicyEngine {
    /// Determines whether a cached object produced by `source_tier` can be safely
    /// consumed by `target_tier` without a promotion approval.
    pub fn can_consume(source_tier: &TrustTier, target_tier: &TrustTier) -> bool {
        match (source_tier, target_tier) {
            // Quarantine artifacts can never be consumed
            (TrustTier::Quarantine, _) => false,
            // A trusted artifact can be consumed by anyone
            (TrustTier::Trusted, _) => true,
            // An untrusted artifact can only be consumed by other untrusted builders
            (TrustTier::Untrusted, TrustTier::Untrusted) => true,
            (TrustTier::Untrusted, TrustTier::Trusted) => false,
            // You can consume untrusted if you're in quarantine (though why would you)
            (TrustTier::Untrusted, TrustTier::Quarantine) => true,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_trust_policy_boundaries() {
        assert!(PolicyEngine::can_consume(
            &TrustTier::Trusted,
            &TrustTier::Trusted
        ));
        assert!(PolicyEngine::can_consume(
            &TrustTier::Trusted,
            &TrustTier::Untrusted
        ));

        assert!(PolicyEngine::can_consume(
            &TrustTier::Untrusted,
            &TrustTier::Untrusted
        ));
        assert!(!PolicyEngine::can_consume(
            &TrustTier::Untrusted,
            &TrustTier::Trusted
        ));

        assert!(!PolicyEngine::can_consume(
            &TrustTier::Quarantine,
            &TrustTier::Trusted
        ));
        assert!(!PolicyEngine::can_consume(
            &TrustTier::Quarantine,
            &TrustTier::Untrusted
        ));
    }
}

//! Owner: Runner Fleet / Pool Management
//! Proof: `cargo test -p jeryu -- pool`
//! Invariants: Pool→Manager is 1:N; SIGQUIT for graceful drain; SIGHUP for token hot-reload
//!
//! A pool is a logical runner configuration in GitLab backed by
//! 0-N runner-manager containers on the local Docker host.

use anyhow::{Context, Result};
use std::collections::BTreeSet;
use std::fs;
use tracing::{info, warn};

use crate::config;
use crate::docker::DockerCtl;
use crate::gitlab_client::GitlabClient;
use crate::state::{Db, Manager, Pool};
use tokio::time::{Duration, Instant, sleep};

#[path = "pool_ops.rs"]
mod pool_ops;
pub use pool_ops::{delete_pool, drain_pool, pause_pool, resume_pool, rotate_pool_token};
pub(crate) use pool_ops::wait_for_active_managers;

// ---------------------------------------------------------------------------
// Scale: bring manager count to target
// ---------------------------------------------------------------------------

fn manager_state_counts_as_active(state: &str) -> bool {
    matches!(state, "starting" | "online")
}

fn manager_has_running_container(
    manager: &Manager,
    running_container_ids: &BTreeSet<String>,
) -> bool {
    running_container_ids.contains(&manager.docker_container_id)
}

pub async fn reconcile_manager_runtime_state(
    store: &Db,
    docker: &DockerCtl,
    pool_name: Option<&str>,
) -> Result<usize> {
    let running_container_ids = docker.running_managed_container_ids().await?;
    let managers = store.list_managers(pool_name).await?; // allowlist: pool orchestration owns runner state
    let mut stopped = 0;

    for manager in managers
        .iter()
        .filter(|manager| manager_state_counts_as_active(&manager.state))
        .filter(|manager| !manager_has_running_container(manager, &running_container_ids))
    {
        warn!(
            manager_id = %manager.id,
            pool = %manager.pool_name,
            container_id = %manager.docker_container_id,
            previous_state = %manager.state,
            "marking expired runner manager stopped; Docker container is not running"
        );
        store.update_manager_state(&manager.id, "stopped").await?; // allowlist: pool orchestration owns runner state
        stopped += 1;
    }

    Ok(stopped)
}

pub async fn count_running_managers(
    store: &Db,
    docker: &DockerCtl,
    pool_name: &str,
) -> Result<i64> {
    let running_container_ids = docker.running_managed_container_ids().await?;
    let managers = store.list_managers(Some(pool_name)).await?; // allowlist: pool orchestration owns runner state
    Ok(managers
        .iter()
        .filter(|manager| manager_state_counts_as_active(&manager.state))
        .filter(|manager| manager_has_running_container(manager, &running_container_ids))
        .count() as i64)
}

async fn remove_manager_cache_dir(docker: &DockerCtl, manager_id: &str) {
    let cache_dir = config::manager_cache_dir(manager_id);
    if !cache_dir.exists() {
        return;
    }
    if let Err(err) = docker.remove_cache_dir_as_root(&cache_dir).await {
        warn!(manager_id, path = %cache_dir.display(), error = %err, "failed to remove manager cache dir");
    }
}

async fn start_manager(store: &Db, docker: &DockerCtl, pool: &Pool, pool_name: &str) -> Result<()> {
    let manager_id = uuid::Uuid::new_v4().to_string();
    let config_dir = config::runners_dir()
        .join(&manager_id)
        .display()
        .to_string();
    let manager_cache_dir = config::manager_cache_dir(&manager_id);
    let pool_cache_dir = config::pool_cache_root(pool_name);
    let pool_targets_dir = config::pool_cargo_targets_root(pool_name);
    let pool_sccache_dir = config::pool_cargo_sccache_dir(pool_name);

    fs::create_dir_all(&config_dir)
        .with_context(|| format!("creating config dir: {config_dir}"))?;
    fs::create_dir_all(&manager_cache_dir)
        .with_context(|| format!("creating cache dir: {}", manager_cache_dir.display()))?;
    fs::create_dir_all(&pool_targets_dir)
        .with_context(|| format!("creating pool targets dir: {}", pool_targets_dir.display()))?;
    fs::create_dir_all(&pool_sccache_dir)
        .with_context(|| format!("creating pool sccache dir: {}", pool_sccache_dir.display()))?;

    let gitlab_url = format!(
        "http://{}:{}",
        config::GITLAB_HOSTNAME,
        config::GITLAB_HTTP_PORT
    );
    let config_content = config::render_runner_config(
        pool_name,
        &manager_id,
        &gitlab_url,
        &pool.auth_token,
        &pool.executor,
        &pool_cache_dir.display().to_string(),
        pool.concurrent,
        pool.request_concurrency,
    );
    fs::write(format!("{config_dir}/config.toml"), &config_content)?;

    let container_id = docker
        .start_runner_manager(
            &manager_id,
            &config_dir,
            &manager_cache_dir.display().to_string(),
            &pool_cache_dir.display().to_string(),
            &pool.executor,
            None,
        )
        .await
        .with_context(|| format!("starting manager for pool '{pool_name}'"))?;

    let manager = Manager {
        id: manager_id.clone(),
        pool_name: pool_name.to_string(),
        docker_container_id: container_id,
        system_id: None,
        state: "starting".to_string(),
        config_dir,
        started_at: Some(chrono::Utc::now().to_rfc3339()),
        last_contact_at: None,
    };
    store.insert_manager(&manager).await?; // allowlist: pool orchestration owns runner state

    info!(manager_id, pool = pool_name, "started new manager");
    Ok(())
}

/// Scale a pool to exactly `target` active managers. Returns the number
/// of managers started (may be 0 if already at target or scaling down).
pub async fn scale_pool_to(
    store: &Db,
    docker: &DockerCtl,
    _client: &GitlabClient,
    pool_name: &str,
    target: usize,
) -> Result<usize> {
    let pool = match store.get_pool(pool_name).await? {
        Some(pool) => pool,
        None => return Err(anyhow::anyhow!("pool '{}' not found", pool_name)),
    };

    reconcile_manager_runtime_state(store, docker, Some(pool_name)).await?;
    let active = store.count_active_managers(pool_name).await? as usize; // allowlist: pool orchestration owns runner state

    if active == target {
        info!(pool = pool_name, active, target, "pool already at target");
        return Ok(0);
    }

    if active > target {
        // Scale down: drain excess managers
        let excess = active - target;
        let managers = store.list_managers(Some(pool_name)).await?; // allowlist: pool orchestration owns runner state
        let to_drain: Vec<_> = managers
            .iter()
            .filter(|m| m.state == "online" || m.state == "starting")
            .take(excess)
            .collect();

        for m in &to_drain {
            info!(manager_id = %m.id, pool = pool_name, "draining excess manager");
            store.update_manager_state(&m.id, "draining").await?; // allowlist: pool orchestration owns runner state
            docker
                .cleanup_runner_cache(&m.docker_container_id)
                .await
                .ok();
            docker
                .drain_runner_manager(
                    &m.docker_container_id,
                    config::runner_shutdown_timeout_secs() as i64,
                )
                .await
                .ok(); // best-effort drain
            docker
                .cleanup_runner_cache(&m.docker_container_id)
                .await
                .ok();
            docker
                .remove_runner_manager(&m.docker_container_id)
                .await
                .ok();
            remove_manager_cache_dir(docker, &m.id).await;
            store.update_manager_state(&m.id, "stopped").await?; // allowlist: pool orchestration owns runner state
        }

        let active_after_drain = store.count_active_managers(pool_name).await? as usize; // allowlist: pool orchestration owns runner state
        if active_after_drain < target {
            for _ in 0..(target - active_after_drain) {
                start_manager(store, docker, &pool, pool_name).await?;
            }
        }
        wait_for_active_managers(store, pool_name, target as i64, Duration::from_secs(90)).await?;
        return Ok(0);
    }

    // Scale up: start new managers
    crate::cache::ensure_root_disk_headroom(
        crate::cache::ROOT_DISK_HEADROOM_MIN_FREE_BYTES,
        "runner fanout",
    )
    .await?;
    let to_start = target - active;
    let mut started = 0;

    for _ in 0..to_start {
        start_manager(store, docker, &pool, pool_name).await?;
        started += 1;
    }

    wait_for_active_managers(store, pool_name, target as i64, Duration::from_secs(90)).await?;
    Ok(started)
}

#[cfg(test)]
mod tests {
