// ---------------------------------------------------------------------------
// Pause / Resume
// ---------------------------------------------------------------------------

use super::*;

/// Pause a pool in GitLab (stops accepting new jobs) but keeps managers alive.
pub async fn pause_pool(store: &Db, client: &GitlabClient, pool_name: &str) -> Result<()> {
    let pool = match store.get_pool(pool_name).await? {
        Some(pool) => pool,
        None => return Err(anyhow::anyhow!("pool '{}' not found", pool_name)),
    };

    client
        .set_runner_paused(pool.gitlab_runner_id, true)
        .await?;
    store.update_pool_paused(pool_name, true).await?; // allowlist: pool orchestration owns runner state

    info!(pool = pool_name, "paused pool");
    Ok(())
}

/// Resume a paused pool.
pub async fn resume_pool(store: &Db, client: &GitlabClient, pool_name: &str) -> Result<()> {
    let pool = match store.get_pool(pool_name).await? {
        Some(pool) => pool,
        None => return Err(anyhow::anyhow!("pool '{}' not found", pool_name)),
    };

    client
        .set_runner_paused(pool.gitlab_runner_id, false)
        .await?;
    store.update_pool_paused(pool_name, false).await?; // allowlist: pool orchestration owns runner state

    info!(pool = pool_name, "resumed pool");
    Ok(())
}

/// Drain a pool: pause in GitLab, then SIGQUIT all managers, wait for
/// current jobs to finish, then stop and remove all manager containers.
pub async fn drain_pool(
    store: &Db,
    docker: &DockerCtl,
    client: &GitlabClient,
    pool_name: &str,
) -> Result<()> {
    pause_pool(store, client, pool_name).await?;

    let managers = store.list_managers(Some(pool_name)).await?; // allowlist: pool orchestration owns runner state
    for m in &managers {
        if m.state == "online" || m.state == "starting" {
            info!(manager_id = %m.id, "draining manager");
            store.update_manager_state(&m.id, "draining").await?; // allowlist: pool orchestration owns runner state

            docker
                .cleanup_runner_cache(&m.docker_container_id)
                .await
                .ok();
            docker
                .drain_runner_manager(
                    &m.docker_container_id,
                    config::runner_shutdown_timeout_secs() as i64,
                )
                .await
                .ok();

            docker
                .cleanup_runner_cache(&m.docker_container_id)
                .await
                .ok();
            docker
                .remove_runner_manager(&m.docker_container_id)
                .await
                .ok();
            remove_manager_cache_dir(docker, &m.id).await;
            store.update_manager_state(&m.id, "stopped").await?; // allowlist: pool orchestration owns runner state

            info!(manager_id = %m.id, "manager drained and stopped");
        }
    }

    wait_for_active_managers(store, pool_name, 0, Duration::from_secs(90)).await?;
    info!(pool = pool_name, "pool fully drained");
    Ok(())
}

/// Remove a pool after draining managers and deregistering the GitLab runner.
pub async fn delete_pool(
    store: &Db,
    docker: &DockerCtl,
    client: &GitlabClient,
    pool_name: &str,
) -> Result<()> {
    let pool = match store.get_pool(pool_name).await? {
        Some(pool) => pool,
        None => return Err(anyhow::anyhow!("pool '{}' not found", pool_name)),
    };

    drain_pool(store, docker, client, pool_name).await.ok();
    client.delete_runner(pool.gitlab_runner_id).await.ok();
    store.delete_pool(pool_name).await?; // allowlist: pool orchestration owns runner state
    Ok(())
}

/// Rotate the auth token for a pool.
pub async fn rotate_pool_token(
    store: &Db,
    docker: &DockerCtl,
    client: &GitlabClient,
    pool_name: &str,
) -> Result<String> {
    let pool = match store.get_pool(pool_name).await? {
        Some(pool) => pool,
        None => return Err(anyhow::anyhow!("pool '{}' not found", pool_name)),
    };

    let new_token = client.reset_runner_token(pool.gitlab_runner_id).await?;
    info!(pool = pool_name, "got new runner auth token");

    let managers = store.list_managers(Some(pool_name)).await?; // allowlist: pool orchestration owns runner state
    let gitlab_url = format!(
        "http://{}:{}",
        config::GITLAB_HOSTNAME,
        config::GITLAB_HTTP_PORT
    );
    for m in &managers {
        let config_content = config::render_runner_config(
            pool_name,
            &m.id,
            &gitlab_url,
            &new_token,
            &pool.executor,
            &config::pool_cache_root(pool_name).display().to_string(),
            pool.concurrent,
            pool.request_concurrency,
        );
        let config_path = format!("{}/config.toml", m.config_dir);
        fs::write(&config_path, &config_content)
            .with_context(|| format!("rewriting config for manager {}", m.id))?;

        if m.state == "online" || m.state == "starting" {
            docker
                .reload_runner_config(&m.docker_container_id)
                .await
                .ok();
        }
    }

    store.update_pool_token(pool_name, &new_token).await?; // allowlist: pool orchestration owns runner state
    let expected = store.count_active_managers(pool_name).await?; // allowlist: pool orchestration owns runner state
    if expected > 0 {
        wait_for_active_managers(store, pool_name, expected, Duration::from_secs(90)).await?;
    }

    info!(
        pool = pool_name,
        "token rotation complete — all managers updated"
    );
    Ok(new_token)
}

pub(crate) async fn wait_for_active_managers(
    store: &Db,
    pool_name: &str,
    expected: i64,
    timeout: Duration,
) -> Result<()> {
    let deadline = Instant::now() + timeout;
    loop {
        let active = store.count_active_managers(pool_name).await?; // allowlist: pool orchestration owns runner state
        if active == expected {
            return Ok(());
        }
        if Instant::now() >= deadline {
            anyhow::bail!(
                "timed out waiting for pool '{}' active managers to reach {} (current={})",
                pool_name,
                expected,
                active
            );
        }
        sleep(Duration::from_secs(2)).await;
    }
}

//! Owner: Storage Audit & GC
//! Proof: `cargo test -p jeryu -- reclaim`
//! Invariants: GC never removes objects referenced by active managers; AutoGcReport is produced before any deletions; audit runs do not block the reconciliation loop

use anyhow::{Context, Result};
use tokio::process::Command;
use tracing::{info, warn};

#[path = "reclaim_support.rs"]
mod reclaim_support;

pub use reclaim_support::{gc_orphaned_workers, mem_available_gb, run_auto_gc, AutoGcReport};

pub fn live_registry_gc_enabled() -> bool {
    false
}

pub fn live_registry_gc_skip_reason() -> &'static str {
    "Docker registry garbage-collect is only safe while the registry is offline; live GC can leave manifests pointing at missing blobs."
}

pub async fn run_storage_audit() -> Result<()> {
    info!("Running storage audit on host...");
    let mut root_df = Command::new("df");
    root_df.args(["-h", "/"]);
    reclaim_support::print_cmd("Root filesystem usage", &mut root_df).await?;

    let mut inode_df = Command::new("df");
    inode_df.args(["-ih", "/"]);
    reclaim_support::print_cmd("Root inode usage", &mut inode_df).await?;

    let mut reserve_cmd = Command::new("docker");
    reserve_cmd.args([
        "run",
        "--rm",
        "--privileged",
        "-v",
        "/:/host",
        "alpine",
        "sh",
        "-lc",
        "chroot /host /usr/sbin/tune2fs -l /dev/nvme0n1p2 | grep -E 'Reserved block count|Block count|Block size'",
    ]);
    reclaim_support::print_cmd("Ext4 reserved block setting", &mut reserve_cmd).await?;

    let mut gitlab_logs_cmd = Command::new("docker");
    gitlab_logs_cmd.args([
        "exec",
        "jeryu-gitlab",
        "sh",
        "-lc",
        "du -sh /var/log/gitlab/* 2>/dev/null | sort -h | tail -n 20",
    ]);
    reclaim_support::print_cmd("GitLab log directory sizes", &mut gitlab_logs_cmd).await?;

    let mut docker_logs_cmd = Command::new("docker");
    docker_logs_cmd.args([
        "run",
        "--rm",
        "-v",
        "/var/lib/docker/containers:/host-containers:ro",
        "alpine",
        "sh",
        "-lc",
        "find /host-containers -name '*-json.log' -exec du -h {} + | sort -h | tail -n 20",
    ]);
    reclaim_support::print_cmd("Largest Docker JSON logs", &mut docker_logs_cmd).await?;

    let output = Command::new("docker")
        .args(["system", "df"])
        .output()
        .await
        .context("Failed to run docker system df")?;

    if !output.status.success() {
        warn!("Failed to query docker storage. Is docker running?");
        println!("{}", String::from_utf8_lossy(&output.stderr));
    } else {
        println!("{}", String::from_utf8_lossy(&output.stdout));
    }

    Ok(())
}

pub async fn run_aggressive_reclaim(apply: bool) -> Result<()> {
    let reclaim_toml = match dirs::home_dir() {
        Some(home) => home.join(".jeryu/reclaim.toml"),
        None => std::path::PathBuf::from(".jeryu/reclaim.toml"),
    };
    let mut exclusions = vec![];
    if reclaim_toml.exists()
        && let Ok(content) = tokio::fs::read_to_string(&reclaim_toml).await
    {
        if let Ok(parsed) = content.parse::<toml::Table>() {
            if let Some(toml::Value::Array(excl)) = parsed.get("exclude") {
                for item in excl {
                    if let toml::Value::String(s) = item {
                        exclusions.push(s.clone());
                    }
                }
            }
        } else {
            tracing::warn!("Failed to parse reclaim.toml; ignoring exclusions");
        }
    }

    if !apply {
        // Fetch accurate docker sizes
        let df_output = Command::new("docker")
            .args(["system", "df", "--format", "{{json .}}"])
            .output()
            .await
            .ok();

        let mut img_sz = "Unknown".to_string();
        let mut cont_sz = "Unknown".to_string();
        if let Some(out) = df_output {
            for line in String::from_utf8_lossy(&out.stdout).lines() {
                if let Ok(j) = serde_json::from_str::<serde_json::Value>(line) {
                    if j["Type"] == "Images" {
                        img_sz = j["Size"].as_str().unwrap_or("Unknown").to_string();
                    }
                    if j["Type"] == "Containers" {
                        cont_sz = j["Size"].as_str().unwrap_or("Unknown").to_string();
                    }
                }
            }
        }

        let plan = serde_json::json!({
            "mode": "plan",
            "exclusions_loaded": exclusions.len(),
            "targets": [
                { "type": "gitlab_internal_logs", "filter": "truncate current logs + remove rotated logs", "estimated_bytes_freed": "Variable" },
                { "type": "docker_container_json_logs", "filter": "truncate jeryu-gitlab + jeryu-managed runner logs", "estimated_bytes_freed": "Variable" },
                { "type": "containers", "filter": "until=24h", "estimated_bytes_freed": cont_sz },
                { "type": "images_dangling", "filter": "dangling=true", "estimated_bytes_freed": img_sz },
                { "type": "images_unreferenced", "filter": "until=168h", "estimated_bytes_freed": "Unknown" },
                { "type": "builder_cache", "filter": "until=168h", "estimated_bytes_freed": "Unknown" }
            ],
            "skipped_targets": [
                { "type": "veox_ci_registry_gc", "filter": "disabled-live-registry", "reason": live_registry_gc_skip_reason() }
            ],
            "message": "Run with --apply to execute."
        });
        let rendered_plan = match serde_json::to_string_pretty(&plan) {
            Ok(plan) => plan,
            Err(_) => String::new(),
        };
        println!("{}", rendered_plan);
        return Ok(());
    }

    println!(
        "Starting aggressive host reclaim (exclusions: {:?})...",
        exclusions
    );

    // Log target digest metrics to ledger as an audit trail before deletion
    let db = crate::state::Db::open().await?;
    let payload = serde_json::json!({
        "action": "aggressive_reclaim_apply",
        "exclusions": exclusions,
        "target_systems": ["docker_containers", "docker_images", "builder_cache"]
    });
    db.append_event(
        "host_reclaim",
        None,
        None,
        "jeryu-cli",
        &payload.to_string(),
    )
    .await?;

    reclaim_support::truncate_gitlab_logs().await?;
    reclaim_support::truncate_docker_json_logs().await?;

    // Remove exited containers older than 24h
    reclaim_support::run_docker_prune(&["container", "prune", "--force", "--filter", "until=24h"])
        .await?;

    // Remove dangling images
    reclaim_support::run_docker_prune(&["image", "prune", "--force"]).await?;

    // Remove unreferenced images older than 7d
    reclaim_support::run_docker_prune(&[
        "image",
        "prune",
        "--all",
        "--force",
        "--filter",
        "until=168h",
    ])
    .await?;

    // Remove Docker build cache older than 7d
    reclaim_support::run_docker_prune(&[
        "builder",
        "prune",
        "--force",
        "--all",
        "--filter",
        "until=168h",
    ])
    .await?;

    warn!(
        reason = live_registry_gc_skip_reason(),
        "skipping veox-ci-registry garbage-collect"
    );

    println!("Aggressive host reclaim completed successfully.");
    Ok(())
}

use anyhow::{Context, Result};
use std::path::{Path, PathBuf};
use tokio::process::Command;
use tracing::{info, warn};

pub(crate) async fn print_cmd(label: &str, cmd: &mut Command) -> Result<()> {
    println!("\n== {} ==", label);
    let output = cmd.output().await?;
    if output.status.success() {
        print!("{}", String::from_utf8_lossy(&output.stdout));
    } else {
        warn!(
            "{} failed: {}",
            label,
            String::from_utf8_lossy(&output.stderr)
        );
    }
    Ok(())
}

pub(crate) async fn run_docker_prune(args: &[&str]) -> Result<()> {
    info!("Running: docker {}", args.join(" "));
    let output = Command::new("docker").args(args).output().await?;

    if output.status.success() {
        let stdout = String::from_utf8_lossy(&output.stdout);
        for line in stdout.lines() {
            if line.contains("Total reclaimed space") || line.contains("Deleted") {
                println!("{}", line);
            }
        }
    } else {
        warn!(
            "Failed to run docker {}: {}",
            args.join(" "),
            String::from_utf8_lossy(&output.stderr)
        );
    }
    Ok(())
}

pub(crate) async fn truncate_gitlab_logs() -> Result<()> {
    let logs_dir = crate::config::gitlab_logs_dir();
    let script = format!(
        r#"
set -eu
find "{logs}" -type f \( -name '@*' -o -name '*.gz' \) -exec rm -f {{}} + || true
find "{logs}" -type f -name current -exec sh -c ': > "$1"' _ {{}} \; || true
find "{logs}/gitlab-rails" -type f \( -name '*_json.log' -o -name '*_client.log' \) -exec sh -c ': > "$1"' _ {{}} \; || true
"#,
        logs = logs_dir.display()
    );
    let output = Command::new("sh")
        .arg("-lc")
        .arg(script)
        .output()
        .await
        .context("truncating gitlab logs")?;
    if !output.status.success() {
        warn!(
            "gitlab log truncation warning: {}",
            String::from_utf8_lossy(&output.stderr)
        );
    }
    Ok(())
}

pub(crate) async fn truncate_docker_json_logs() -> Result<()> {
    let script = r#"
set -eu
for cid in $(docker ps -aq --filter name=jeryu-gitlab --filter label=jeryu.managed=true); do
  log_path=$(docker inspect --format '{{.LogPath}}' "$cid" 2>/dev/null || true)
  if [ -n "$log_path" ] && [ -f "$log_path" ]; then
    : > "$log_path" || true
  fi
done
"#;
    let output = Command::new("sh")
        .arg("-lc")
        .arg(script)
        .output()
        .await
        .context("truncating docker json logs")?;
    if !output.status.success() {
        warn!(
            "docker json log truncation warning: {}",
            String::from_utf8_lossy(&output.stderr)
        );
    }
    Ok(())
}

/// Report from an automatic GC cycle.
#[derive(Debug, Default)]
pub struct AutoGcReport {
    pub volumes_removed: u64,
    pub stale_dirs_removed: u64,
    pub artifacts_removed: u64,
}

pub async fn run_auto_gc(
    docker: &crate::docker::DockerCtl,
    is_critical: bool,
    is_emergency: bool,
) -> Result<AutoGcReport> {
    info!(
        critical = is_critical,
        emergency = is_emergency,
        "running automatic storage GC"
    );
    let mut report = AutoGcReport::default();

    if is_emergency {
        warn!(
            "disk pressure emergency: build/default pools should already be paused and draining before host GC"
        );
    }

    match docker.prune_orphan_runner_volumes().await {
        Ok(n) => report.volumes_removed = n,
        Err(e) => warn!(error = %e, "orphan volume prune failed"),
    }

    let home = match dirs::home_dir() {
        Some(home) => home,
        None => std::path::PathBuf::new(),
    };
    let age_threshold = if is_emergency {
        std::time::Duration::from_secs(30 * 60)
    } else if is_critical {
        std::time::Duration::from_secs(2 * 3600)
    } else {
        std::time::Duration::from_secs(6 * 3600)
    };

    report.stale_dirs_removed +=
        sweep_stale_dirs(&home, "dougx-release-ci-", age_threshold, docker).await;
    let tmp = std::path::PathBuf::from("/tmp");
    for prefix in &["dougx-", "enclave"] {
        report.stale_dirs_removed += sweep_stale_dirs(&tmp, prefix, age_threshold, docker).await;
    }

    if is_critical || is_emergency {
        if let Err(e) = truncate_gitlab_logs().await {
            warn!(error = %e, "gitlab log truncation failed");
        }
        if let Err(e) = truncate_docker_json_logs().await {
            warn!(error = %e, "docker json log truncation failed");
        }
    }

    let artifact_dir = crate::config::data_dir().join("gitlab/data/gitlab-rails/shared/artifacts");
    if artifact_dir.is_dir() {
        report.artifacts_removed += sweep_stale_files(&artifact_dir, ".zip", age_threshold).await;
        let artifact_budget: u64 = if is_emergency {
            2 * 1024 * 1024 * 1024
        } else if is_critical {
            5 * 1024 * 1024 * 1024
        } else {
            20 * 1024 * 1024 * 1024
        };
        report.artifacts_removed +=
            evict_artifacts_over_budget(&artifact_dir, ".zip", artifact_budget).await;
    }

    if let Err(e) = docker.prune_docker_objects(is_critical).await {
        warn!(error = %e, "docker object prune failed");
    }

    if is_critical || is_emergency {
        warn!(
            critical = is_critical,
            emergency = is_emergency,
            reason = crate::reclaim::live_registry_gc_skip_reason(),
            "skipping veox-ci-registry garbage-collect"
        );
    }

    info!(
        volumes = report.volumes_removed,
        dirs = report.stale_dirs_removed,
        artifacts = report.artifacts_removed,
        "automatic storage GC complete"
    );
    Ok(report)
}

pub(crate) async fn evict_artifacts_over_budget(
    dir: &Path,
    suffix: &str,
    budget_bytes: u64,
) -> u64 {
    let mut files: Vec<(PathBuf, u64, std::time::SystemTime)> = Vec::new();
    walk_files_with_suffix(dir, suffix, |path, meta| {
        let mtime = meta.modified().unwrap_or(std::time::UNIX_EPOCH);
        files.push((path, meta.len(), mtime));
    })
    .await;

    let total: u64 = files.iter().map(|(_, sz, _)| sz).sum();
    if total <= budget_bytes {
        return 0;
    }

    files.sort_by_key(|(_, _, mtime)| *mtime);
    let mut to_free = total - budget_bytes;
    let mut removed = 0u64;
    for (path, size, _) in files {
        if to_free == 0 {
            break;
        }
        if let Err(e) = tokio::fs::remove_file(&path).await {
            warn!(path = %path.display(), error = %e, "artifact eviction failed");
        } else {
            to_free = to_free.saturating_sub(size);
            removed += 1;
        }
    }
    removed
}

pub(crate) async fn sweep_stale_dirs(
    parent: &Path,
    prefix: &str,
    max_age: std::time::Duration,
    _docker: &crate::docker::DockerCtl,
) -> u64 {
    let mut stale_paths = Vec::new();
    let Ok(mut entries) = tokio::fs::read_dir(parent).await else {
        return 0;
    };

    while let Ok(Some(entry)) = entries.next_entry().await {
        let name = entry.file_name();
        let name_str = name.to_string_lossy();
        if !name_str.starts_with(prefix) {
            continue;
        }
        let Ok(meta) = entry.metadata().await else {
            continue;
        };
        if !meta.is_dir() {
            continue;
        }
        let is_stale = meta
            .modified()
            .ok()
            .and_then(|mtime| std::time::SystemTime::now().duration_since(mtime).ok())
            .is_some_and(|age| age >= max_age);

        if is_stale {
            stale_paths.push(entry.path().display().to_string());
        }
    }

    if stale_paths.is_empty() {
        return 0;
    }

    info!(
        count = stale_paths.len(),
        "batch removing outdated directories"
    );

    let mut need_sudo: Vec<String> = Vec::new();
    for path in &stale_paths {
        if tokio::fs::remove_dir_all(path).await.is_err() {
            need_sudo.push(path.clone());
        }
    }

    if need_sudo.is_empty() {
        return stale_paths.len() as u64;
    }

    let output = tokio::process::Command::new("sudo")
        .arg("rm")
        .arg("-rf")
        .args(&need_sudo)
        .output()
        .await;

    let sudo_removed = match output {
        Ok(out) if out.status.success() => need_sudo.len(),
        Ok(out) => {
            warn!(
                stderr = %String::from_utf8_lossy(&out.stderr),
                "batch removal command failed"
            );
            0
        }
        Err(e) => {
            warn!(error = %e, "failed to spawn batch removal command");
            0
        }
    };
    (stale_paths.len() - need_sudo.len() + sudo_removed) as u64
}

pub(crate) async fn sweep_stale_files(dir: &Path, suffix: &str, max_age: std::time::Duration) -> u64 {
    let mut removed = 0u64;
    let mut to_remove: Vec<PathBuf> = Vec::new();
    walk_files_with_suffix(dir, suffix, |path, meta| {
        let is_stale = meta
            .modified()
            .ok()
            .and_then(|mtime| std::time::SystemTime::now().duration_since(mtime).ok())
            .is_some_and(|age| age >= max_age);
        if is_stale {
            to_remove.push(path);
        }
    })
    .await;

    for path in to_remove {
        if let Err(e) = tokio::fs::remove_file(&path).await {
            warn!(path = %path.display(), error = %e, "failed to remove outdated artifact");
        } else {
            removed += 1;
        }
    }
    removed
}

async fn walk_files_with_suffix<F>(dir: &Path, suffix: &str, mut visit: F)
where
    F: FnMut(PathBuf, std::fs::Metadata),
{
    let mut stack = vec![dir.to_path_buf()];
    while let Some(current) = stack.pop() {
        let Ok(mut entries) = tokio::fs::read_dir(&current).await else {
            continue;
        };
        while let Ok(Some(entry)) = entries.next_entry().await {
            let Ok(meta) = entry.metadata().await else {
                continue;
            };
            if meta.is_dir() {
                stack.push(entry.path());
                continue;
            }
            let name = entry.file_name();
            if !name.to_string_lossy().ends_with(suffix) {
                continue;
            }
            visit(entry.path(), meta);
        }
    }
}

pub async fn gc_orphaned_workers() -> u64 {
    use std::fs;
    let Ok(proc_dir) = fs::read_dir("/proc") else {
        return 0;
    };
    let mut killed = 0u64;
    for entry in proc_dir.flatten() {
        let name = entry.file_name();
        let name_str = name.to_string_lossy();
        if !name_str.chars().all(|c| c.is_ascii_digit()) {
            continue;
        }
        let pid: u32 = match name_str.parse() {
            Ok(p) => p,
            Err(_) => continue,
        };
        let status_path = format!("/proc/{pid}/status");
        let Ok(status) = fs::read_to_string(&status_path) else {
            continue;
        };
        let ppid: u32 = status
            .lines()
            .find(|l| l.starts_with("PPid:"))
            .and_then(|l| l.split_whitespace().nth(1))
            .and_then(|v| v.parse().ok())
            .unwrap_or(u32::MAX);
        if ppid != 1 {
            continue;
        }
        let cmdline_path = format!("/proc/{pid}/cmdline");
        let Ok(cmdline) = fs::read_to_string(&cmdline_path) else {
            continue;
        };
        let cmd = cmdline.replace('\0', " ");
        if !cmd.contains("forkserver") && !cmd.contains("local_run_mimo") {
            continue;
        }
        let _ = std::process::Command::new("kill")
            .args(["-9", &pid.to_string()])
            .output();
        killed += 1;
    }
    killed
}

pub fn mem_available_gb() -> f64 {
    let meminfo = match std::fs::read_to_string("/proc/meminfo") {
        Ok(meminfo) => meminfo,
        Err(_) => String::new(),
    };

    meminfo
        .lines()
        .find(|l| l.starts_with("MemAvailable:"))
        .and_then(|l| l.split_whitespace().nth(1))
        .and_then(|v| v.parse::<f64>().ok())
        .map(|kb| kb / 1024.0 / 1024.0)
        .unwrap_or(f64::MAX)
}

//! Owner: cross-cutting redaction helpers
//! Proof: `cargo test -p jeryu redact`
//! Invariants: Sensitive tokens are redacted before they reach receipts, logs, or human-facing summaries.

use sha2::{Digest, Sha256};

pub fn redact_text(input: &str) -> String {
    let mut out = input.to_string();
    for (needle, replacement) in [("https://", "https://"), ("http://", "http://")] {
        if out.contains(needle) {
            out = redact_urls(&out);
        }
        let _ = replacement;
    }
    out = redact_basic_auth(&out);
    out = redact_known_tokens(&out);
    out
}

pub fn redact_args(args: &[String]) -> Vec<String> {
    args.iter().map(|arg| redact_text(arg)).collect()
}

pub fn hash_argv(args: &[String]) -> String {
    let mut hasher = Sha256::new();
    for arg in args {
        hasher.update(arg.as_bytes());
        hasher.update([0]);
    }
    hex::encode(hasher.finalize())
}

fn redact_urls(input: &str) -> String {
    input
        .split_whitespace()
        .map(|token| {
            if token.starts_with("http://") || token.starts_with("https://") {
                redact_url(token)
            } else {
                token.to_string()
            }
        })
        .collect::<Vec<_>>()
        .join(" ")
}

pub fn redact_url(url: &str) -> String {
    if let Some((scheme, rest)) = url.split_once("://") {
        let mut out = String::from(scheme);
        out.push_str("://");
        if let Some((auth, tail)) = rest.split_once('@') {
            let host = tail.split('/').next().unwrap_or("");
            out.push_str("redacted@");
            out.push_str(host);
            if let Some(path) = tail.strip_prefix(host) {
                out.push_str(path);
            }
            if auth.contains(':') {
                return out;
            }
        }
    }
    url.to_string()
}

fn redact_basic_auth(input: &str) -> String {
    input
        .split_whitespace()
        .map(|token| {
            if let Some((scheme, rest)) = token.split_once("://") {
                if let Some((auth, tail)) = rest.split_once('@') {
                    if auth.contains(':') {
                        let host = tail.split('/').next().unwrap_or("");
                        let suffix = tail.strip_prefix(host).unwrap_or("");
                        return format!("{scheme}://redacted@{host}{suffix}");
                    }
                }
            }
            token.to_string()
        })
        .collect::<Vec<_>>()
        .join(" ")
}

fn redact_known_tokens(input: &str) -> String {
    let mut out = input.to_string();
    for marker in ["token=", "access_token=", "password=", "pat="] {
        if let Some(idx) = out.to_ascii_lowercase().find(marker) {
            let end = out[idx..]
                .find([' ', '&', '\n', '\r'])
                .map(|n| idx + n)
                .unwrap_or(out.len());
            out.replace_range(idx..end, &format!("{marker}redacted"));
        }
    }
    out
}

