    print_action_envelope(
        opts,
        serde_json::json!({
            "action": "remote-uninstall",
            "alias": cfg.alias,
            "target": cfg.target,
            "dry_run": opts.dry_run,
        }),
    )?;
    if opts.dry_run {
        return Ok(0);
    }
    match resolve_service_mode(cfg).await? {
