                color: ColorMode::Auto,
                interactive: InteractiveMode::Auto,
                service_mode: ServiceMode::Auto,
                verbose: false,
            },
        );
        assert_eq!(plan.action, "remote-install");
        assert!(!plan.preflight.local_ssh_keygen || plan.preflight.local_ssh);
    }

    #[test]
    fn effective_service_mode_resolves_auto_by_preflight() {
        assert_eq!(
            effective_service_mode(ServiceMode::Auto, Some(true)),
            ServiceMode::User
        );
        assert_eq!(
            effective_service_mode(ServiceMode::Auto, Some(false)),
            ServiceMode::Manual
        );
        assert_eq!(
            effective_service_mode(ServiceMode::User, Some(false)),
            ServiceMode::User
        );
        assert_eq!(
            effective_service_mode(ServiceMode::Manual, Some(true)),
            ServiceMode::Manual
        );
    }

    #[test]
    fn remote_config_defaults_service_mode_when_missing() {
        let text = r#"
alias = "xbabe1"
target = "xbabe1"
ssh_port = 22
remote_prefix = "~/.jeryu"
remote_bin = "~/.jeryu/bin/jeryu"
local_http_port = 8929
local_ssh_port = 2224
local_vault_port = 18200
local_webhook_port = 9777
created_at_utc = "2026-05-04T00:00:00Z"
"#;
        let cfg: RemoteConfig = toml::from_str(text).unwrap();
        assert_eq!(cfg.service_mode, ServiceMode::Auto);
    }
}

use super::*;

pub(crate) fn default_alias(target: &str) -> String {
    target
        .rsplit('@')
        .next()
        .unwrap_or(target)
        .replace([':', '/'], "-")
}

pub(crate) fn remote_root() -> PathBuf {
    expand_tilde("~/.jeryu/remotes")
}

pub(crate) fn config_path(alias: &str) -> PathBuf {
    remote_root().join(format!("{alias}.toml"))
}

pub(crate) fn load_remote_config(alias: &str) -> Result<RemoteConfig> {
    let path = config_path(alias);
    let text = fs::read_to_string(&path)
        .with_context(|| format!("loading remote config {}", path.display()))?;
    let cfg = toml::from_str(&text).with_context(|| format!("parsing {}", path.display()))?;
    Ok(cfg)
}

pub(crate) async fn with_loaded_remote_config<F, Fut>(alias: String, f: F) -> Result<i32>
where
    F: FnOnce(RemoteConfig) -> Fut,
    Fut: Future<Output = Result<i32>>,
{
    let cfg = load_remote_config(&alias)?;
    f(cfg).await
}

pub(crate) fn save_remote_config(cfg: &RemoteConfig) -> Result<()> {
    let path = config_path(&cfg.alias);
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).with_context(|| format!("creating {}", parent.display()))?;
    }
    let text = toml::to_string_pretty(cfg).context("serializing remote config")?;
    fs::write(&path, text).with_context(|| format!("writing {}", path.display()))?;
    Ok(())
}

pub(crate) fn ssh_args(cfg: &RemoteConfig) -> Vec<String> {
    let mut args = vec![
        "-p".to_string(),
        cfg.ssh_port.to_string(),
        "-o".to_string(),
        "StrictHostKeyChecking=accept-new".to_string(),
        "-o".to_string(),
        "ControlMaster=auto".to_string(),
        "-o".to_string(),
        "ControlPersist=10m".to_string(),
        "-o".to_string(),
        "ControlPath=~/.ssh/jeryu-%r@%h:%p".to_string(),
    ];
    if let Some(identity) = &cfg.identity {
        args.push("-i".to_string());
        args.push(identity.clone());
    }
    args
}

pub(crate) fn make_remote_step(
    id: &str,
    label: &str,
    detail: String,
    command: Option<String>,
    requires_network: bool,
    estimated_seconds: Option<u64>,
) -> RemoteStep {
    RemoteStep {
        id: id.into(),
        label: label.into(),
        detail,
        command,
        requires_network,
        estimated_seconds,
    }
}

pub(crate) fn build_remote_plan(
    cfg: &RemoteConfig,
    setup_key: bool,
    opts: &RemoteCommonOptions,
) -> RemoteInstallPlan {
    let preflight = RemotePreflight {
        local_ssh: command_exists("ssh"),
        local_ssh_keygen: command_exists("ssh-keygen"),
        remote_os: None,
        remote_arch: None,
        remote_docker_ready: None,
        remote_systemd_user: None,
        remote_disk_free_gb: None,
    };
    let mut steps = vec![
        make_remote_step(
            "preflight",
            "check local and remote prerequisites",
            "verify ssh, ssh-keygen, remote OS, docker, and systemd user support".into(),
            Some("ssh -p <port> host 'uname -s; uname -m; command -v docker; docker info; command -v systemctl; df -Pk $HOME'".into()),
            true,
            Some(2),
        ),
        make_remote_step(
            "binary",
            "upload the current binary",
            format!("stream {} to {}", current_exe_string(), cfg.remote_bin),
            Some(format!("ssh {} cat > {}", cfg.target, cfg.remote_bin)),
            true,
            Some(3),
        ),
        make_remote_step(
            "verify",
            "verify remote --version",
            "run the uploaded binary to confirm execution".into(),
            Some(format!("ssh {} {} --version", cfg.target, cfg.remote_bin)),
            true,
            Some(1),
        ),
    ];
    let service_detail = match opts.service_mode {
        ServiceMode::Auto => {
            "enable a user systemd unit when available, otherwise print manual serve guidance"
                .to_string()
        }
        ServiceMode::User => "force user systemd setup".to_string(),
        ServiceMode::Manual => "skip systemd and print manual serve guidance".to_string(),
    };
    steps.push(make_remote_step(
        "service",
        "configure the remote service",
        service_detail,
        Some("systemctl --user enable --now jeryu.service || print manual instructions".into()),
        true,
        Some(2),
    ));
    steps.push(make_remote_step(
        "save",
        "save the remote metadata",
        "write ~/.jeryu/remotes/<alias>.toml after verification".into(),
        Some(format!("write {}", config_path(&cfg.alias).display())),
        false,
        Some(1),
    ));
    RemoteInstallPlan {
        action: "remote-install".into(),
        connection: cfg.connection.clone(),
        options: opts.clone(),
        setup_key,
        preflight,
        steps,
    }
}

pub(crate) fn effective_service_mode(
    requested: ServiceMode,
    remote_systemd_user: Option<bool>,
) -> ServiceMode {
    match requested {
        ServiceMode::Auto => {
            if remote_systemd_user.unwrap_or(false) {
                ServiceMode::User
            } else {
                ServiceMode::Manual
            }
        }
        mode => mode,
    }
}

pub(crate) async fn resolve_service_mode(cfg: &RemoteConfig) -> Result<ServiceMode> {
    match cfg.service_mode {
        ServiceMode::Auto => {
            let preflight = probe_remote(cfg).await?;
            Ok(effective_service_mode(
                ServiceMode::Auto,
                preflight.remote_systemd_user,
            ))
        }
        mode => Ok(mode),
    }
}

pub(crate) fn render_remote_plan(plan: &RemoteInstallPlan) {
    let color = should_colorize(plan.options.color, plan.options.json);
    println!(
        "{} {}",
        status_label(color, "PLAN", "36;1"),
        color_text(color, "1", "Remote install plan")
    );
    println!("  alias: {}", plan.connection.alias);
    println!("  target: {}", plan.connection.target);
    println!("  remote binary: {}", plan.connection.remote_bin);
    println!("  prefix: {}", plan.connection.remote_prefix);
    println!("  service mode: {:?}", plan.options.service_mode);
    println!("  setup key: {}", plan.setup_key);
    println!(
        "  local ssh: {}",
        if plan.preflight.local_ssh {
            "yes"
        } else {
            "no"
        }
    );
    println!(
        "  local ssh-keygen: {}",
        if plan.preflight.local_ssh_keygen {
            "yes"
        } else {
            "no"
        }
    );
    render_plan_steps(
        &plan.steps,
        plan.options.verbose,
        |step| step.requires_network,
        |step| step.label.as_str(),
        |step| step.detail.as_str(),
        |step| step.command.as_deref(),
        color,
        "RUN",
        "OK",
        "36;1",
        "32;1",
    );
}

pub(crate) fn remote_confirmation(
    plan: &RemoteInstallPlan,
    opts: &RemoteCommonOptions,
) -> Result<bool> {
    render_remote_plan(plan);
    prompt_for_confirmation_with_message(
        "Proceed with remote install? [y/N] ",
        "refusing to mutate the remote host without --yes in non-interactive mode",
        opts.interactive,
        opts.yes,
    )
}

pub(crate) fn current_exe_string() -> String {
    match env::current_exe() {
        Ok(path) => path.display().to_string(),
        Err(_) => "(unavailable)".into(),
    }
}

pub(crate) fn command_exists(cmd: &str) -> bool {
    std::process::Command::new("sh")
        .arg("-lc")
        .arg(format!("command -v {cmd} >/dev/null 2>&1"))
        .stdout(Stdio::null())
        .stderr(Stdio::null())
        .status()
        .map(|status| status.success())
        .unwrap_or(false)
}

use anyhow::{Context, Result, bail};
use std::fs;
use std::path::PathBuf;
use std::process::Stdio;
use tokio::process::Command;

pub async fn postgres_state_proof() -> Result<i32> {
    let container = match std::env::var("JERYU_POSTGRES_PROOF_CONTAINER") {
        Ok(value) => value,
        Err(_) => "jeryu-postgres-proof".to_string(),
    };
    let port = match std::env::var("JERYU_POSTGRES_PROOF_PORT") {
        Ok(value) => value,
        Err(_) => "15439".to_string(),
    };
    let db = match std::env::var("JERYU_POSTGRES_PROOF_DB") {
        Ok(value) => value,
        Err(_) => "jeryu_test".to_string(),
    };
    let user = match std::env::var("JERYU_POSTGRES_PROOF_USER") {
        Ok(value) => value,
        Err(_) => "jeryu".to_string(),
    };
    let password = match std::env::var("JERYU_POSTGRES_PROOF_PASSWORD") {
        Ok(value) => value,
        Err(_) => "jeryu_test".to_string(),
    };
    let image = match std::env::var("JERYU_POSTGRES_PROOF_IMAGE") {
        Ok(value) => value,
        Err(_) => "postgres:16-alpine".to_string(),
    };
    let url = format!("postgres://{user}:{password}@127.0.0.1:{port}/{db}");

    let _ = Command::new("docker")
        .args(["rm", "-f", &container])
        .stdout(Stdio::null())
        .stderr(Stdio::null())
        .status()
        .await;

    let mut run = Command::new("docker");
    run.args([
        "run",
        "--rm",
        "-d",
        "--name",
        &container,
        "-e",
        &format!("POSTGRES_DB={db}"),
        "-e",
        &format!("POSTGRES_USER={user}"),
        "-e",
        &format!("POSTGRES_PASSWORD={password}"),
        "-p",
        &format!("127.0.0.1:{port}:5432"),
        &image,
    ]);
    let status = run
        .status()
        .await
        .context("starting postgres proof container")?;
    if !status.success() {
        bail!("docker run failed");
    }

    let cleanup = container.clone();
    let keep = match std::env::var("JERYU_KEEP_POSTGRES_PROOF") {
        Ok(value) => value == "1",
        Err(_) => false,
    };
    let result = async {
        for _ in 0..30 {
            let ready = Command::new("docker")
                .args(["exec", &container, "pg_isready", "-U", &user, "-d", &db])
                .stdout(Stdio::null())
                .stderr(Stdio::null())
                .status()
                .await
                .context("probing postgres readiness")?;
            if ready.success() {
                let mut test = Command::new("cargo");
                test.args([
                    "test",
                    "-p",
                    "jeryu",
                    "state::tests::postgres_backend_smoke_test_when_configured",
                    "--",
                    "--nocapture",
                ]);
                test.env("JERYU_TEST_POSTGRES_URL", &url);
                crate::exec::run_status_check(&mut test, "running postgres proof test").await?;
                return Ok(());
            }
            tokio::time::sleep(std::time::Duration::from_secs(1)).await;
        }
        bail!("postgreSQL proof container did not become ready");
    }
    .await;

    if !keep {
        let _ = Command::new("docker")
            .args(["rm", "-f", &cleanup])
            .stdout(Stdio::null())
            .stderr(Stdio::null())
            .status()
            .await;
    }
    result?;
    Ok(0)
}

pub async fn capture_tui_screenshots(output_dir: Option<PathBuf>) -> Result<i32> {
    let root = repo_root()?;
    let output_dir = match output_dir {
        Some(path) => path,
        None => root.join("paper/assets"),
    };
    let debug_dir = root.join("target/tui-capture");
    fs::create_dir_all(&output_dir)
        .with_context(|| format!("creating {}", output_dir.display()))?;
    fs::create_dir_all(&debug_dir).with_context(|| format!("creating {}", debug_dir.display()))?;

    let cols = std::env::var("JERYU_TUI_CAPTURE_COLS")
        .ok()
        .and_then(|value| value.parse().ok())
        .unwrap_or(160);
    let rows = std::env::var("JERYU_TUI_CAPTURE_ROWS")
        .ok()
        .and_then(|value| value.parse().ok())
        .unwrap_or(48);
    let font_path = match std::env::var("JERYU_TUI_CAPTURE_FONT") {
        Ok(value) => PathBuf::from(value),
        Err(_) => PathBuf::from("/usr/share/fonts/truetype/dejavu/DejaVuSansMono.ttf"),
    };
    let font_size = std::env::var("JERYU_TUI_CAPTURE_FONT_SIZE")
        .ok()
        .and_then(|value| value.parse().ok())
        .unwrap_or(19.0);
    let cell_w = std::env::var("JERYU_TUI_CAPTURE_CELL_W")
        .ok()
        .and_then(|value| value.parse().ok())
        .unwrap_or(12);
    let cell_h = std::env::var("JERYU_TUI_CAPTURE_CELL_H")
        .ok()
        .and_then(|value| value.parse().ok())
        .unwrap_or(23);
    let bg = match std::env::var("JERYU_TUI_CAPTURE_BG") {
        Ok(value) => value,
        Err(_) => "#17212b".to_string(),
    };
    let fg = match std::env::var("JERYU_TUI_CAPTURE_FG") {
        Ok(value) => value,
        Err(_) => "#f4fbff".to_string(),
    };
    let brighten = std::env::var("JERYU_TUI_CAPTURE_BRIGHTEN")
        .ok()
        .and_then(|value| value.parse().ok())
        .unwrap_or(1.35_f32);
    let max_wait_ms = std::env::var("JERYU_TUI_CAPTURE_MAX_WAIT_MS")
        .ok()
        .and_then(|value| value.parse().ok())
        .unwrap_or(8000_u64);
    let min_wait_ms = std::env::var("JERYU_TUI_CAPTURE_MIN_WAIT_MS")
        .ok()
        .and_then(|value| value.parse().ok())
        .unwrap_or(1200_u64);
    let quiet_ms = std::env::var("JERYU_TUI_CAPTURE_QUIET_MS")
        .ok()
        .and_then(|value| value.parse().ok())
        .unwrap_or(300_u64);

    let mut build = Command::new("cargo");
    build
        .args(["build", "--release", "-p", "jeryu", "-p", "tui-capture"])
        .current_dir(&root);
    crate::exec::run_status_check(&mut build, "building tui-capture assets").await?;

    let shots = [
        ("mission", output_dir.join("jeryu-tui-mission.png")),
        ("jobs", output_dir.join("jeryu-tui-jobs-flow.png")),
        ("agents", output_dir.join("jeryu-tui-agents.png")),
        ("tests", output_dir.join("jeryu-tui-tests-vti.png")),
        ("evidence", output_dir.join("jeryu-tui-evidence.png")),
        ("release", output_dir.join("jeryu-tui-release.png")),
    ];

    for (tab, output) in shots {
        let ready_file = tempfile::NamedTempFile::new().context("creating ready file")?;
        let mut cmd = Command::new(root.join("target/release/tui-capture"));
        cmd.arg("--cols").arg(cols.to_string());
        cmd.arg("--rows").arg(rows.to_string());
        cmd.arg("--out").arg(&output);
        cmd.arg("--font").arg(&font_path);
        cmd.arg("--font-size").arg(font_size.to_string());
        cmd.arg("--cell-w").arg(cell_w.to_string());
        cmd.arg("--cell-h").arg(cell_h.to_string());
        cmd.arg("--bg").arg(&bg);
        cmd.arg("--fg").arg(&fg);
        cmd.arg("--brighten").arg(brighten.to_string());
        cmd.arg("--min-wait-ms").arg(min_wait_ms.to_string());
        cmd.arg("--max-wait-ms").arg(max_wait_ms.to_string());
        cmd.arg("--quiet-ms").arg(quiet_ms.to_string());
        cmd.arg("--ready-file").arg(ready_file.path());
        cmd.arg("--dump-text")
            .arg(debug_dir.join(format!("{tab}.txt")));
        cmd.arg("--");
        cmd.arg(root.join("target/release/jeryu"));
        cmd.arg("tui");
        cmd.arg("--screenshot");
        cmd.arg("--tab").arg(tab);
        cmd.arg("--screenshot-hold-ms").arg("10000");
        crate::exec::run_status_check(&mut cmd, &format!("tui capture failed for {tab}")).await?;
        if !ready_file.path().exists() {
            bail!("TUI did not signal readiness for {tab}");
        }
    }
    Ok(0)
}

fn repo_root() -> Result<PathBuf> {
    let mut dir = std::env::current_dir().context("resolving current directory")?;
    loop {
        if dir.join("Cargo.toml").is_file() {
            return Ok(dir);
        }
        if !dir.pop() {
            bail!("unable to locate repo root");
        }
    }
}

//! Owner: Workload Sandbox (Network-Namespace Isolation)
//! Proof: `cargo test -p jeryu -- sandbox`
//! Invariants: strict_network_isolation fails closed unless an isolation backend is available;
//!             all env vars flow through SandboxConfig, never shell-escaped; do not weaken isolation without an AER

use anyhow::{Context, Result};
use std::process::Stdio;
use tokio::process::{Child, Command};

#[derive(Debug, Clone)]
pub struct SandboxConfig {
    pub use_strict_network_isolation: bool,
    pub proxy_host: String,
    pub proxy_port: u16,
    pub bind_workspace: String,
    pub extra_envs: Vec<(String, String)>,
}

pub struct ExecutorSandbox {
    config: SandboxConfig,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SandboxBackend {
    SoftLocal,
    Bubblewrap,
    Unshare,
    Unavailable,
}

impl ExecutorSandbox {
    pub fn new(config: SandboxConfig) -> Self {
        Self { config }
    }

    pub fn selected_backend(&self) -> SandboxBackend {
        if !self.config.use_strict_network_isolation {
            return SandboxBackend::SoftLocal;
        }
        detect_strict_backend()
    }

    /// Spawns the workload, optionally inside a strict network namespace
    /// using `unshare` or `bwrap` depending on the environment capabilities.
    /// Strict mode never silently downgrades to soft local execution.
    pub fn spawn_script(&self, script_path: &str) -> Result<Child> {
        let mut cmd = match self.selected_backend() {
            SandboxBackend::SoftLocal => Command::new("bash"),
            SandboxBackend::Bubblewrap => {
                let mut c = Command::new("bwrap");
                c.arg("--die-with-parent")
                    .arg("--unshare-net")
                    .arg("--proc")
                    .arg("/proc")
                    .arg("--dev")
                    .arg("/dev")
                    .arg("--ro-bind")
                    .arg("/")
                    .arg("/")
                    .arg("--tmpfs")
                    .arg("/tmp")
                    .arg("--chdir")
                    .arg(&self.config.bind_workspace)
                    .arg("bash");
                c.env("JERYU_SANDBOXED", "strict:bwrap");
                c
            }
            SandboxBackend::Unshare => {
                let mut c = Command::new("unshare");
                c.arg("--net").arg("--").arg("bash");
                c.env("JERYU_SANDBOXED", "strict:unshare");
                c
            }
            SandboxBackend::Unavailable => {
                anyhow::bail!(
                    "strict network isolation requested but neither bwrap nor unshare is available"
                );
            }
        };

        cmd.arg(script_path);

        if !self.config.proxy_host.is_empty() && self.config.proxy_port != 0 {
            let proxy_url = format!(
                "http://{}:{}",
                self.config.proxy_host, self.config.proxy_port
            );
            cmd.env("HTTP_PROXY", &proxy_url)
                .env("HTTPS_PROXY", &proxy_url)
                .env("NO_PROXY", "localhost,127.0.0.1,::1");
        }

        for (k, v) in &self.config.extra_envs {
            cmd.env(k, v);
        }

        cmd.stdout(Stdio::piped()).stderr(Stdio::piped());

        cmd.spawn().context("Failed to spawn sandboxed script")
    }
}

fn detect_strict_backend() -> SandboxBackend {
    if command_exists("bwrap") {
        SandboxBackend::Bubblewrap
    } else if command_exists("unshare") {
        SandboxBackend::Unshare
    } else {
        SandboxBackend::Unavailable
    }
}

fn command_exists(command: &str) -> bool {
    std::env::var_os("PATH")
        .and_then(|paths| {
            std::env::split_paths(&paths)
                .map(|path| path.join(command))
                .find(|path| path.is_file())
        })
        .is_some()
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::io::Write;

    #[tokio::test]
    async fn test_sandbox_proxy_injection() {
        let config = SandboxConfig {
            use_strict_network_isolation: false,
            proxy_host: "127.0.0.1".into(),
            proxy_port: 19800,
            bind_workspace: "/tmp".into(),
            extra_envs: vec![],
        };
        let sandbox = ExecutorSandbox::new(config);

        let mut script_file = tempfile::NamedTempFile::new().unwrap();
        script_file.write_all(b"echo $HTTP_PROXY").unwrap();

        let child = sandbox
            .spawn_script(script_file.path().to_str().unwrap())
            .unwrap();
        let output = child.wait_with_output().await.unwrap();
        let stdout = String::from_utf8_lossy(&output.stdout);
        assert_eq!(stdout.trim(), "http://127.0.0.1:19800");
    }

    #[test]
    fn soft_mode_reports_soft_backend() {
        let config = SandboxConfig {
            use_strict_network_isolation: false,
            proxy_host: "10.0.0.1".into(),
            proxy_port: 8080,
            bind_workspace: "/tmp".into(),
            extra_envs: vec![],
        };
        let sandbox = ExecutorSandbox::new(config);
        assert_eq!(sandbox.selected_backend(), SandboxBackend::SoftLocal);
    }

    #[tokio::test]
    async fn strict_sandbox_never_silently_downgrades_to_soft() {
        let config = SandboxConfig {
            use_strict_network_isolation: true,
            proxy_host: "10.0.0.1".into(),
            proxy_port: 8080,
            bind_workspace: "/tmp".into(),
            extra_envs: vec![],
        };
        let sandbox = ExecutorSandbox::new(config);

        let mut script_file = tempfile::NamedTempFile::new().unwrap();
        script_file.write_all(b"echo $JERYU_SANDBOXED").unwrap();

        match sandbox.selected_backend() {
            SandboxBackend::Unavailable => {
                let err = sandbox
                    .spawn_script(script_file.path().to_str().unwrap())
                    .unwrap_err()
                    .to_string();
                assert!(err.contains("strict network isolation requested"));
            }
            SandboxBackend::Bubblewrap | SandboxBackend::Unshare => {}
            SandboxBackend::SoftLocal => panic!("strict mode reported soft local backend"),
        }
    }
}

//! Owner: sccache Management subsystem
//! Proof: `cargo nextest run -p jeryu -- sccache_mgr`
//! Invariants: Cache workers stay isolated by manager namespace and report health before reuse.
use anyhow::{Context, Result};
use std::path::{Path, PathBuf};

/// Manages sccache daemon and environment configurations for sandboxed runners.
pub struct SccacheManager {
    pub cache_dir: PathBuf,
    pub cache_size: String,
}

impl SccacheManager {
    pub fn new(cache_dir: PathBuf) -> Self {
        Self {
            cache_dir,
            cache_size: "10G".to_string(),
        }
    }

    pub fn new_with_size(cache_dir: PathBuf, cache_size: String) -> Self {
        Self {
            cache_dir,
            cache_size,
        }
    }

    pub fn cache_path(&self) -> &Path {
        &self.cache_dir
    }

    /// Provides the environment variables to inject into the `ExecutorSandbox`
    /// to seamlessly route rustc invocations through sccache.
    pub fn inject_env(&self) -> Vec<(String, String)> {
        vec![
            ("RUSTC_WRAPPER".to_string(), "sccache".to_string()),
            (
                "SCCACHE_DIR".to_string(),
                self.cache_dir.to_string_lossy().to_string(),
            ),
            // Force incremental off — incompatible with sccache's object-level caching
            ("CARGO_INCREMENTAL".to_string(), "0".to_string()),
            // Run inline (no daemon process) — correct for per-job container use
            ("SCCACHE_NO_DAEMON".to_string(), "1".to_string()),
            // Cap disk usage per manager; sccache evicts LRU entries above this
            ("SCCACHE_CACHE_SIZE".to_string(), self.cache_size.clone()),
        ]
    }
}

/// Manages branch-scoped L1 caching for Cargo's `target/` directory.
pub struct CargoL1Hydrator {
    pub storage_dir: PathBuf,
}

impl CargoL1Hydrator {
    pub fn new(storage_dir: PathBuf) -> Self {
        Self { storage_dir }
    }

    pub fn snapshot_name(&self, branch_name: &str) -> PathBuf {
        let sanitized = branch_name.replace('/', "_");
        self.storage_dir
            .join(format!("target_{}.tar.zst", sanitized))
    }

    /// Unarchive the L1 target/ cache into the sandbox for the given branch.
    /// Returns Ok(true) if hydration succeeded, Ok(false) if no snapshot exists.
    pub async fn hydrate(&self, branch_name: &str, target_dir: &Path) -> Result<bool> {
        let snapshot = self.snapshot_name(branch_name);
        if snapshot.exists() {
            tracing::info!("Hydrating L1 target/ cache for branch {}", branch_name);
            let status = tokio::process::Command::new("tar")
                .arg("-I")
                .arg("zstd")
                .arg("-xf")
                .arg(&snapshot)
                .arg("-C")
                .arg(target_dir)
                .status()
                .await
                .context("Failed to run tar for L1 hydration")?;
            if status.success() {
                tracing::info!("L1 hydration complete from {:?}", snapshot);
                Ok(true)
            } else {
                tracing::warn!(
                    "L1 hydration tar failed with exit {:?}; starting cold",
                    status.code()
                );
                Ok(false)
            }
        } else {
            Ok(false)
        }
    }

    /// Capture the target/ directory into a branch-scoped zstd archive for future hydration.
    pub async fn snapshot(&self, branch_name: &str, target_dir: &Path) -> Result<()> {
        let snapshot = self.snapshot_name(branch_name);
        if let Some(parent) = snapshot.parent() {
            std::fs::create_dir_all(parent)?;
        }
        let status = tokio::process::Command::new("tar")
            .arg("-I")
            .arg("zstd")
            .arg("-cf")
            .arg(&snapshot)
            .arg("-C")
            .arg(target_dir)
            .arg(".")
            .status()
            .await
            .context("Failed to run tar for L1 snapshot")?;
        if status.success() {
            tracing::info!("L1 snapshot captured to {:?}", snapshot);
        } else {
            tracing::warn!("L1 snapshot tar failed with exit {:?}", status.code());
        }
        Ok(())
    }
}

