    let m: TestMap = toml::from_str(
        r#"
[policy]
full_on_unknown = false
min_confidence = 0.50

[global_invalidators]
paths = ["Cargo.lock"]

[[subsystem]]
id = "app"
paths = ["src/**"]
ci_jobs = ["test"]
"#,
    )
    .unwrap();
    // With full_on_unknown = false, unmatched paths don't trigger full
    let plan = plan_from_testmap(&m, &["unknown/path.rs".into()]);
    // No subsystem matched, and no full-on-unknown, so selected with 0 jobs
    // But with unmatched penalty it might dip below confidence...
    // Actually with no matched subsystems and some unmatched, confidence = 1.0 - 0.15 = 0.85
    // min_confidence = 0.50, so this stays at Selected with 0 jobs
    assert_ne!(plan.mode, ExternalPlanMode::Full);
}

//! Owner: CI Test Runner subsystem
//! Proof: `cargo nextest run -p jeryu -- test_runner`
//! Invariants: Test execution preserves lane semantics and reports enough structure for VTI feedback.
//! Test Runner: Agent-friendly single-test execution via jeryu.
//!
//! Enables an agent to run a single test (or set of tests) through the
//! GitLab CI pipeline and get structured results back. Works by creating
//! a dynamic pipeline with just the requested test command.

use anyhow::Result;
use serde::{Deserialize, Serialize};
use std::cmp::max;

// ---------------------------------------------------------------------------
// Public types
// ---------------------------------------------------------------------------

/// Result of a test run through the CI pipeline.
#[derive(Debug, Serialize, Deserialize)]
pub struct TestRunResult {
    pub pipeline_id: i64,
    pub job_id: Option<i64>,
    pub job_name: String,
    pub status: String,
    pub duration_secs: Option<f64>,
    pub trace_tail: String,
    pub passed: bool,
}

/// Planning metadata for a test run.
#[derive(Debug, Serialize, Deserialize)]
pub struct TestRunPlan {
    pub command: String,
    pub job_name: String,
    pub image: String,
    pub tags: Vec<String>,
    pub timeout_secs: u64,
    pub risk_class: String,
    pub rationale: Vec<String>,
}

/// Options for running a test.
#[derive(Debug, Clone)]
pub struct TestRunOpts {
    pub project_id: i64,
    pub test_command: String,
    pub job_name: Option<String>,
    pub image: String,
    pub tags: Option<Vec<String>>,
    pub timeout_secs: u64,
    pub force: bool,
    pub commit_sha: String,
}

impl Default for TestRunOpts {
    fn default() -> Self {
        Self {
            project_id: 2,
            test_command: String::new(),
            job_name: None,
            image: "rust:1.92.0".to_string(),
            tags: None,
            timeout_secs: 600,
            force: false,
            commit_sha: "latest".to_string(),
        }
    }
}

/// Options for running multiple tests in parallel through CI pipelines.
#[derive(Debug, Clone)]
pub struct TestBatchOpts {
    pub project_id: i64,
    pub test_commands: Vec<String>,
    pub job_name_prefix: Option<String>,
    pub image: String,
    pub tags: Option<Vec<String>>,
    pub timeout_secs: u64,
    pub max_parallel: usize,
    pub force: bool,
    pub commit_sha: String,
}

impl Default for TestBatchOpts {
    fn default() -> Self {
        Self {
            project_id: 2,
            test_commands: Vec::new(),
            job_name_prefix: None,
            image: "rust:1.92.0".to_string(),
            tags: None,
            timeout_secs: 600,
            max_parallel: 3,
            force: false,
            commit_sha: "latest".to_string(),
        }
    }
}

// ---------------------------------------------------------------------------
// Core API
// ---------------------------------------------------------------------------

pub fn plan_test_run(opts: &TestRunOpts) -> TestRunPlan {
    let job_name = match opts.job_name.clone() {
        Some(value) => value,
        None => "jeryu-test-run".to_string(),
    };
    let inferred = match opts.tags.clone() {
        Some(value) => value,
        None => infer_test_tags(&opts.test_command),
    };
    let routing = infer_test_routing(&opts.test_command);
    let timeout_secs = if opts.timeout_secs == TestRunOpts::default().timeout_secs {
        routing.timeout_secs
    } else {
        opts.timeout_secs
    };

    TestRunPlan {
        command: opts.test_command.clone(),
        job_name,
        image: opts.image.clone(),
        tags: inferred,
        timeout_secs,
        risk_class: routing.risk_class,
        rationale: routing.rationale,
    }
}

pub(crate) fn render_ephemeral_ci_yaml(plan: &TestRunPlan) -> String {
    let tags_yaml = plan
        .tags
        .iter()
        .map(|t| format!("    - {}", t))
        .collect::<Vec<_>>()
        .join("\n");

    format!(
        r#"# Auto-generated by jeryu test run — ephemeral pipeline
{job_name}:
  stage: test
  image: {image}
  tags:
{tags}
  variables:
    GIT_STRATEGY: clone
    GIT_CLONE_PATH: "$CI_BUILDS_DIR/$CI_PROJECT_PATH_SLUG-jeryu-$CI_PIPELINE_ID-$CI_JOB_ID"
  script:
    - {command}
"#,
        job_name = plan.job_name,
        image = plan.image,
        tags = tags_yaml,
        command = plan.command,
    )
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

struct TestRoutingInference {
    tags: Vec<String>,
    risk_class: String,
    timeout_secs: u64,
    rationale: Vec<String>,
}

fn infer_test_tags(command: &str) -> Vec<String> {
    infer_test_routing(command).tags
}

fn infer_test_routing(command: &str) -> TestRoutingInference {
    let lower = command.to_ascii_lowercase();

    let untrusted_patterns = [
        "security",
        "chaos",
        "ip_exfiltration",
        "ip guard",
        "ip-guard",
        "sandbox",
        "fuzz",
    ];
    if untrusted_patterns
        .iter()
        .any(|pattern| lower.contains(pattern))
    {
        return TestRoutingInference {
            tags: vec!["untrusted".to_string()],
            risk_class: "untrusted".to_string(),
            timeout_secs: 1800,
            rationale: vec!["matched untrusted/risky command pattern".to_string()],
        };
    }

    let build_patterns = [
        "deployctl",
        "payloadctl",
        "build-local",
        "publish-rc",
        "cargo check",
        "cargo build",
        "cargo nextest",
        "cargo test --workspace",
        "cargo test -p veox-deploy",
        "cargo test -p veox-bootstrap",
        "cargo test -p veox-rc-gate",
        "cargo test -p cargo-vrc",
        "cargo test -p cargo-aer",
        "cargo test -p cargo-witness",
        "cargo test -p nht",
        "test-local-built",
        "test-local-rc",
        "deploy-canary",
    ];
    if build_patterns.iter().any(|pattern| lower.contains(pattern)) {
        return TestRoutingInference {
            tags: vec!["build".to_string()],
            risk_class: "build".to_string(),
            timeout_secs: 1200,
            rationale: vec!["matched build-heavy command pattern".to_string()],
        };
    }

    TestRoutingInference {
        tags: vec!["default".to_string()],
        risk_class: "default".to_string(),
        timeout_secs: max(600, TestRunOpts::default().timeout_secs),
        rationale: vec!["no heavy/risky pattern matched; using default runner".to_string()],
    }
}

