//! Owner: Interactive TUI subsystem — flow graph builder
//! Proof: `cargo nextest run -p jeryu -- tui::flow`
//! Invariants: Flow graphs are derived from job events and preserve lane/column classification deterministically.

use super::model::{
    BackendRef, FlowColumn, FlowColumnKind, FlowEdge, FlowGraph, FlowNode, LaneGroup, LaneKind,
};
use crate::state::JobEvent;
use std::collections::{BTreeMap, HashMap};

pub fn classify_column(job_name: &str) -> FlowColumnKind {
    let lower = job_name.to_lowercase();
    if lower.contains("hook") || lower.contains("policy") || lower.contains("admission") {
        FlowColumnKind::Admission
    } else if lower.contains("impact") || lower.contains("plan") {
        FlowColumnKind::Impact
    } else if lower.contains("build") || lower.contains("compile") || lower.contains("image") {
        FlowColumnKind::Build
    } else if lower.contains("test")
        || lower.contains("unit")
        || lower.contains("integration")
        || lower.contains("e2e")
        || lower.contains("lint")
        || lower.contains("fmt")
    {
        FlowColumnKind::Tests
    } else if lower.contains("security")
        || lower.contains("secret")
        || lower.contains("honeypot")
        || lower.contains("guard")
    {
        FlowColumnKind::Security
    } else if lower.contains("package") || lower.contains("publish") {
        FlowColumnKind::Package
    } else if lower.contains("gate") || lower.contains("telemetry") {
        FlowColumnKind::ReleaseGates
    } else if lower.contains("canary") {
        FlowColumnKind::Canary
    } else if lower.contains("prod") || lower.contains("deploy") {
        FlowColumnKind::Production
    } else {
        FlowColumnKind::Other
    }
}

pub fn classify_lane(job_name: &str) -> LaneKind {
    let lower = job_name.to_lowercase();
    if lower.contains("unit") || lower.contains("local") || lower.contains("lib") {
        LaneKind::Unit
    } else if lower.contains("integration") || lower.contains("e2e") || lower.contains("live") {
        LaneKind::Integration
    } else if lower.contains("security") || lower.contains("secret") || lower.contains("guard") {
        LaneKind::Security
    } else if lower.contains("build") || lower.contains("compile") {
        LaneKind::Build
    } else if lower.contains("admission") || lower.contains("hook") {
        LaneKind::Admission
    } else if lower.contains("canary")
        || lower.contains("prod")
        || lower.contains("deploy")
        || lower.contains("gate")
    {
        LaneKind::ReleaseExecution
    } else {
        LaneKind::Other
    }
}

/// Stable node ID: hash of (pipeline_id, job_name) so selection survives refreshes.
fn stable_node_id(pipeline_id: i64, job_name: &str) -> i64 {
    // FNV-1a 64-bit
    let mut hash: u64 = 14695981039346656037;
    for b in job_name.bytes() {
        hash ^= b as u64;
        hash = hash.wrapping_mul(1099511628211);
    }
    // Mix in pipeline_id to avoid cross-pipeline collisions
    hash ^= pipeline_id as u64;
    hash = hash.wrapping_mul(1099511628211);
    (hash & 0x7FFF_FFFF_FFFF_FFFF) as i64
}

pub fn build_graph(pipeline_id: i64, jobs: Vec<JobEvent>) -> FlowGraph {
    let mut nodes = Vec::new();
    let now = chrono::Utc::now();

    for job in jobs.into_iter() {
        let name = job.job_name.as_deref().unwrap_or("unknown").to_string();
        let column = classify_column(&name);
        let lane = classify_lane(&name);

        let active = job.status == "running" || job.status == "pending" || job.status == "created";
        let mut elapsed_secs = 0;
        if let Ok(st) = chrono::DateTime::parse_from_rfc3339(&job.received_at) {
            elapsed_secs = now.signed_duration_since(st).num_seconds();
        }

        let eta = if active {
            Some(super::eta::estimate_job_eta(&name, lane, elapsed_secs))
        } else {
            None
        };

        let progress_pct = match job.status.as_str() {
            "success" => 100,
            "failed" | "canceled" => 50,
            "running" => {
                if let Some(ref e) = eta {
                    let total = e.remaining_secs + elapsed_secs;
                    if total > 0 {
                        ((elapsed_secs as f64 / total as f64) * 99.0) as u16
                    } else {
                        50
                    }
                } else {
                    ((elapsed_secs as f64 / 120.0) * 100.0).min(99.0) as u16
                }
            }
            _ => 0,
        };

        let backend = BackendRef {
            project_id: job.project_id,
            job_id: job.job_id,
            pipeline_id: job.pipeline_id,
            status: job.status.clone(),
            queued_duration: job.queued_duration,
            received_at: job.received_at.clone(),
        };

        let node = FlowNode {
            id: stable_node_id(pipeline_id, &name),
            job_id: Some(job.job_id),
            label: name.clone(),
            column,
            lane,
            status: job.status.clone(),
            progress_pct,
            eta,
            is_required: true,
            is_critical_path: false, // computed after edge build
            backend: Some(backend),
            elapsed_secs,
            // v3 defaults — populated by VTI enrichment pass:
            vti_status: None,
            cache_verdict: None,
            flake_probability: None,
            capsule_id: None,
            attempt_lineage: Vec::new(),
            agent_id: None,
        };
        nodes.push(node);
    }

    // Now organize into columns and lanes Grouping
    let mut columns = Vec::new();
    let col_kinds = vec![
        FlowColumnKind::Commit,
        FlowColumnKind::Admission,
        FlowColumnKind::Impact,
        FlowColumnKind::Pipeline,
        FlowColumnKind::Build,
        FlowColumnKind::Tests,
        FlowColumnKind::Security,
        FlowColumnKind::Package,
        FlowColumnKind::ReleaseGates,
        FlowColumnKind::Canary,
        FlowColumnKind::Production,
        FlowColumnKind::Other,
    ];

    for kind in col_kinds {
        let col_nodes: Vec<&FlowNode> = nodes.iter().filter(|n| n.column == kind).collect();
        if col_nodes.is_empty() && kind != FlowColumnKind::Pipeline {
            // Always keep Pipeline col.
            continue;
        }

        // Group by lane
        let mut lanes_map: BTreeMap<LaneKind, Vec<i64>> = BTreeMap::new();
        for node in &col_nodes {
            lanes_map.entry(node.lane).or_default().push(node.id);
        }

        let mut lane_groups = Vec::new();
        for (lane_kind, node_ids) in lanes_map {
            lane_groups.push(LaneGroup {
                lane: lane_kind,
                title: lane_kind.to_str().to_string(),
                node_ids,
            });
        }

        columns.push(FlowColumn {
            key: kind,
            title: kind.to_str().to_string(),
            status: "active".to_string(), // default until job state arrives
            eta: None,                    // pipeline-level eta goes here later
            lane_groups,
        });
    }

    // Build stage-ordering edges: jobs in column N depend on all jobs in column N-1.
    let col_order: Vec<FlowColumnKind> = columns.iter().map(|c| c.key).collect();
    let mut edges = Vec::new();
    for win in col_order.windows(2) {
        let (from_kind, to_kind) = (win[0], win[1]);
        let from_ids: Vec<i64> = nodes
            .iter()
            .filter(|n| n.column == from_kind)
            .map(|n| n.id)
            .collect();
        let to_ids: Vec<i64> = nodes
            .iter()
            .filter(|n| n.column == to_kind)
            .map(|n| n.id)
            .collect();
        for &from in &from_ids {
            for &to in &to_ids {
                edges.push(FlowEdge { from, to, kind: crate::api::snapshot::EdgeKind::StageOrder });
            }
        }
    }

    // Compute critical path via DAG longest-path (expected duration = eta remaining + elapsed).
    // We use a simple topological sort over the edge graph.
    let critical_path_ids = compute_critical_path(&nodes, &edges);
    for node in &mut nodes {
        node.is_critical_path = critical_path_ids.contains(&node.id);
    }

    FlowGraph {
        columns,
        nodes,
        edges,
    }
}

/// DAG longest-path to find the critical path.
/// Each node's weight = elapsed_secs + eta.remaining_secs (or a lane default if eta is None).
fn compute_critical_path(nodes: &[FlowNode], edges: &[FlowEdge]) -> std::collections::HashSet<i64> {
    if nodes.is_empty() {
        return std::collections::HashSet::new();
    }

    // Build adjacency: node_id -> successors
    let mut successors: HashMap<i64, Vec<i64>> = HashMap::new();
    let mut predecessors: HashMap<i64, Vec<i64>> = HashMap::new();
    for node in nodes {
        successors.entry(node.id).or_default();
        predecessors.entry(node.id).or_default();
    }
    for edge in edges {
        successors.entry(edge.from).or_default().push(edge.to);
        predecessors.entry(edge.to).or_default().push(edge.from);
    }

    // Node weight: estimated total duration
    let weight: HashMap<i64, i64> = nodes
        .iter()
        .map(|n| {
            let w = n.elapsed_secs + n.eta.as_ref().map(|e| e.remaining_secs).unwrap_or(0);
            (n.id, w.max(1))
        })
        .collect();

    // Topological sort (Kahn's algorithm)
    let mut in_degree: HashMap<i64, usize> = nodes.iter().map(|n| (n.id, 0)).collect();
    for edge in edges {
        *in_degree.entry(edge.to).or_insert(0) += 1;
    }

    let mut queue: std::collections::VecDeque<i64> = in_degree
        .iter()
        .filter(|(_, d)| **d == 0)
        .map(|(id, _)| *id)
        .collect();

    // dist[id] = max cost path ending at id; prev[id] = predecessor on that path
    let mut dist: HashMap<i64, i64> = nodes
        .iter()
        .map(|n| (n.id, *weight.get(&n.id).unwrap_or(&1)))
        .collect();
    let mut prev: HashMap<i64, Option<i64>> = nodes.iter().map(|n| (n.id, None)).collect();
    let mut topo_order = Vec::new();

    while let Some(u) = queue.pop_front() {
        topo_order.push(u);
        for &v in successors.get(&u).map(|s| s.as_slice()).unwrap_or(&[]) {
            let new_dist = dist[&u] + weight.get(&v).unwrap_or(&1);
            if new_dist > dist[&v] {
                dist.insert(v, new_dist);
                prev.insert(v, Some(u));
            }
            let deg = in_degree.entry(v).or_insert(1);
            *deg = deg.saturating_sub(1);
            if *deg == 0 {
                queue.push_back(v);
            }
        }
    }

    // Find the node with the maximum distance (end of critical path)
    let Some((end_id_ref, _)) = dist.iter().max_by_key(|(_, v)| *v) else {
        return std::collections::HashSet::new();
    };
    let end_id = *end_id_ref;

    // Trace back the critical path
    let mut critical = std::collections::HashSet::new();
    let mut cur = end_id;
    loop {
        critical.insert(cur);
        match prev.get(&cur).and_then(|p| *p) {
            Some(p) => cur = p,
            None => break,
        }
    }
    critical
}

//! Owner: Interactive TUI subsystem — flow snapshot collector
//! Proof: `cargo nextest run -p jeryu -- tui::flow`
//! Invariants: Collection is best-effort, bounded, and never blocks the TUI render loop on remote state.

use super::model::{FlowGraph, FlowSnapshot, PipelineFlow};
use crate::{
    docker::DockerCtl,
    gitlab_client::{GitlabClient, Job},
    release,
    state::{CiJobRun, JobEvent, TrackedPipeline, TuiSession}, // allowlist: TUI session import
};
use std::collections::BTreeSet;
use tokio::sync::mpsc;
use tokio::sync::watch;

pub async fn run_collector(
    session: TuiSession,
    docker: DockerCtl,
    gitlab: GitlabClient,
    tx: mpsc::Sender<FlowSnapshot>,
    _log_rx: watch::Receiver<Option<crate::tui::app::LogTarget>>,
) {
    let mut last_active_pipelines: Vec<PipelineFlow> = Vec::new();
    let mut last_active_seen_at: Option<chrono::DateTime<chrono::Utc>> = None;

    loop {
        let mut snap = FlowSnapshot {
            generated_at: chrono::Utc::now(),
            ..Default::default()
        };

        if let Ok(pools) = session.list_pools().await {
            snap.pools = pools;
        }

        if let Ok(managed) = docker.list_managed_containers().await {
            snap.active_containers = managed.len();
        }

        snap.gitlab_online = gitlab.is_ready().await;

        let mut release_pipeline_hint = None;
        if let Ok(report) = release::build_release_status_report(
            &session,
            release::ReleaseStatusQuery {
                project_id: Some(release::DEFAULT_RELEASE_PROJECT_ID),
                ref_name: Some("main".into()),
                sha: None,
                limit: 1,
            },
        )
        .await
        {
            release_pipeline_hint = report.latest.as_ref().and_then(|view| {
                view.attempt.release_pipeline_id.map(|pipeline_id| {
                    (
                        view.attempt.project_id,
                        pipeline_id,
                        view.attempt.ref_name.clone(),
                        view.attempt.sha.clone(),
                        match view.attempt.release_pipeline_status.clone() {
                            Some(value) => value,
                            None => "unknown".to_string(),
                        },
                    )
                })
            });
            snap.release = report.latest;
        }

        if let Ok(metrics) = session.get_cache_metrics().await {
            snap.cache_metrics.hot_usage_bytes = metrics.bytes_served;
            snap.cache_metrics.hits = metrics.hit_count;
            snap.cache_metrics.objects = metrics.object_count;
            snap.cache_metrics.singleflight_coalesced = metrics.singleflight_coalesced;
            snap.cache_metrics.hit_ratio = metrics.hit_ratio;
            snap.cache_metrics.misses = metrics.miss_count;
            snap.cache_metrics.requests = metrics.total_requests;
        }

        let mut included_pipeline_ids = BTreeSet::new();
        if let Ok(pipes) = session.list_tracked_pipelines(5).await {
            for p in pipes {
                included_pipeline_ids.insert(p.pipeline_id);
                snap.active_pipelines
                    .push(build_tracked_pipeline_flow(&session, &gitlab, p).await);
            }
        }

        if let Some((project_id, pipeline_id, ref_name, sha, status)) = release_pipeline_hint
            && included_pipeline_ids.insert(pipeline_id)
            && let Some(flow) =
                build_gitlab_pipeline_flow(&gitlab, project_id, pipeline_id, ref_name, sha, status)
                    .await
        {
            snap.active_pipelines.insert(0, flow);
        }

        if snap.active_pipelines.is_empty() {
            if !last_active_pipelines.is_empty() {
                snap.active_pipelines = last_active_pipelines.clone();
                snap.outdated = true;
                snap.last_non_empty_at = last_active_seen_at;
            }
        } else {
            last_active_pipelines = snap.active_pipelines.clone();
            last_active_seen_at = Some(snap.generated_at);
            snap.last_non_empty_at = last_active_seen_at;
        }

        if tx.send(snap).await.is_err() {
            break;
        }

        tokio::time::sleep(std::time::Duration::from_millis(1500)).await;
    }
}

async fn build_tracked_pipeline_flow(
    session: &TuiSession,
    gitlab: &GitlabClient,
    pipeline: TrackedPipeline,
) -> PipelineFlow {
    let mut jobs = match session
        .list_ci_job_runs(pipeline.project_id, pipeline.pipeline_id)
        .await
    {
        Ok(runs) => runs.into_iter().map(ci_job_run_to_event).collect(),
        Err(_) => Vec::new(),
    };

    if jobs.is_empty()
        && let Ok(gitlab_jobs) = gitlab
            .list_pipeline_jobs_with_downstream(pipeline.project_id, pipeline.pipeline_id)
            .await
    {
        jobs = gitlab_jobs_to_events(pipeline.project_id, pipeline.pipeline_id, gitlab_jobs);
    }

    pipeline_flow_from_graph(
        pipeline.pipeline_id,
        pipeline.project_id,
        pipeline.ref_name,
        Some(pipeline.sha),
        pipeline.status,
        super::builder::build_graph(pipeline.pipeline_id, jobs),
    )
}

fn ci_job_run_to_event(run: CiJobRun) -> JobEvent {
    let received_at = match (run.started_at.clone(), run.finished_at.clone()) {
        (Some(started_at), _) => started_at,
        (None, Some(finished_at)) => finished_at,
        (None, None) => run.observed_at.clone(),
    };
    let pool_name = run.runner_pool.clone();
    JobEvent {
        job_id: run.job_id,
        project_id: run.project_id,
        pipeline_id: Some(run.pipeline_id),
        status: run.status,
        job_name: Some(run.job_name),
        pool_name,
        system_id: None,
        queued_duration: run.queued_duration_secs,
        received_at,
    }
}

async fn build_gitlab_pipeline_flow(
    gitlab: &GitlabClient,
    project_id: i64,
    pipeline_id: i64,
    default_ref_name: String,
    default_sha: String,
    default_status: String,
) -> Option<PipelineFlow> {
    let pipeline = gitlab.get_pipeline(project_id, pipeline_id).await.ok();
    let jobs = gitlab
        .list_pipeline_jobs_with_downstream(project_id, pipeline_id)
        .await
        .ok()?;
    let events = gitlab_jobs_to_events(project_id, pipeline_id, jobs);
    let ref_name = match pipeline.as_ref() {
        Some(pipeline) => pipeline.ref_name.clone(),
        None => default_ref_name,
    };
    let sha = match pipeline.as_ref() {
        Some(pipeline) => pipeline.sha.clone(),
        None => default_sha,
    };
    let status = match pipeline.as_ref() {
        Some(pipeline) => pipeline.status.clone(),
        None => default_status,
    };

    Some(pipeline_flow_from_graph(
        pipeline_id,
        project_id,
        ref_name,
        Some(sha),
        status,
        super::builder::build_graph(pipeline_id, events),
    ))
}

fn gitlab_jobs_to_events(project_id: i64, pipeline_id: i64, jobs: Vec<Job>) -> Vec<JobEvent> {
    let now = chrono::Utc::now().to_rfc3339();
    jobs.into_iter()
        .map(|job| {
            let pool_name = job
                .runner
                .and_then(|runner| runner.description)
                .or(Some(job.stage.clone()));
            let received_at = if let Some(started_at) = job.started_at.clone() {
                started_at
            } else if let Some(finished_at) = job.finished_at.clone() {
                finished_at
            } else {
                now.clone()
            };
            JobEvent {
                job_id: job.id,
                project_id,
                pipeline_id: Some(pipeline_id),
                status: job.status,
                job_name: Some(job.name),
                pool_name,
                system_id: None,
                queued_duration: job.queued_duration,
                received_at,
            }
        })
        .collect()
}

fn pipeline_flow_from_graph(
    pipeline_id: i64,
    project_id: i64,
    ref_name: String,
    sha: Option<String>,
    status: String,
    graph: FlowGraph,
) -> PipelineFlow {
    let total = graph.nodes.len();
    let mut completed = 0;
    let mut running = 0;
    for n in &graph.nodes {
        if n.status == "success" || n.status == "failed" || n.status == "canceled" {
            completed += 1;
        } else if n.status == "running" {
            running += 1;
        }
    }

    let pct = if total > 0 {
        let effective = completed as f64 + (running as f64 * 0.5);
        ((effective / total as f64) * 100.0) as u16
    } else {
        0
    };

    let cur_blocker = graph
        .nodes
        .iter()
        .filter(|n| n.status == "running" || n.status == "failed")
        .max_by_key(|n| n.elapsed_secs)
        .and_then(|n| n.job_id);

    PipelineFlow {
        pipeline_id,
        project_id,
        ref_name,
        sha,
        status,
        graph,
        current_blocker: cur_blocker,
        critical_path: vec![],
        eta: None,
        progress_pct: pct,
    }
}

//! Owner: Interactive TUI subsystem — flow ETA estimation
//! Proof: `cargo nextest run -p jeryu -- tui::flow`
//! Invariants: ETA estimates remain advisory and never affect scheduling or release decisions.

use super::model::{EtaConfidence, EtaEstimate};

pub fn estimate_job_eta(
    job_name: &str,
    lane: super::model::LaneKind,
    elapsed_secs: i64,
) -> EtaEstimate {
    // A real implementation would query the state store's bottleneck history or similar.
    // We will simulate estimation via simple heuristics.
    let historical_duration = match lane {
        super::model::LaneKind::Unit => 60,
        super::model::LaneKind::Integration => 300,
        super::model::LaneKind::Security => 120,
        super::model::LaneKind::Build => 180,
        super::model::LaneKind::ReleaseExecution => 120,
        _ => 90,
    };

    let remaining = i64::max(0, historical_duration - elapsed_secs);

    // Slight tweak for known jobs that take a while
    let remaining = if job_name.contains("cargo build") {
        i64::max(0, 360 - elapsed_secs)
    } else {
        remaining
    };

    EtaEstimate {
        remaining_secs: remaining,
        confidence: EtaConfidence::Medium,
        reason: format!("lane avg {}s", historical_duration),
    }
}

//! Owner: Interactive TUI subsystem — flow inspector pane
//! Proof: `cargo nextest run -p jeryu -- tui::flow`
//! Invariants: Inspector output is read-only and redacts sensitive trace material.

use super::model::FlowNode;
use crate::api::snapshot::{CacheVerdict, VtiStatus};
use ratatui::{
    Frame,
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, Borders, Paragraph, Wrap},
};

pub fn draw_inspector(
    f: &mut Frame,
    area: Rect,
    node: Option<&FlowNode>,
    trace_tail: Option<&str>,
) {
    if let Some(n) = node {
        let title = format!(" JOB {} ", n.label);

        let color = match n.status.as_str() {
            "success" => Color::Green,
            "running" => Color::Blue,
            "failed" => Color::Red,
            "pending" | "created" => Color::Yellow,
            "canceled" => Color::DarkGray,
            _ => Color::Gray,
        };

        let eta_str = if let Some(ref e) = n.eta {
            format!("{}s", e.remaining_secs)
        } else {
            "N/A".to_string()
        };

        let mut lines: Vec<Line> = vec![
            Line::from(vec![
                Span::styled("  Status: ", Style::default().fg(Color::DarkGray)),
                Span::styled(
                    &n.status,
                    Style::default()
                        .fg(color)
                        .add_modifier(Modifier::BOLD),
                ),
                Span::styled(
                    format!("  {}%", n.progress_pct),
                    Style::default().fg(Color::White),
                ),
            ]),
            Line::from(vec![
                Span::styled("  ETA:    ", Style::default().fg(Color::DarkGray)),
                Span::styled(&eta_str, Style::default().fg(Color::White)),
                Span::styled(
                    format!("  Elapsed: {}s", n.elapsed_secs),
                    Style::default().fg(Color::DarkGray),
                ),
            ]),
            Line::from(vec![
                Span::styled("  Phase:  ", Style::default().fg(Color::DarkGray)),
                Span::styled(
                    format!("{:?}", n.column),
                    Style::default().fg(Color::Cyan),
                ),
                Span::styled("  Lane: ", Style::default().fg(Color::DarkGray)),
                Span::styled(
                    format!("{:?}", n.lane),
                    Style::default().fg(Color::Cyan),
                ),
            ]),
            Line::from(vec![
                Span::styled("  Flags:  ", Style::default().fg(Color::DarkGray)),
                Span::styled(
                    if n.is_required { "required " } else { "" },
                    Style::default().fg(Color::White),
                ),
                Span::styled(
                    if n.is_critical_path { "[CRIT] " } else { "" },
                    Style::default()
                        .fg(Color::Yellow)
                        .add_modifier(Modifier::BOLD),
                ),
            ]),
        ];

        // VTI status line
        if let Some(ref vti) = n.vti_status {
            let (vti_label, vti_color) = match vti {
                VtiStatus::Accelerated { reason, time_saved_secs } => (
                    format!("🔥 Accelerated — saved {}s — {}", time_saved_secs, reason),
                    Color::Rgb(255, 165, 0),
                ),
                VtiStatus::Skipped { reason, confidence } => (
                    format!("⊘ Skipped (conf {:.0}%) — {}", confidence * 100.0, reason),
                    Color::DarkGray,
                ),
                VtiStatus::Selected { reason, confidence } => (
                    format!("✓ Selected (conf {:.0}%) — {}", confidence * 100.0, reason),
                    Color::Green,
                ),
                VtiStatus::FullSuite => (
                    "Full suite (no VTI filtering)".to_string(),
                    Color::Gray,
                ),
            };
            lines.push(Line::from(vec![
                Span::styled("  VTI:    ", Style::default().fg(Color::DarkGray)),
                Span::styled(
                    vti_label,
                    Style::default().fg(vti_color).add_modifier(Modifier::BOLD),
                ),
            ]));
        }

        // Cache verdict line
        if let Some(ref cache) = n.cache_verdict {
            let (cache_label, cache_color) = match cache {
                CacheVerdict::Hit { trust } => (
                    format!("HIT (trust: {:?})", trust),
                    Color::Green,
                ),
                CacheVerdict::Miss => ("MISS".to_string(), Color::Yellow),
                CacheVerdict::Tainted { reason } => (
                    format!("TAINTED — {}", reason),
                    Color::Magenta,
                ),
                CacheVerdict::Denied { reason } => (
                    format!("DENIED — {}", reason),
                    Color::Red,
                ),
            };
            lines.push(Line::from(vec![
                Span::styled("  Cache:  ", Style::default().fg(Color::DarkGray)),
                Span::styled(cache_label, Style::default().fg(cache_color)),
            ]));
        }

        // Flake probability
        if let Some(flake) = n.flake_probability {
            if flake > 0.01 {
                let flake_color = if flake > 0.15 {
                    Color::Red
                } else if flake > 0.05 {
                    Color::Yellow
                } else {
                    Color::DarkGray
                };
                lines.push(Line::from(vec![
                    Span::styled("  Flake:  ", Style::default().fg(Color::DarkGray)),
                    Span::styled(
                        format!("{:.1}%", flake * 100.0),
                        Style::default().fg(flake_color),
                    ),
                ]));
            }
        }

        // Agent badge
        if let Some(ref agent_id) = n.agent_id {
            lines.push(Line::from(vec![
                Span::styled("  Agent:  ", Style::default().fg(Color::DarkGray)),
                Span::styled(
                    agent_id.clone(),
                    Style::default().fg(Color::Rgb(102, 255, 255)),
                ),
            ]));
        }

        // Capsule badge
        if let Some(ref capsule_id) = n.capsule_id {
            lines.push(Line::from(vec![
                Span::styled("  Capsule:", Style::default().fg(Color::DarkGray)),
                Span::styled(
                    format!(" {}", capsule_id),
                    Style::default().fg(Color::Yellow),
                ),
            ]));
        }

        // Retry lineage
        if !n.attempt_lineage.is_empty() {
            let lineage_str: String = n
                .attempt_lineage
                .iter()
                .map(|id| format!("#{}", id))
                .collect::<Vec<_>>()
                .join(" → ");
            lines.push(Line::from(vec![
                Span::styled("  Retries:", Style::default().fg(Color::DarkGray)),
                Span::styled(
                    format!(" {}", lineage_str),
                    Style::default().fg(Color::DarkGray),
                ),
            ]));
        }

        // Trace tail
        lines.push(Line::from(""));
        lines.push(Line::from(Span::styled(
            "  Trace tail:",
            Style::default()
                .fg(Color::DarkGray)
                .add_modifier(Modifier::BOLD),
        )));
        let tail = trace_tail.unwrap_or("Waiting for logs...");
        for line in tail.lines().take(6) {
            lines.push(Line::from(Span::styled(
                format!("  {}", line),
                Style::default().fg(Color::White),
            )));
        }

        let p = Paragraph::new(lines)
            .block(
                Block::default()
                    .title(title)
                    .borders(Borders::ALL)
                    .border_style(Style::default().fg(color)),
            )
            .wrap(Wrap { trim: false });

        f.render_widget(p, area);
    } else {
        let p =
            Paragraph::new("No job selected or graph is empty.\nUse arrow keys to navigate flow.")
                .block(
                    Block::default()
                        .title(" [ Inspector ] ")
                        .borders(Borders::ALL),
                );
        f.render_widget(p, area);
    }
}

