//! Owner: Interactive TUI subsystem — action execution runtime bridge
//! Proof: `cargo nextest run -p jeryu -- tui::widgets::action_dispatch`
//! Invariants: Every mutation goes through preview → confirm → execute.

use crate::api::actions::{
    ActionContext, ActionPreview, ActionResult, ActionStatus, ActorKind, ActorRef,
    ContextualAction, actions_for_entity,
};
use crate::api::entity::{EntityKind, EntityRef};
use crate::tui::action_registry::{GrantRequirement, RiskTier, SideEffectClass};

/// Preview state for the action execution modal.
#[derive(Debug, Clone)]
pub enum ActionExecutionState {
    /// No action being executed.
    Idle,
    /// Action selected — showing preview modal.
    Previewing {
        action_id: String,
        label: String,
        preview: ActionPreview,
        entity: Option<EntityRef>,
    },
    /// User confirmed — executing.
    Executing {
        action_id: String,
        label: String,
    },
    /// Execution complete — showing result.
    Completed {
        action_id: String,
        result: ActionResult,
    },
}

impl Default for ActionExecutionState {
    fn default() -> Self {
        Self::Idle
    }
}

impl ActionExecutionState {
    pub fn is_previewing(&self) -> bool {
        matches!(self, Self::Previewing { .. })
    }

    pub fn is_executing(&self) -> bool {
        matches!(self, Self::Executing { .. })
    }

    /// Start previewing an action from the command palette.
    pub fn begin_preview(
        action_id: &str,
        label: &str,
        entity: Option<EntityRef>,
        risk: RiskTier,
        side_effect_class: SideEffectClass,
        description: &str,
        required_grant: GrantRequirement,
        dry_run: bool,
    ) -> Self {
        let preview = ActionPreview {
            enabled: true,
            disabled_reason: None,
            risk,
            side_effect_class,
            side_effects: vec![description.to_string()],
            will_not: vec![
                "modify production state".to_string(),
                "bypass sandbox constraints".to_string(),
            ],
            summary: description.to_string(),
            evidence_expected: Vec::new(),
            required_grant,
            undo_action: compute_undo_action(action_id),
            confirm_prompt: Some(format!(
                "[Enter] Execute {}   [Esc] Cancel",
                label
            )),
        };

        Self::Previewing {
            action_id: action_id.to_string(),
            label: label.to_string(),
            preview,
            entity,
        }
    }

    /// Transition from preview to executing.
    pub fn confirm(&mut self) {
        if let Self::Previewing { action_id, label, .. } = self {
            *self = Self::Executing {
                action_id: action_id.clone(),
                label: label.clone(),
            };
        }
    }

    /// Mark execution as complete.
    pub fn complete(&mut self, result: ActionResult) {
        if let Self::Executing { action_id, .. } = self {
            *self = Self::Completed {
                action_id: action_id.clone(),
                result,
            };
        }
    }

    /// Reset to idle.
    pub fn dismiss(&mut self) {
        *self = Self::Idle;
    }
}

/// Build the action context for the current selected entity.
pub fn build_context(entity: Option<EntityRef>, dry_run: bool) -> ActionContext {
    ActionContext {
        selected_entity: entity,
        actor: ActorRef {
            kind: ActorKind::Human,
            id: "tui-user".to_string(),
        },
        grant_id: None,
        dry_run,
        idempotency_key: Some(format!("tui-{}", chrono::Utc::now().timestamp_millis())),
    }
}

/// Get available actions for the current entity context.
pub fn available_actions(entity: Option<&EntityRef>) -> Vec<ContextualAction> {
    match entity {
        Some(e) => actions_for_entity(e),
        None => {
            // System-level actions
            actions_for_entity(&EntityRef::new(EntityKind::System, "global"))
        }
    }
}

/// Compute the undo action for a given action.
fn compute_undo_action(action_id: &str) -> Option<String> {
    match action_id {
        "pause_pool" => Some("resume_pool".to_string()),
        "requeue_job" => None,
        "remove_record" => None,
        "cancel_job" => Some("requeue_job".to_string()),
        _ => None,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn action_state_machine() {
        let mut state = ActionExecutionState::begin_preview(
            "requeue_job",
            "Retry Failed Job",
            Some(EntityRef::new(EntityKind::Job, "123")),
            RiskTier::Low,
            SideEffectClass::LocalState,
            "Requeue job #123",
            GrantRequirement::None,
            false,
        );
        assert!(state.is_previewing());

        state.confirm();
        assert!(state.is_executing());

        state.complete(ActionResult {
            status: ActionStatus::Completed,
            summary: "Job requeued".to_string(),
            event_cursor: Some(42),
            affected_entity: Some(EntityRef::new(EntityKind::Job, "123")),
            evidence_created: Vec::new(),
        });
        assert!(matches!(state, ActionExecutionState::Completed { .. }));

        state.dismiss();
        assert!(matches!(state, ActionExecutionState::Idle));
    }

    #[test]
    fn system_actions_always_available() {
        let actions = available_actions(None);
        let ids: Vec<_> = actions.iter().map(|a| a.action_id).collect();
        assert!(ids.contains(&"next_action"));
        assert!(ids.contains(&"get_system_snapshot"));
    }

    #[test]
    fn undo_action_mapping() {
        assert_eq!(compute_undo_action("pause_pool"), Some("resume_pool".to_string()));
        assert_eq!(compute_undo_action("cancel_job"), Some("requeue_job".to_string()));
        assert_eq!(compute_undo_action("remove_record"), None);
    }
}

//! Owner: Interactive TUI subsystem — action preview modal
//! Proof: `cargo nextest run -p jeryu -- tui::widgets::action_preview`
//! Invariants: Preview modal is read-only; it never executes the action.

use ratatui::{
    Frame,
    layout::{Constraint, Direction, Layout, Rect},
    style::{Modifier, Style},
    text::{Line, Span},
    widgets::{Block, Borders, Clear, Paragraph, Wrap},
};

use crate::api::actions::ActionPreview;
use crate::tui::theme::Theme;

/// Render a centered action preview modal over the current screen.
pub fn render_action_preview(
    f: &mut Frame,
    area: Rect,
    action_label: &str,
    preview: &ActionPreview,
    theme: &Theme,
) {
    // Center a modal at 60% width, 50% height
    let modal = centered_rect(60, 50, area);

    // Clear the background
    f.render_widget(Clear, modal);

    let risk_color = theme.status_color(preview.risk.label());
    let block = Block::default()
        .title(format!(" Action Preview — {} ", action_label))
        .borders(Borders::ALL)
        .border_style(Style::default().fg(risk_color));

    let inner = block.inner(modal);
    f.render_widget(block, modal);

    let sections = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Length(3),  // Summary + Risk
            Constraint::Length(4),  // Will do
            Constraint::Length(3),  // Will NOT
            Constraint::Length(2),  // Grant + undo
            Constraint::Min(2),    // Confirmation
        ])
        .split(inner);

    // Summary + Risk
    let summary_lines = vec![
        Line::from(vec![
            Span::styled("  Risk: ", theme.muted()),
            Span::styled(
                preview.risk.label(),
                theme.bold(risk_color),
            ),
            Span::styled(
                format!("   Effect: {}", preview.side_effect_class.label()),
                theme.secondary(),
            ),
        ]),
        Line::from(vec![
            Span::styled("  ", theme.muted()),
            Span::styled(&preview.summary, theme.primary()),
        ]),
    ];
    f.render_widget(Paragraph::new(summary_lines), sections[0]);

    // Will do
    let mut will_lines = vec![Line::from(Span::styled(
        "  Will:",
        theme.bold(theme.text_secondary),
    ))];
    for effect in preview.side_effects.iter().take(3) {
        will_lines.push(Line::from(vec![
            Span::styled("    • ", Style::default().fg(theme.running)),
            Span::styled(effect.clone(), theme.primary()),
        ]));
    }
    f.render_widget(Paragraph::new(will_lines), sections[1]);

    // Will NOT
    let mut wont_lines = vec![Line::from(Span::styled(
        "  Will NOT:",
        theme.bold(theme.text_secondary),
    ))];
    for wont in preview.will_not.iter().take(2) {
        wont_lines.push(Line::from(vec![
            Span::styled("    ✗ ", Style::default().fg(theme.skipped)),
            Span::styled(wont.clone(), theme.muted()),
        ]));
    }
    f.render_widget(Paragraph::new(wont_lines), sections[2]);

    // Grant + undo
    let grant_lines = vec![
        Line::from(vec![
            Span::styled("  Grant: ", theme.muted()),
            Span::styled(
                preview.required_grant.label(),
                theme.secondary(),
            ),
            Span::styled("   Undo: ", theme.muted()),
            Span::styled(
                preview.undo_action.as_deref().unwrap_or("n/a"),
                theme.secondary(),
            ),
        ]),
    ];
    f.render_widget(Paragraph::new(grant_lines), sections[3]);

    // Confirmation footer
    let confirm = preview
        .confirm_prompt
        .as_deref()
        .unwrap_or("[Enter] Execute   [Esc] Cancel");
    f.render_widget(
        Paragraph::new(Line::from(vec![
            Span::styled("  ", theme.muted()),
            Span::styled(
                confirm.to_string(),
                theme.bold(theme.border_accent),
            ),
        ]))
        .wrap(Wrap { trim: true }),
        sections[4],
    );
}

fn centered_rect(pct_x: u16, pct_y: u16, area: Rect) -> Rect {
    let vert = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Percentage((100 - pct_y) / 2),
            Constraint::Percentage(pct_y),
            Constraint::Percentage((100 - pct_y) / 2),
        ])
        .split(area);
    let horiz = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([
            Constraint::Percentage((100 - pct_x) / 2),
            Constraint::Percentage(pct_x),
            Constraint::Percentage((100 - pct_x) / 2),
        ])
        .split(vert[1]);
    horiz[1]
}

