/// Render the full agent fleet view — replaces pipeline-centric agent rendering.
pub fn render_agent_fleet(
    f: &mut Frame,
    area: Rect,
    sessions: &[AgentSession],
    selected: usize,
    theme: &Theme,
) {
    let cols = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([
            Constraint::Percentage(34),  // Agent list
            Constraint::Percentage(40),  // Agent detail cockpit
            Constraint::Percentage(26),  // Grants + actions
        ])
        .split(area);

    // ── Agent List ──────────────────────────────────────────────────
    let items: Vec<ListItem> = sessions
        .iter()
        .enumerate()
        .map(|(i, s)| {
            let is_selected = i == selected;
            let prefix = if is_selected { ">>" } else { "  " };
            let state_color = state_theme_color(s.state, theme);

            let line = Line::from(vec![
                Span::styled(
                    format!("{} {} ", prefix, s.state.glyph()),
                    Style::default()
                        .fg(state_color)
                        .add_modifier(Modifier::BOLD),
                ),
                Span::styled(
                    format!("{:<5} ", s.state.label()),
                    Style::default().fg(state_color),
                ),
                Span::styled(
                    super::truncate_label(&s.objective, cols[0].width.saturating_sub(16) as usize),
                    if is_selected { theme.primary() } else { theme.secondary() },
                ),
            ]);

            let style = if is_selected {
                Style::default().bg(Color::Rgb(45, 45, 55))
            } else {
                Style::default()
            };
            ListItem::new(line).style(style)
        })
        .collect();

    let count_active = sessions.iter().filter(|s| s.state.is_active()).count();
    f.render_widget(
        List::new(items).block(
            Block::default()
                .title(format!(" [ Agent Fleet ({}/{}) ] ", count_active, sessions.len()))
                .borders(Borders::ALL)
                .border_style(Style::default().fg(theme.agent)),
        ),
        cols[0],
    );

    // ── Agent Detail Cockpit ────────────────────────────────────────
    let detail_rows = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Length(11), // Detail card
            Constraint::Min(6),    // Patch race board
        ])
        .split(cols[1]);

    if let Some(session) = sessions.get(selected) {
        render_session_detail(f, detail_rows[0], session, theme);
        render_patch_board(f, detail_rows[1], session, theme);
    } else {
        f.render_widget(
            Paragraph::new("  No agent sessions yet.\n  Branches starting with agent/ appear here.")
                .block(
                    Block::default()
                        .title(" [ Agent Cockpit ] ")
                        .borders(Borders::ALL),
                )
                .style(theme.muted()),
            detail_rows[0],
        );
    }

    // ── Grants + Actions ────────────────────────────────────────────
    if let Some(session) = sessions.get(selected) {
        render_agent_grants(f, cols[2], session, theme);
    } else {
        f.render_widget(
            Paragraph::new("  —")
                .block(
                    Block::default()
                        .title(" [ Grants ] ")
                        .borders(Borders::ALL)
                        .border_style(Style::default().fg(theme.border_subtle)),
                ),
            cols[2],
        );
    }
}

fn render_session_detail(f: &mut Frame, area: Rect, s: &AgentSession, theme: &Theme) {
    let state_color = state_theme_color(s.state, theme);

    let budget_bar = |used: f64, limit: f64| -> String {
        if limit <= 0.0 { return "n/a".to_string(); }
        let pct = ((used / limit) * 100.0).min(100.0);
        let filled = (pct as usize * 10 / 100).min(10);
        format!("{}{}  {:.0}%", "█".repeat(filled), "░".repeat(10 - filled), pct)
    };

    let time_bar = budget_bar(s.budget.time_used_secs as f64, s.budget.time_limit_secs as f64);
    let ci_bar = budget_bar(s.budget.ci_minutes_used as f64, s.budget.ci_minutes_limit as f64);

    let mut lines = vec![
        Line::from(vec![
            Span::styled("  State:  ", theme.muted()),
            Span::styled(
                format!("{} {}", s.state.glyph(), s.state.label()),
                theme.bold(state_color),
            ),
            Span::styled("  Trust: ", theme.muted()),
            Span::styled(
                s.trust_tier.label(),
                Style::default().fg(trust_color(s.trust_tier, theme)),
            ),
        ]),
        Line::from(vec![
            Span::styled("  Goal:   ", theme.muted()),
            Span::styled(
                super::truncate_label(&s.objective, area.width.saturating_sub(14) as usize),
                theme.primary(),
            ),
        ]),
    ];

    if let Some(ref intent) = s.current_intent {
        lines.push(Line::from(vec![
            Span::styled("  Intent: ", theme.muted()),
            Span::styled(intent.clone(), Style::default().fg(theme.running)),
        ]));
    }
    if let Some(ref step) = s.current_step {
        lines.push(Line::from(vec![
            Span::styled("  Step:   ", theme.muted()),
            Span::styled(step.clone(), theme.secondary()),
        ]));
    }

    // Budget bars
    lines.push(Line::from(vec![
        Span::styled("  Time:   ", theme.muted()),
        Span::styled(
            time_bar,
            Style::default().fg(if s.budget.time_pct() > 80.0 { theme.fail } else { theme.ok }),
        ),
    ]));
    lines.push(Line::from(vec![
        Span::styled("  CI:     ", theme.muted()),
        Span::styled(
            ci_bar,
            Style::default().fg(if s.budget.is_exhausted() { theme.fail } else { theme.ok }),
        ),
    ]));

    if let Some(conf) = s.confidence {
        lines.push(Line::from(vec![
            Span::styled("  Conf:   ", theme.muted()),
            Span::styled(
                format!("{:.0}%", conf * 100.0),
                Style::default().fg(if conf > 0.7 { theme.ok } else { theme.waiting }),
            ),
        ]));
    }

    if let Some(ref branch) = s.branch {
        lines.push(Line::from(vec![
            Span::styled("  Branch: ", theme.muted()),
            Span::styled(branch.clone(), theme.secondary()),
        ]));
    }

    f.render_widget(
        Paragraph::new(lines).block(
            Block::default()
                .title(format!(" [ {} ] ", s.id))
                .borders(Borders::ALL)
                .border_style(Style::default().fg(state_color)),
        ),
        area,
    );
}

fn render_patch_board(f: &mut Frame, area: Rect, s: &AgentSession, theme: &Theme) {
    let block = Block::default()
        .title(format!(" [ Patch Race ({}) ] ", s.patch_attempts.len()))
        .borders(Borders::ALL)
        .border_style(Style::default().fg(theme.border_subtle));
    let inner = block.inner(area);
    f.render_widget(block, area);

    if s.patch_attempts.is_empty() {
        f.render_widget(
            Paragraph::new(Span::styled("  No patches yet", theme.muted())),
            inner,
        );
        return;
    }

    let max = inner.height as usize;
    let lines: Vec<Line> = s.patch_attempts
        .iter()
        .take(max)
        .map(|p| {
            let status_color = patch_color(p.status, theme);
            let score_str = match p.score {
                Some(score) => format!(" score:{}", score),
                None => String::new(),
            };
            Line::from(vec![
                Span::styled(
                    format!(" {} ", p.status.glyph()),
                    theme.bold(status_color),
                ),
                Span::styled(
                    super::truncate_label(&p.label, inner.width.saturating_sub(30) as usize),
                    theme.primary(),
                ),
                Span::styled(
                    format!(" {} {}{}", p.diff_stat, p.risk.label(), score_str),
                    theme.muted(),
                ),
            ])
        })
        .collect();

    f.render_widget(Paragraph::new(lines), inner);
}

fn render_agent_grants(f: &mut Frame, area: Rect, s: &AgentSession, theme: &Theme) {
    let mut lines = vec![
        Line::from(Span::styled(
            "  Authority",
            theme.bold(theme.text_secondary),
        )),
        Line::from(vec![
            Span::styled("  Trust: ", theme.muted()),
            Span::styled(
                s.trust_tier.label(),
                Style::default().fg(trust_color(s.trust_tier, theme)),
            ),
        ]),
        Line::from(""),
        Line::from(Span::styled(
            "  Active Grants",
            theme.bold(theme.text_secondary),
        )),
    ];

    if s.grants.is_empty() {
        lines.push(Line::from(Span::styled("  none", theme.muted())));
    } else {
        for g in s.grants.iter().take(4) {
            let remaining = g.expires_at.signed_duration_since(chrono::Utc::now()).num_seconds().max(0);
            lines.push(Line::from(vec![
                Span::styled(
                    format!("  {} ", g.action_id),
                    Style::default().fg(theme.waiting),
                ),
                Span::styled(
                    format!("{}s left", remaining),
                    theme.muted(),
                ),
            ]));
        }
    }

    lines.push(Line::from(""));
    lines.push(Line::from(Span::styled(
        "  Blockers",
        theme.bold(theme.text_secondary),
    )));

    if s.blockers.is_empty() {
        lines.push(Line::from(Span::styled("  clear", Style::default().fg(theme.ok))));
    } else {
        for b in s.blockers.iter().take(3) {
            lines.push(Line::from(vec![
                Span::styled(
                    format!("  {} ", b.severity.label()),
                    theme.bold(match b.severity {
                        crate::api::entity::Severity::Critical => theme.fail,
                        crate::api::entity::Severity::Error => theme.warning,
                        _ => theme.waiting,
                    }),
                ),
                Span::styled(
                    super::truncate_label(&b.summary, area.width.saturating_sub(10) as usize),
                    theme.primary(),
                ),
            ]));
        }
    }

    lines.push(Line::from(""));
    lines.push(Line::from(Span::styled(
        "  Actions",
        theme.bold(theme.text_secondary),
    )));
    lines.push(Line::from(Span::styled("  ^K explain blockers", theme.primary())));
    lines.push(Line::from(Span::styled("  ^K fetch capsule", theme.primary())));

    if let Some(ref next) = s.next_action {
        lines.push(Line::from(vec![
            Span::styled("  → ", Style::default().fg(theme.running)),
            Span::styled(&next.label, theme.bold(theme.running)),
        ]));
    }

    f.render_widget(
        Paragraph::new(lines)
            .block(
                Block::default()
                    .title(" [ Grants / Blockers ] ")
                    .borders(Borders::ALL)
                    .border_style(Style::default().fg(theme.blocked)),
            )
            .wrap(Wrap { trim: false }),
        area,
    );
}

fn state_theme_color(state: AgentState, theme: &Theme) -> Color {
    match state {
        AgentState::Spawning => theme.waiting,
        AgentState::Diagnosing => theme.running,
        AgentState::Patching => theme.agent,
        AgentState::Validating => theme.running,
        AgentState::Racing => theme.vti_fire,
        AgentState::Blocked | AgentState::Failed => theme.fail,
        AgentState::WaitingApproval => theme.warning,
        AgentState::Completed => theme.ok,
        AgentState::Paused => theme.skipped,
    }
}

fn trust_color(tier: TrustTier, theme: &Theme) -> Color {
    match tier {
        TrustTier::Untrusted => theme.fail,
        TrustTier::Standard => theme.waiting,
        TrustTier::Trusted => theme.ok,
        TrustTier::Elevated => theme.blocked,
    }
}

fn patch_color(status: PatchStatus, theme: &Theme) -> Color {
    match status {
        PatchStatus::Proposed => theme.waiting,
        PatchStatus::Testing => theme.running,
        PatchStatus::Green => theme.ok,
        PatchStatus::Failed => theme.fail,
        PatchStatus::Winner => theme.vti_fire,
        PatchStatus::Archived => theme.skipped,
    }
}



#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn state_colors_are_themed() {
        let t = Theme::dark();
        assert_eq!(state_theme_color(AgentState::Completed, &t), t.ok);
        assert_eq!(state_theme_color(AgentState::Failed, &t), t.fail);
        assert_eq!(state_theme_color(AgentState::Racing, &t), t.vti_fire);
    }

    #[test]
    fn trust_colors_are_themed() {
        let t = Theme::dark();
        assert_eq!(trust_color(TrustTier::Trusted, &t), t.ok);
        assert_eq!(trust_color(TrustTier::Untrusted, &t), t.fail);
    }
}

//! Owner: Interactive TUI subsystem — attention queue widget
//! Proof: `cargo nextest run -p jeryu -- tui::widgets::attention`
//! Invariants: Attention items are rendered in severity order; never mutates state.

use ratatui::{
    Frame,
    layout::Rect,
    style::{Modifier, Style},
    text::{Line, Span},
    widgets::{Block, Borders, Paragraph},
};

use crate::api::entity::Severity;
use crate::api::read_model::AttentionItem;
use crate::tui::theme::Theme;

/// Render the left-rail attention queue from ranked attention items.
pub fn render_attention_rail(
    f: &mut Frame,
    area: Rect,
    items: &[AttentionItem],
    selected: Option<usize>,
    theme: &Theme,
) {
    let block = Block::default()
        .title(" [ Attention ] ")
        .borders(Borders::ALL)
        .border_style(Style::default().fg(if items.is_empty() {
            theme.ok
        } else {
            severity_color(
                items.first().map(|i| i.severity).unwrap_or(Severity::Info),
                theme,
            )
        }));

    let inner = block.inner(area);
    f.render_widget(block, area);

    if items.is_empty() {
        f.render_widget(
            Paragraph::new(Line::from(Span::styled(
                " No blockers",
                Style::default().fg(theme.ok),
            ))),
            inner,
        );
        return;
    }

    let max_items = inner.height as usize;
    let lines: Vec<Line> = items
        .iter()
        .take(max_items)
        .enumerate()
        .map(|(idx, item)| {
            let sev_color = severity_color(item.severity, theme);
            let is_selected = selected == Some(idx);

            let mut spans = vec![
                Span::styled(
                    format!(" {} ", item.severity.label()),
                    Style::default()
                        .fg(theme.text_inverse)
                        .bg(sev_color)
                        .add_modifier(Modifier::BOLD),
                ),
                Span::raw(" "),
            ];

            let max_title = inner.width.saturating_sub(8) as usize;
            let title = if item.title.len() > max_title && max_title > 3 {
                format!("{}...", &item.title[..max_title - 3])
            } else {
                item.title.clone()
            };

            if is_selected {
                spans.push(Span::styled(
                    title,
                    Style::default()
                        .fg(sev_color)
                        .add_modifier(Modifier::BOLD | Modifier::UNDERLINED),
                ));
            } else {
                spans.push(Span::styled(
                    title,
                    Style::default()
                        .fg(sev_color)
                        .add_modifier(Modifier::BOLD),
                ));
            }

            Line::from(spans)
        })
        .collect();

    f.render_widget(Paragraph::new(lines), inner);
}

fn severity_color(severity: Severity, theme: &Theme) -> ratatui::style::Color {
    match severity {
        Severity::Critical => theme.fail,
        Severity::Error => theme.warning,
        Severity::Warning => theme.waiting,
        Severity::Info => theme.text_muted,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn severity_color_maps_correctly() {
        let t = Theme::dark();
        assert_eq!(severity_color(Severity::Critical, &t), t.fail);
        assert_eq!(severity_color(Severity::Warning, &t), t.waiting);
    }
}

//! Owner: Interactive TUI subsystem — universal entity inspector widget
//! Proof: `cargo nextest run -p jeryu -- tui::widgets::inspector`
//! Invariants: Inspector renders from `EntityDetail`; never reaches into raw state.

use ratatui::{
    Frame,
    layout::{Constraint, Direction, Layout, Rect},
    style::{Modifier, Style},
    text::{Line, Span},
    widgets::{Block, Borders, Paragraph, Wrap},
};

use crate::api::entity::{EntityDetail, Severity};
use crate::tui::theme::Theme;

/// Render the universal inspector for any selected entity.
/// This is the right-side pane that answers: What? Why? Proof? Actions? Related?
pub fn render_inspector(f: &mut Frame, area: Rect, detail: &EntityDetail, theme: &Theme) {
    let block = Block::default()
        .title(format!(
            " [ {} {} ] ",
            detail.entity.kind.label().to_uppercase(),
            detail.entity.id
        ))
        .borders(Borders::ALL)
        .border_style(
            detail
                .risk
                .map(|r| Style::default().fg(theme.status_color(r.label())))
                .unwrap_or(Style::default().fg(theme.border_active)),
        );

    let inner = block.inner(area);
    f.render_widget(block, area);

    let sections = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Length(4),  // What: state + summary
            Constraint::Length(4),  // Why: blockers
            Constraint::Length(4),  // Proof: evidence
            Constraint::Length(4),  // Actions
            Constraint::Min(1),    // Related
        ])
        .split(inner);

    // ── What ────────────────────────────────────────────────────────
    let mut what_lines = vec![
        Line::from(vec![
            Span::styled("  State: ", theme.muted()),
            Span::styled(
                &detail.state,
                theme.bold(theme.status_color(&detail.state)),
            ),
        ]),
    ];
    if !detail.summary.is_empty() {
        what_lines.push(Line::from(vec![
            Span::styled("  ", theme.muted()),
            Span::styled(
                truncate(&detail.summary, sections[0].width.saturating_sub(4) as usize),
                theme.secondary(),
            ),
        ]));
    }
    f.render_widget(Paragraph::new(what_lines).wrap(Wrap { trim: true }), sections[0]);

    // ── Why: blockers ───────────────────────────────────────────────
    let mut why_lines = vec![Line::from(Span::styled(
        "  Blockers",
        theme.bold(theme.text_secondary),
    ))];
    if detail.blockers.is_empty() {
        why_lines.push(Line::from(Span::styled(
            "  none",
            Style::default().fg(theme.ok),
        )));
    } else {
        for blocker in detail.blockers.iter().take(2) {
            let sev_color = match blocker.severity {
                Severity::Critical => theme.fail,
                Severity::Error => theme.warning,
                Severity::Warning => theme.waiting,
                Severity::Info => theme.text_muted,
            };
            why_lines.push(Line::from(vec![
                Span::styled(
                    format!("  {} ", blocker.severity.label()),
                    theme.bold(sev_color),
                ),
                Span::styled(
                    truncate(&blocker.summary, sections[1].width.saturating_sub(8) as usize),
                    theme.primary(),
                ),
            ]));
        }
    }
    f.render_widget(Paragraph::new(why_lines), sections[1]);

    // ── Proof: evidence ─────────────────────────────────────────────
    let mut proof_lines = vec![Line::from(Span::styled(
        "  Evidence",
        theme.bold(theme.text_secondary),
    ))];
    if detail.evidence.is_empty() {
        proof_lines.push(Line::from(Span::styled(
            "  no linked evidence",
            theme.muted(),
        )));
    } else {
        for ev in detail.evidence.iter().take(2) {
            proof_lines.push(Line::from(vec![
                Span::styled(format!("  [{}] ", ev.kind), theme.secondary()),
                Span::styled(
                    ev.summary
                        .as_deref()
                        .unwrap_or(&ev.id),
                    theme.primary(),
                ),
            ]));
        }
    }
    f.render_widget(Paragraph::new(proof_lines), sections[2]);

    // ── Actions ─────────────────────────────────────────────────────
    let mut action_lines = vec![Line::from(Span::styled(
        "  Actions",
        theme.bold(theme.text_secondary),
    ))];
    if detail.available_actions.is_empty() {
        action_lines.push(Line::from(Span::styled(
            "  ^K palette for all actions",
            theme.muted(),
        )));
    } else {
        for action in detail.available_actions.iter().take(3) {
            let risk_color = action
                .risk
                .map(|r| theme.status_color(r.label()))
                .unwrap_or(theme.text_muted);
            action_lines.push(Line::from(vec![
                Span::styled(
                    format!(
                        "  {} ",
                        action
                            .risk
                            .map(|r| r.label())
                            .unwrap_or("—")
                    ),
                    Style::default().fg(risk_color),
                ),
                Span::styled(&action.label, theme.primary()),
            ]));
        }
    }
    f.render_widget(Paragraph::new(action_lines), sections[3]);

    // ── Related ─────────────────────────────────────────────────────
    let mut rel_lines = vec![Line::from(Span::styled(
        "  Related",
        theme.bold(theme.text_secondary),
    ))];
    if detail.related.is_empty() {
        rel_lines.push(Line::from(Span::styled("  —", theme.muted())));
    } else {
        for entity in detail.related.iter().take(4) {
            rel_lines.push(Line::from(Span::styled(
                format!("  → {}", entity.display()),
                Style::default().fg(theme.agent),
            )));
        }
    }
    f.render_widget(Paragraph::new(rel_lines), sections[4]);
}

fn truncate(s: &str, max: usize) -> String {
    if s.len() <= max {
        s.to_string()
    } else if max > 3 {
        format!("{}...", &s[..max - 3])
    } else {
        s[..max].to_string()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn truncate_short_strings() {
        assert_eq!(truncate("hello", 10), "hello");
        assert_eq!(truncate("hello world", 8), "hello...");
    }
}

//! Owner: Interactive TUI subsystem — mission control attention-first view
//! Proof: `cargo nextest run -p jeryu -- tui::widgets::mission`
//! Invariants: Mission view renders from TuiReadModel and AttentionItems; no mutation.

use ratatui::{
    Frame,
    layout::{Constraint, Direction, Layout, Rect},
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, Borders, Paragraph, Wrap},
};

use crate::api::read_model::{
    AttentionItem, MissionSnapshot, NextActionRecommendation, SystemHealth,
};
use crate::tui::theme::Theme;
use super::mission_shared::{render_metric_row, MetricTile};

/// Render the mission control attention-first cockpit.
pub fn render_mission(
    f: &mut Frame,
    area: Rect,
    mission: &MissionSnapshot,
    attention: &[AttentionItem],
    health: &SystemHealth,
    next_actions: &[NextActionRecommendation],
    selected_attention: usize,
    theme: &Theme,
) {
    let rows = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Length(5),   // Posture banner
            Constraint::Length(7),   // Metric tiles
            Constraint::Min(8),     // Body: attention + proof + actions
        ])
        .split(area);

    // ── Posture Banner ──────────────────────────────────────────────
    let posture_color = if !mission.safe_to_code {
        theme.fail
    } else if !mission.safe_to_merge {
        theme.warning
    } else if !mission.safe_to_release {
        theme.waiting
    } else {
        theme.ok
    };

    let posture_label = if !mission.safe_to_code {
        "BLOCKED — Cannot safely code"
    } else if !mission.safe_to_merge {
        "CAUTION — Merge conditions not met"
    } else if !mission.safe_to_release {
        "HOLD — Release gates incomplete"
    } else {
        "ALL CLEAR — Ready to ship"
    };

    let banner_lines = vec![
        Line::from(vec![
            Span::styled(
                format!("  {} ", posture_label),
                Style::default()
                    .fg(theme.text_inverse)
                    .bg(posture_color)
                    .add_modifier(Modifier::BOLD),
            ),
        ]),
        Line::from(vec![
            Span::styled("  code:", theme.muted()),
            Span::styled(
                if mission.safe_to_code { "✓ " } else { "✗ " },
                Style::default().fg(if mission.safe_to_code { theme.ok } else { theme.fail }),
            ),
            Span::styled("merge:", theme.muted()),
            Span::styled(
                if mission.safe_to_merge { "✓ " } else { "✗ " },
                Style::default().fg(if mission.safe_to_merge { theme.ok } else { theme.fail }),
            ),
            Span::styled("release:", theme.muted()),
            Span::styled(
                if mission.safe_to_release { "✓ " } else { "✗ " },
                Style::default().fg(if mission.safe_to_release { theme.ok } else { theme.fail }),
            ),
            Span::styled("agents:", theme.muted()),
            Span::styled(
                if mission.agents_can_code { "✓" } else { "✗" },
                Style::default().fg(if mission.agents_can_code { theme.ok } else { theme.fail }),
            ),
        ]),
    ];

    f.render_widget(
        Paragraph::new(banner_lines).block(
            Block::default()
                .title(" [ Mission Control ] ")
                .borders(Borders::ALL)
                .border_style(Style::default().fg(posture_color)),
        ),
        rows[0],
    );

    // ── Metric Tiles ────────────────────────────────────────────────
    let gitlab_label = match health
        .components()
        .iter()
        .find(|c| c.name == "gitlab")
    {
        Some(component) => component.status_label(),
        None => "unknown".to_string(),
    };
    let runners_value = format!("{}/{}", mission.active_runners, mission.total_runners);
    let agents_value = format!("{} active", mission.active_agents);
    let cache_value = format!("{} taints", mission.taint_count);
    let evidence_value = format!("{} capsules", mission.evidence_count);
    render_metric_row(
        f,
        rows[1],
        &[
            MetricTile {
                title: "GitLab",
                value: &gitlab_label,
                detail: None,
                color: metric_color(&gitlab_label, theme),
            },
            MetricTile {
                title: "Runners",
                value: &runners_value,
                detail: None,
                color: metric_color(&runners_value, theme),
            },
            MetricTile {
                title: "Agents",
                value: &agents_value,
                detail: None,
                color: metric_color(&agents_value, theme),
            },
            MetricTile {
                title: "Cache Trust",
                value: &cache_value,
                detail: None,
                color: metric_color(&cache_value, theme),
            },
            MetricTile {
                title: "Evidence",
                value: &evidence_value,
                detail: None,
                color: metric_color(&evidence_value, theme),
            },
        ],
    );

    // ── Body: Attention Queue + Proof Stack + Next Actions ───────
    let body_cols = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([
            Constraint::Percentage(44),
            Constraint::Percentage(32),
            Constraint::Percentage(24),
        ])
        .split(rows[2]);

    // Attention queue
    crate::tui::widgets::attention::render_attention_rail(
        f, body_cols[0], attention, Some(selected_attention), theme,
    );

    // Proof stack lanes
    render_proof_stack(f, body_cols[1], mission, theme);

    // Next actions
    render_next_actions(f, body_cols[2], next_actions, theme);
}

fn metric_color(value: &str, theme: &Theme) -> Color {
    if value.contains("unknown") || value.contains("degraded") {
        theme.warning
    } else if value.contains("taint") && !value.starts_with("0") {
        theme.blocked
    } else {
        theme.ok
    }
}

fn render_proof_stack(f: &mut Frame, area: Rect, mission: &MissionSnapshot, theme: &Theme) {
    let lanes = vec![
        ("Capability grants", if mission.safe_to_code { "observed" } else { "blocked" }),
        ("VTI receipts", if mission.evidence_count > 0 { "present" } else { "needed" }),
        ("Merge proof", if mission.safe_to_merge { "ready" } else { "blocked" }),
        ("Release gate", if mission.safe_to_release { "green" } else { "pending" }),
        ("Agent sandbox", "strict"),
    ];

    let lines: Vec<Line> = lanes
        .iter()
        .map(|(lane, state)| {
            let glyph = theme.status_glyph(state);
            let color = theme.status_color(state);
            Line::from(vec![
                Span::styled(format!(" {} ", glyph), theme.bold(color)),
                Span::styled(format!("{:<20}", lane), theme.primary()),
                Span::styled(state.to_string(), theme.muted()),
            ])
        })
        .collect();

    f.render_widget(
        Paragraph::new(lines).block(
            Block::default()
                .title(" [ Proof Stack ] ")
                .borders(Borders::ALL)
                .border_style(Style::default().fg(theme.border_subtle)),
        ),
        area,
    );
}

fn render_next_actions(
    f: &mut Frame, area: Rect,
    actions: &[NextActionRecommendation], theme: &Theme,
) {
    let block = Block::default()
        .title(" [ Next Actions ] ")
        .borders(Borders::ALL)
        .border_style(Style::default().fg(theme.border_accent));
    let inner = block.inner(area);
    f.render_widget(block, area);

    if actions.is_empty() {
        f.render_widget(
            Paragraph::new(vec![
                Line::from(Span::styled("  No recommended", theme.muted())),
                Line::from(Span::styled("  actions right now", theme.muted())),
            ]),
            inner,
        );
        return;
    }

    let max = inner.height as usize;
    let lines: Vec<Line> = actions.iter().take(max).map(|a| {
        let risk_color = theme.status_color(a.risk.label());
        let label = super::truncate_label(&a.label, inner.width.saturating_sub(10) as usize);
        Line::from(vec![
            Span::styled(
                format!(" {} ", a.risk.label()),
                Style::default().fg(theme.text_inverse).bg(risk_color).add_modifier(Modifier::BOLD),
            ),
            Span::styled(format!(" {}", label), theme.primary()),
        ])
    }).collect();

    f.render_widget(Paragraph::new(lines), inner);
}

